--
-- Name: v_compliance_instance_flat; Type: VIEW; Schema: riskm_manager_model_evaluation; Owner: -
--

CREATE VIEW riskm_manager_model_evaluation.v_compliance_instance_flat AS
 WITH doc_stats AS (
         SELECT csd.compliance_instance_id,
            (count(*))::integer AS supporting_docs_count,
            (avg(csd.confidence))::numeric(5,4) AS supporting_docs_avg_confidence,
            string_agg((csd.document_id)::text, ', '::text ORDER BY csd.document_id) AS supporting_doc_ids
           FROM riskm_manager_model_evaluation.compliance_supporting_document csd
          GROUP BY csd.compliance_instance_id
        )
 SELECT ci.compliance_instance_id,
    ci.run_instance_id,
    ri.run_datetime,
    ci.run_date,
    ci.compliance_type_id,
    ct.name AS compliance_type_name,
    ci.model_id,
        CASE
            WHEN (NULLIF(btrim(COALESCE(r.code, m.router_code)), ''::text) IS NULL) THEN m.code
            ELSE (((m.code || ' ('::text) || COALESCE(r.code, m.router_code)) || ')'::text)
        END AS model_code,
    ci.inference_params_id,
    ip.name AS inference_params_name,
    ip.is_active AS inference_params_active,
    ip.clinical_pathway_id AS inference_params_clinical_pathway_id,
    cp_inf.name AS inference_params_clinical_pathway_name,
    ci.case_id,
    cc.identifier AS case_identifier,
    cc.clinical_pathway_id AS case_clinical_pathway_id,
    cp_case.name AS case_clinical_pathway_name,
    ci.rule_id,
    COALESCE((rd.body ->> 'rule_id'::text), rd.name) AS rule_code,
    rd.name AS rule_name,
    rd.clinical_pathway_id AS rule_clinical_pathway_id,
    cp_rule.name AS rule_clinical_pathway_name,
    COALESCE(cp_rule.name, cp_case.name, cp_inf.name) AS clinical_pathway_name,
    ci.confidence,
    ci.quality_score_total,
    ci.quality_score_rationale,
    ci.quality_score_classification,
    ci.computing_time_ms,
    ci.cost_in_dollar,
    ci.body AS compliance_body,
    (ci.body ->> 'outcome'::text) AS outcome,
    (ci.body ->> 'check_id'::text) AS check_id,
    (ci.body ->> 'check_timestamp'::text) AS check_timestamp,
    COALESCE(ds.supporting_docs_count, 0) AS supporting_docs_count,
    ds.supporting_docs_avg_confidence,
    ds.supporting_doc_ids,
    m.model_family_id,
    mf.code AS model_family_code,
    mf.name AS model_family_name
   FROM ((((((((((((riskm_manager_model_evaluation.compliance_instance ci
     LEFT JOIN riskm_manager_model_evaluation.run_instance ri ON ((ri.run_instance_id = ci.run_instance_id)))
     LEFT JOIN riskm_manager_model_evaluation.compliance_type ct ON ((ct.compliance_type_id = ci.compliance_type_id)))
     LEFT JOIN riskm_manager_model_evaluation.model m ON ((m.model_id = ci.model_id)))
     LEFT JOIN riskm_manager_model_evaluation.model_family mf ON ((mf.model_family_id = m.model_family_id)))
     LEFT JOIN riskm_manager_model_evaluation.router r ON ((r.code = m.router_code)))
     LEFT JOIN riskm_manager_model_evaluation.inference_params ip ON ((ip.inference_params_id = ci.inference_params_id)))
     LEFT JOIN riskm_manager_model_evaluation.clinical_pathway cp_inf ON ((cp_inf.clinical_pathway_id = ip.clinical_pathway_id)))
     LEFT JOIN riskm_manager_model_evaluation.clinical_case cc ON ((cc.case_id = ci.case_id)))
     LEFT JOIN riskm_manager_model_evaluation.clinical_pathway cp_case ON ((cp_case.clinical_pathway_id = cc.clinical_pathway_id)))
     LEFT JOIN riskm_manager_model_evaluation.rule_definition rd ON ((rd.rule_id = ci.rule_id)))
     LEFT JOIN riskm_manager_model_evaluation.clinical_pathway cp_rule ON ((cp_rule.clinical_pathway_id = rd.clinical_pathway_id)))
     LEFT JOIN doc_stats ds ON ((ds.compliance_instance_id = ci.compliance_instance_id)));


