INSERT INTO riskm_manager_model_evaluation.rule_definition OVERRIDING SYSTEM VALUE VALUES (1, 1, 'STEMI-DO-001', '{"title": "Valutazione immediata per strategia di riperfusione d''emergenza nei pazienti con sospetto STEMI", "intent": "Garantire che ogni paziente con sospetto STEMI riceva una valutazione tempestiva finalizzata alla selezione e attivazione della strategia di riperfusione d''emergenza piÃ¹ appropriata, riducendo il tempo totale di ischemia miocardica.", "rule_id": "STEMI-DO-001", "trigger": {"anchor_event": "Primo contatto medico con riscontro di sospetto STEMI (First Medical Contact - FMC)", "trigger_type": "diagnostic_finding", "inference_allowed": true, "trigger_description": "Riscontro di sopraslivellamento del tratto ST su ECG a 12 derivazioni in un paziente con sintomatologia clinica compatibile con sindrome coronarica acuta, oppure sospetto clinico fondato di STEMI comunicato dal personale del 118 o dal medico di triage.", "end_of_applicability": "Fino alla documentazione formale della decisione sulla strategia di riperfusione (PCI primaria, fibrinolisi, o esclusione motivata della riperfusione).", "trigger_data_elements": ["DE-001", "DE-002", "DE-003", "DE-008"], "start_of_applicability": "Dal momento del primo contatto medico (FMC) con riscontro di sospetto STEMI, sia in fase pre-ospedaliera che in Pronto Soccorso."}, "rationale": "La tempestivitÃ  della riperfusione miocardica Ã¨ il principale determinante della prognosi nei pazienti con STEMI. La valutazione immediata per la strategia di riperfusione consente di ridurre il ritardo tra il primo contatto medico e l''apertura del vaso coronarico occluso, migliorando la sopravvivenza e riducendo l''estensione dell''infarto.", "rule_type": "do", "exceptions": [{"label": "Arresto cardiaco refrattario con prognosi infausta", "description": "Paziente in arresto cardiaco refrattario a manovre di rianimazione cardiopolmonare avanzata prolungate, con segni di prognosi infausta, per il quale il team medico ritiene non indicato proseguire con la strategia di riperfusione.", "exception_id": "EXP-001", "condition_logic": "arresto_cardiaco == true AND RCP_prolungata > 30min AND segni_prognosi_infausta == true", "required_evidence": ["Documentazione del tempo di arresto cardiaco e delle manovre rianimatorie eseguite", "Valutazione prognostica documentata dal medico responsabile"], "required_justification": true}, {"label": "Rifiuto informato del paziente", "description": "Il paziente, adeguatamente informato, rifiuta espressamente la valutazione o il trattamento di riperfusione.", "exception_id": "EXP-002", "condition_logic": "rifiuto_informato_paziente == true AND documentazione_rifiuto == true", "required_evidence": ["Modulo di rifiuto informato firmato dal paziente", "Nota clinica attestante l''informazione fornita al paziente"], "required_justification": true}, {"label": "ComorbiditÃ  terminali con aspettativa di vita molto limitata", "description": "Paziente con patologie terminali preesistenti note (es. neoplasia in fase terminale) con aspettativa di vita molto limitata, per il quale il team medico concorda che la riperfusione non Ã¨ nel miglior interesse del paziente.", "exception_id": "EXP-003", "condition_logic": "patologia_terminale == true AND aspettativa_vita_limitata == true", "required_evidence": ["Documentazione clinica della patologia terminale", "Discussione multidisciplinare documentata", "Eventuale parere palliativista"], "required_justification": true}], "short_label": "Valutazione riperfusione STEMI", "applicability": {"care_context": "Fase pre-ospedaliera (ambulanza 118) e fase di accesso al Pronto Soccorso / DEA, fino alla decisione sulla strategia di riperfusione.", "clinical_context": "Sospetto clinico ed elettrocardiografico di STEMI in fase acuta, indipendentemente dal tempo di insorgenza dei sintomi.", "exclusion_criteria": [{"label": "Direttive anticipate di trattamento che escludono interventi invasivi", "description": "Paziente con direttive anticipate di trattamento (DAT) valide che escludono esplicitamente interventi cardiologici invasivi o manovre di riperfusione.", "criterion_id": "EXC-001", "data_elements": ["DE-006"], "logic_expression": "DAT_presente == true AND DAT_esclude_riperfusione == true", "inference_allowed": false}, {"label": "Diagnosi alternativa confermata", "description": "Paziente per il quale Ã¨ stata confermata una diagnosi alternativa che esclude lo STEMI, come pericardite acuta, sindrome di Takotsubo confermata, o artefatto ECG.", "criterion_id": "EXC-002", "data_elements": ["DE-007"], "logic_expression": "diagnosi_alternativa_confermata == true AND diagnosi_stemi_esclusa == true", "inference_allowed": true}], "inclusion_criteria": [{"label": "Dolore toracico acuto suggestivo di sindrome coronarica acuta", "description": "Paziente che presenta dolore toracico acuto, oppressivo, retrosternale, eventualmente irradiato, o equivalente anginoso, suggestivo di ischemia miocardica acuta.", "criterion_id": "INC-001", "data_elements": ["DE-001", "DE-002"], "logic_expression": "sintomo_dolore_toracico_acuto == true OR equivalente_anginoso == true", "inference_allowed": true}, {"label": "Sopraslivellamento del tratto ST all''ECG a 12 derivazioni", "description": "ECG a 12 derivazioni che mostra sopraslivellamento del tratto ST in almeno due derivazioni contigue, oppure blocco di branca sinistra di nuova insorgenza, compatibile con diagnosi di STEMI.", "criterion_id": "INC-002", "data_elements": ["DE-003", "DE-004"], "logic_expression": "ecg_st_elevation >= 1mm IN >=2 derivazioni_contigue OR nuovo_BBS == true", "inference_allowed": true}, {"label": "EtÃ  adulta", "description": "Paziente di etÃ  maggiore o uguale a 18 anni.", "criterion_id": "INC-003", "data_elements": ["DE-005"], "logic_expression": "etÃ _paziente >= 18", "inference_allowed": false}], "population_description": "Pazienti adulti (etÃ  â‰¥ 18 anni) con sospetto clinico di infarto miocardico con sopraslivellamento del tratto ST (STEMI), inclusi pazienti con dolore toracico acuto e alterazioni ECG compatibili con STEMI."}, "care_settings": ["Pronto Soccorso", "Sistema di Emergenza Territoriale 118", "UnitÃ  di Terapia Intensiva Cardiologica"], "clinical_phase": "triage e valutazione iniziale", "evidence_level": "Livello di evidenza B", "schema_version": "1.0.0", "expected_action": {"action_verb": "valutare", "action_target": "Strategia di riperfusione d''emergenza (PCI primaria, fibrinolisi sistemica, o strategia farmaco-invasiva)", "action_parameters": [{"unit": null, "mandatory": true, "expected_value": "immediata", "parameter_name": "Tempistica della valutazione", "comparison_operator": "equals", "parameter_description": "La valutazione per la strategia di riperfusione deve essere effettuata immediatamente al momento del riconoscimento del sospetto STEMI."}, {"unit": "minuti", "mandatory": true, "expected_value": "10", "parameter_name": "Esecuzione ECG a 12 derivazioni", "comparison_operator": "less_than", "parameter_description": "Un ECG a 12 derivazioni deve essere eseguito e interpretato entro 10 minuti dal primo contatto medico per confermare il sospetto STEMI."}, {"unit": "minuti", "mandatory": true, "expected_value": "120", "parameter_name": "Valutazione disponibilitÃ  PCI primaria", "comparison_operator": "less_than", "parameter_description": "Deve essere verificata la possibilitÃ  di eseguire una PCI primaria entro 120 minuti dal primo contatto medico (o 90 minuti se il paziente si presenta precocemente)."}], "action_description": "Valutare immediatamente il paziente con sospetto STEMI per determinare la strategia di riperfusione d''emergenza piÃ¹ appropriata, considerando: il tempo dall''insorgenza dei sintomi, la disponibilitÃ  di un laboratorio di emodinamica per PCI primaria entro i tempi raccomandati, le controindicazioni alla fibrinolisi, le condizioni cliniche del paziente e la logistica di trasporto.", "alternative_compliant_actions": ["Se la PCI primaria non Ã¨ disponibile entro i tempi raccomandati, considerare la fibrinolisi sistemica entro 10 minuti dalla diagnosi di STEMI, seguita da eventuale strategia farmaco-invasiva.", "In caso di presentazione pre-ospedaliera, attivazione diretta del laboratorio di emodinamica con trasporto diretto del paziente, bypassando il Pronto Soccorso."]}, "deontic_strength": "recommended", "evaluation_logic": {"notes": "In caso di discordanza tra il timestamp FMC registrato nel sistema 118 e quello registrato nel sistema di Pronto Soccorso, utilizzare il timestamp piÃ¹ precoce. La valutazione retrospettiva puÃ² richiedere revisione manuale delle note cliniche per i casi in cui la documentazione strutturata Ã¨ incompleta.", "ambiguity_policy": "review_required", "formal_expression": "IF (sospetto_STEMI == true) THEN { IF (ECG_eseguito_entro_10min == true AND decisione_riperfusione_documentata == true AND FMC_timestamp_registrato == true) THEN outcome = ''compliant''; ELSE IF (eccezione_documentata == true AND giustificazione_presente == true) THEN outcome = ''justified_deviation''; ELSE IF (dati_mancanti_critici == true) THEN outcome = ''not_evaluable''; ELSE outcome = ''non_compliant''; } ELSE outcome = ''not_applicable'';", "missing_data_policy": "not_evaluable", "natural_language_test": "Per ogni paziente con sospetto STEMI (dolore toracico acuto o equivalente anginoso + sopraslivellamento ST o BBS di nuova insorgenza all''ECG), verificare che: (1) sia stato eseguito un ECG a 12 derivazioni entro 10 minuti dal primo contatto medico; (2) sia stata documentata immediatamente la decisione sulla strategia di riperfusione d''emergenza; (3) il timestamp del FMC sia stato registrato. Se tutti e tre i criteri sono soddisfatti, la regola Ã¨ conforme. Se manca la decisione sulla strategia di riperfusione o l''ECG non Ã¨ stato eseguito/interpretato, la regola Ã¨ non conforme. Se il paziente rientra in un''eccezione documentata, si classifica come deviazione giustificata.", "conflict_resolution_policy": "human_review", "formal_expression_language": "pseudocode"}, "time_constraints": [{"description": "L''ECG a 12 derivazioni deve essere eseguito e interpretato entro 10 minuti dal primo contatto medico (FMC).", "anchor_event": "Primo contatto medico (FMC)", "constraint_id": "TC-001", "duration_unit": "minuti", "hard_deadline": true, "duration_value": 10, "relation_to_anchor": "within", "alert_threshold_unit": "minuti", "alert_threshold_value": 7}, {"description": "La decisione sulla strategia di riperfusione deve essere presa immediatamente dopo la conferma diagnostica del sospetto STEMI all''ECG.", "anchor_event": "Diagnosi di STEMI confermata all''ECG", "constraint_id": "TC-002", "duration_unit": null, "hard_deadline": true, "duration_value": null, "relation_to_anchor": "immediate", "alert_threshold_unit": null, "alert_threshold_value": null}, {"description": "Se la strategia scelta Ã¨ la PCI primaria, il tempo wire-crossing (apertura del vaso) deve avvenire entro 120 minuti dal FMC (o entro 90 minuti se il paziente si presenta entro 2 ore dall''insorgenza dei sintomi e in un centro con PCI).", "anchor_event": "Primo contatto medico (FMC)", "constraint_id": "TC-003", "duration_unit": "minuti", "hard_deadline": true, "duration_value": 120, "relation_to_anchor": "no_later_than", "alert_threshold_unit": "minuti", "alert_threshold_value": 90}], "evaluation_method": {"notes": "La valutazione deterministica Ã¨ possibile per i casi con documentazione strutturata completa (timestamp, referto ECG codificato, decisione di riperfusione nel modulo STEMI). L''inferenza Ã¨ necessaria quando la decisione di riperfusione Ã¨ documentata solo in testo libero o quando i timestamp non sono registrati in campi strutturati.", "primary_method": "hybrid", "minimum_confidence": 0.85, "human_review_required": true, "allowed_inference_sources": ["Note cliniche di triage", "Verbale di Pronto Soccorso", "Scheda intervento 118", "Referto ECG", "Scheda di attivazione emodinamica", "Note del cardiologo di guardia"]}, "possible_outcomes": ["compliant", "non_compliant", "justified_deviation", "not_applicable", "not_evaluable", "probable_non_compliance"], "source_references": [{"issuer": "European Society of Cardiology (ESC)", "source_id": "SRC-ESC-STEMI-2023", "citation_uri": "https://doi.org/10.1093/eurheartj/ehad191", "license_note": "Contenuto soggetto a copyright ESC. Utilizzo consentito per finalitÃ  cliniche e di ricerca secondo le condizioni d''uso dell''editore.", "source_level": "international", "document_title": "2023 ESC Guidelines for the management of acute coronary syndromes", "page_reference": "p. 28-35", "statement_quote": "Si raccomanda che i pazienti con sospetto STEMI siano immediatamente valutati per una emergency reperfusion strategy.", "document_version": "2023", "publication_date": "2023-08-25", "section_reference": "Sezione 5 - Strategia di riperfusione"}], "original_statement": "Si raccomanda che i pazienti con sospetto STEMI siano immediatamente valutati per una emergency reperfusion strategy.", "responsible_actors": [{"notes": "Responsabile della valutazione clinica iniziale e dell''attivazione della strategia di riperfusione.", "role_name": "Medico d''emergenza-urgenza", "organization_unit": "Pronto Soccorso / Dipartimento di Emergenza e Accettazione (DEA)", "responsibility_type": "primary"}, {"notes": "Consulente per la definizione della strategia di riperfusione piÃ¹ appropriata (PCI primaria vs fibrinolisi).", "role_name": "Cardiologo interventista", "organization_unit": "Laboratorio di Emodinamica / Cardiologia Interventistica", "responsibility_type": "consulted"}, {"notes": "Supporto nell''identificazione precoce dei pazienti con sospetto STEMI e nell''esecuzione dell''ECG a 12 derivazioni.", "role_name": "Infermiere di triage", "organization_unit": "Pronto Soccorso", "responsibility_type": "supporting"}, {"notes": "Responsabile della valutazione pre-ospedaliera e dell''attivazione del percorso STEMI in fase pre-ospedaliera.", "role_name": "Medico del Sistema di Emergenza Territoriale 118", "organization_unit": "Centrale Operativa 118 / Ambulanza medicalizzata", "responsibility_type": "primary"}, {"notes": "Supervisione del rispetto dei tempi e delle procedure della rete per lo STEMI.", "role_name": "Coordinatore della rete STEMI", "organization_unit": "Rete cardiologica regionale", "responsibility_type": "monitoring"}], "clinical_pathway_id": "PDTA-STEMI-001", "completion_criteria": {"description": "La regola si considera soddisfatta quando Ã¨ stata documentata formalmente la decisione sulla strategia di riperfusione d''emergenza piÃ¹ appropriata per il paziente con sospetto STEMI, con le relative motivazioni cliniche e la tempistica prevista.", "success_condition": "ECG interpretato E strategia di riperfusione documentata E timestamp FMC registrato E decisione riperfusione avvenuta immediatamente dopo il riconoscimento del sospetto STEMI", "minimum_occurrences": 1, "required_event_types": ["Interpretazione ECG a 12 derivazioni documentata", "Decisione sulla strategia di riperfusione documentata"], "required_documentation_elements": ["Referto ECG con interpretazione e ora di esecuzione", "Nota clinica con indicazione della strategia di riperfusione scelta", "Ora del primo contatto medico (FMC)", "Ora della diagnosi di STEMI"]}, "extraction_metadata": {"validated_at": null, "validated_by": null, "ambiguity_flags": ["Il termine ''immediatamente'' non specifica un tempo massimo numerico esatto per la decisione sulla strategia; Ã¨ stato operazionalizzato tramite i vincoli temporali ESC esistenti (ECG entro 10 min, PCI entro 120 min).", "Il termine ''sospetto STEMI'' non definisce criteri diagnostici precisi nel testo sorgente; sono stati adottati i criteri ECG standard delle linee guida ESC."], "generation_mode": "llm_inference", "extraction_confidence": 0.92, "human_validation_status": "not_reviewed", "source_interpretation_notes": "Il testo sorgente utilizza il termine ''emergency reperfusion strategy'' che Ã¨ stato normalizzato in italiano come ''strategia di riperfusione d''emergenza''. Il verbo ''si raccomanda'' Ã¨ stato interpretato come forza deontica ''recommended'' (Classe I ESC). L''avverbio ''immediatamente'' Ã¨ stato interpretato come vincolo temporale che richiede azione senza ritardo evitabile dopo il riconoscimento del sospetto STEMI. La valutazione include sia la componente diagnostica (ECG) sia la componente decisionale (scelta della strategia di riperfusione)."}, "governance_metadata": {"version": "1.0.0", "rule_owner": "Direttore Dipartimento Emergenza e Accettazione", "approved_by": null, "effective_to": null, "review_cycle": "Ogni 12 mesi o in occasione di aggiornamento delle linee guida ESC/ANMCO", "authoring_body": "Team Clinical Pathway STEMI", "effective_from": null, "last_reviewed_at": null, "lifecycle_status": "draft"}, "risk_classification": {"rationale": "La mancata valutazione immediata per la strategia di riperfusione in un paziente con STEMI comporta un prolungamento del tempo di ischemia miocardica, con aumento diretto della mortalitÃ , dell''estensione dell''infarto e del rischio di complicanze gravi (scompenso cardiaco, shock cardiogeno, aritmie fatali). La rilevanza critica Ã¨ confermata da tutte le linee guida internazionali.", "detectability": "moderate", "priority_score": 9.5, "process_risk_severity": "critical", "clinical_risk_severity": "critical", "likelihood_if_violated": "likely"}, "normalized_statement": "Ogni paziente con sospetto clinico ed elettrocardiografico di STEMI deve essere immediatamente valutato per determinare la strategia di riperfusione d''emergenza piÃ¹ appropriata.", "sequence_constraints": [{"description": "L''ECG a 12 derivazioni deve essere eseguito e interpretato prima della decisione formale sulla strategia di riperfusione.", "allowed_order": "predecessor_first", "constraint_id": "SC-001", "successor_event": "Decisione sulla strategia di riperfusione d''emergenza", "predecessor_event": "Esecuzione e interpretazione ECG a 12 derivazioni", "violation_condition": "La decisione sulla strategia di riperfusione Ã¨ stata documentata senza evidenza di un ECG a 12 derivazioni interpretato precedentemente."}, {"description": "Il primo contatto medico deve precedere la valutazione per la strategia di riperfusione.", "allowed_order": "predecessor_first", "constraint_id": "SC-002", "successor_event": "Valutazione per strategia di riperfusione", "predecessor_event": "Primo contatto medico (FMC)", "violation_condition": "La valutazione per la strategia di riperfusione risulta temporalmente antecedente al primo contatto medico registrato."}], "clinical_pathway_name": "Percorso Diagnostico Terapeutico Assistenziale per Infarto Miocardico con Sopraslivellamento del tratto ST (STEMI)", "evidence_of_compliance": [{"description": "Presenza di un ECG a 12 derivazioni eseguito e interpretato entro 10 minuti dal primo contatto medico, con risultato documentato compatibile con sospetto STEMI.", "evidence_id": "EC-001", "evidence_type": "result", "time_reference": "Entro 10 minuti dal primo contatto medico (FMC)", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-003", "DE-008", "DE-009"]}, {"description": "Documentazione della decisione sulla strategia di riperfusione d''emergenza immediatamente successiva alla conferma diagnostica di sospetto STEMI.", "evidence_id": "EC-002", "evidence_type": "documentation", "time_reference": "Immediatamente dopo la conferma diagnostica di STEMI", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-010", "DE-011"]}, {"description": "Registrazione del timestamp del primo contatto medico (FMC) nel sistema informativo.", "evidence_id": "EC-003", "evidence_type": "timestamp", "time_reference": "Al momento del primo contatto medico", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-008"]}], "required_data_elements": [{"name": "Sintomatologia di presentazione", "data_type": "text", "query_hint": "Cercare nel campo motivo di accesso, triage narrative, valutazione clinica iniziale.", "description": "Descrizione della sintomatologia riferita dal paziente al momento del primo contatto, in particolare dolore toracico acuto o equivalente anginoso.", "coding_system": null, "data_element_id": "DE-001", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "Equivalente anginoso", "data_type": "boolean", "query_hint": "Estrarre da note cliniche di triage e valutazione medica iniziale.", "description": "Presenza di sintomi atipici compatibili con ischemia miocardica (dispnea, sudorazione, nausea, sincope) in assenza di dolore toracico tipico.", "coding_system": null, "data_element_id": "DE-002", "source_location": "ehr_unstructured", "extraction_method": "inferential", "required_for_evaluation": false}, {"name": "Referto ECG a 12 derivazioni", "data_type": "coded concept", "query_hint": "Verificare il campo referto ECG nel sistema di refertazione cardiologica o nel verbale di Pronto Soccorso.", "description": "Risultato dell''ECG a 12 derivazioni con indicazione della presenza o assenza di sopraslivellamento del tratto ST e localizzazione delle derivazioni coinvolte.", "coding_system": "Codifica locale referto ECG / ICD-10 I21.x", "data_element_id": "DE-003", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Blocco di branca sinistra di nuova insorgenza", "data_type": "boolean", "query_hint": "Verificare nel referto ECG e confrontare con ECG precedenti se disponibili.", "description": "Presenza di blocco di branca sinistra (BBS) di nuova insorgenza all''ECG, compatibile con STEMI.", "coding_system": "ICD-10 I44.7", "data_element_id": "DE-004", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": false}, {"name": "EtÃ  del paziente", "data_type": "numeric", "query_hint": "Calcolare dalla data di nascita nel sistema anagrafico.", "description": "EtÃ  anagrafica del paziente in anni compiuti al momento dell''accesso.", "coding_system": null, "data_element_id": "DE-005", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Direttive anticipate di trattamento (DAT)", "data_type": "text", "query_hint": "Verificare nel registro DAT nazionale o nella cartella clinica del paziente.", "description": "Presenza e contenuto delle direttive anticipate di trattamento registrate per il paziente.", "coding_system": null, "data_element_id": "DE-006", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": false}, {"name": "Diagnosi alternativa confermata", "data_type": "coded concept", "query_hint": "Verificare il campo diagnosi nel verbale di Pronto Soccorso o nella lettera di dimissione.", "description": "Eventuale diagnosi alternativa allo STEMI confermata dal team clinico.", "coding_system": "ICD-10", "data_element_id": "DE-007", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": false}, {"name": "Timestamp del primo contatto medico (FMC)", "data_type": "datetime", "query_hint": "Cercare nel campo orario di triage, orario di arrivo ambulanza, o orario di primo contatto nel flusso STEMI.", "description": "Data e ora esatte del primo contatto del paziente con un operatore sanitario in grado di eseguire e interpretare un ECG (medico o infermiere formato).", "coding_system": null, "data_element_id": "DE-008", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Timestamp esecuzione ECG", "data_type": "datetime", "query_hint": "Cercare nel sistema di refertazione ECG o nel verbale di Pronto Soccorso.", "description": "Data e ora di esecuzione dell''ECG a 12 derivazioni.", "coding_system": null, "data_element_id": "DE-009", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Decisione strategia di riperfusione", "data_type": "coded concept", "query_hint": "Verificare nel modulo STEMI, nota clinica del medico d''emergenza, o scheda di attivazione emodinamica.", "description": "Documentazione della strategia di riperfusione scelta (PCI primaria, fibrinolisi, strategia farmaco-invasiva, nessuna riperfusione con motivazione).", "coding_system": "Codifica locale percorso STEMI", "data_element_id": "DE-010", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "Timestamp decisione strategia di riperfusione", "data_type": "datetime", "query_hint": "Cercare nel modulo STEMI o nella nota clinica relativa alla decisione di riperfusione.", "description": "Data e ora della documentazione della decisione sulla strategia di riperfusione.", "coding_system": null, "data_element_id": "DE-011", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}], "recommendation_strength": "Classe I (fortemente raccomandato)", "associated_weak_signal_ids": ["WS-STEMI-001", "WS-STEMI-002", "WS-STEMI-003"], "documentation_requirements": {"mandatory_fields": ["Timestamp del primo contatto medico (FMC)", "Timestamp di esecuzione dell''ECG a 12 derivazioni", "Referto ECG con interpretazione", "Strategia di riperfusione scelta", "Timestamp della decisione sulla strategia di riperfusione", "Identificativo del medico responsabile della decisione"], "free_text_allowed": true, "justification_fields": ["Campo motivazione nel modulo STEMI", "Nota clinica nel verbale di Pronto Soccorso", "Campo note della scheda di attivazione emodinamica"], "acceptable_evidence_sources": ["Cartella clinica elettronica di Pronto Soccorso", "Sistema di refertazione ECG", "Scheda intervento 118", "Modulo percorso STEMI", "Scheda di attivazione laboratorio di emodinamica", "Registro regionale STEMI"], "justification_required_when_deviating": true}, "evidence_of_non_compliance": [{"description": "Assenza di documentazione di un ECG a 12 derivazioni eseguito entro 10 minuti dal primo contatto medico in un paziente con sospetto STEMI.", "evidence_id": "ENC-001", "evidence_type": "absence_of_event", "time_reference": "Entro 10 minuti dal FMC non risulta alcun ECG documentato", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-003", "DE-008", "DE-009"]}, {"description": "Assenza di documentazione della decisione sulla strategia di riperfusione d''emergenza dopo la conferma diagnostica di sospetto STEMI.", "evidence_id": "ENC-002", "evidence_type": "absence_of_event", "time_reference": "Dopo la conferma diagnostica di STEMI, nessuna decisione di riperfusione documentata", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-010", "DE-011"]}, {"description": "Ritardo significativo tra il primo contatto medico e la decisione sulla strategia di riperfusione, senza giustificazione clinica documentata.", "evidence_id": "ENC-003", "evidence_type": "timestamp", "time_reference": "Intervallo FMC â†’ decisione riperfusione superiore ai tempi raccomandati", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-008", "DE-009", "DE-011"]}, {"description": "Mancata registrazione del timestamp del primo contatto medico (FMC), che impedisce la verifica dei tempi del percorso STEMI.", "evidence_id": "ENC-004", "evidence_type": "documentation_gap", "time_reference": null, "minimum_occurrences": 1, "derived_from_data_elements": ["DE-008"]}]}');
INSERT INTO riskm_manager_model_evaluation.rule_definition OVERRIDING SYSTEM VALUE VALUES (2, 1, 'STEMI-DO-002', '{"title": "Diagnosi e stratificazione del rischio a breve termine della SCA basata su anamnesi, sintomi, segni vitali, esame obiettivo, ECG e troponina ad alta sensibilitÃ ", "intent": "Garantire una diagnosi accurata e una stratificazione del rischio a breve termine della SCA mediante un approccio diagnostico multiparametrico integrato che combini dati clinici, strumentali e di laboratorio.", "rule_id": "STEMI-DO-002", "trigger": {"anchor_event": "primo_contatto_medico", "trigger_type": "documented_symptom", "inference_allowed": true, "trigger_description": "Il paziente si presenta al Pronto Soccorso o viene valutato dal Servizio di Emergenza Territoriale con sintomi suggestivi di sindrome coronarica acuta (dolore toracico acuto, dispnea, sudorazione, nausea, sincope o equivalenti anginosi).", "end_of_applicability": "Fino al completamento della valutazione diagnostica iniziale integrata e alla formulazione della diagnosi di lavoro.", "trigger_data_elements": ["DE-001", "DE-002", "DE-003"], "start_of_applicability": "Dal momento del primo contatto medico con il paziente che presenta sospetta SCA."}, "rationale": "L''utilizzo combinato di anamnesi, sintomi, parametri vitali, esame obiettivo, ECG e troponina ad alta sensibilitÃ  consente di aumentare la sensibilitÃ  e la specificitÃ  diagnostica della SCA, riducendo il rischio di mancata diagnosi e permettendo una stratificazione prognostica precoce che orienta il trattamento tempestivo.", "rule_type": "do", "exceptions": [{"label": "Arresto cardiaco in corso con necessitÃ  di rianimazione immediata", "description": "Nel paziente in arresto cardiaco, le manovre rianimatorie hanno prioritÃ  assoluta. La valutazione diagnostica multiparametrica completa puÃ² essere posticipata fino al ripristino della circolazione spontanea (ROSC).", "exception_id": "EX-001", "condition_logic": "patient_status == ''arresto_cardiaco'' AND rosc == false", "required_evidence": ["Documentazione dello stato di arresto cardiaco", "Registrazione dei tempi di rianimazione cardiopolmonare", "Nota clinica che giustifica il differimento della valutazione diagnostica completa"], "required_justification": true}, {"label": "InstabilitÃ  emodinamica critica che richiede intervento immediato", "description": "In presenza di shock cardiogeno o instabilitÃ  emodinamica grave con necessitÃ  di supporto circolatorio immediato, alcune componenti della valutazione diagnostica possono essere differite o eseguite in parallelo con le manovre di stabilizzazione.", "exception_id": "EX-002", "condition_logic": "hemodynamic_status == ''shock_cardiogeno'' OR systolic_bp < 90", "required_evidence": ["Documentazione dei parametri emodinamici critici", "Nota clinica sulla prioritizzazione delle manovre di stabilizzazione"], "required_justification": true}], "short_label": "Diagnosi SCA multiparametrica", "applicability": {"care_context": "Fase diagnostica iniziale in ambito pre-ospedaliero (118) e in Pronto Soccorso, fino alla conferma o esclusione della diagnosi di SCA.", "clinical_context": "Sospetto clinico di sindrome coronarica acuta (SCA) in fase acuta, inclusa la presentazione con dolore toracico, dispnea, sintomi equivalenti anginosi o alterazioni emodinamiche suggestive.", "exclusion_criteria": [{"label": "Causa non cardiaca chiaramente identificata", "description": "Paziente in cui una causa non cardiaca dei sintomi Ã¨ stata chiaramente identificata e documentata prima della valutazione multiparametrica (ad es. trauma toracico diretto, pneumotorace evidente alla radiografia).", "criterion_id": "EC-001", "data_elements": ["DE-010"], "logic_expression": "confirmed_non_cardiac_etiology == true AND alternative_diagnosis IS NOT NULL", "inference_allowed": false}], "inclusion_criteria": [{"label": "Sospetta SCA", "description": "Paziente adulto che si presenta con sintomi compatibili con sindrome coronarica acuta, come dolore toracico, dispnea acuta, sincope o equivalenti anginosi.", "criterion_id": "IC-001", "data_elements": ["DE-001", "DE-002"], "logic_expression": "age >= 18 AND (chief_complaint IN [''dolore_toracico'', ''dispnea_acuta'', ''sincope'', ''equivalente_anginoso''] OR clinical_suspicion == ''SCA'')", "inference_allowed": true}], "population_description": "Pazienti adulti (etÃ  â‰¥ 18 anni) che si presentano con sospetta sindrome coronarica acuta, incluso STEMI, NSTEMI e angina instabile."}, "care_settings": ["Pronto Soccorso", "Servizio di Emergenza Territoriale (118)", "UnitÃ  di Terapia Intensiva Cardiologica"], "clinical_phase": "diagnosi", "evidence_level": "Livello di evidenza B", "schema_version": "1.0.0", "expected_action": {"action_verb": "eseguire", "action_target": "Valutazione diagnostica integrata multiparametrica per SCA", "action_parameters": [{"unit": null, "mandatory": true, "expected_value": "completata", "parameter_name": "Anamnesi clinica", "comparison_operator": "equals", "parameter_description": "Raccolta dell''anamnesi completa inclusi fattori di rischio cardiovascolare, storia cardiologica, comorbilitÃ , terapie farmacologiche in corso e anamnesi familiare per cardiopatia ischemica."}, {"unit": null, "mandatory": true, "expected_value": "completata", "parameter_name": "Valutazione dei sintomi", "comparison_operator": "equals", "parameter_description": "Caratterizzazione dei sintomi di presentazione: tipo, localizzazione, irradiazione, durata, intensitÃ  del dolore toracico; presenza di sintomi associati quali dispnea, nausea, sudorazione, sincope."}, {"unit": null, "mandatory": true, "expected_value": "completata", "parameter_name": "Segni vitali", "comparison_operator": "equals", "parameter_description": "Rilevazione di pressione arteriosa sistolica e diastolica, frequenza cardiaca, frequenza respiratoria, saturazione periferica di ossigeno e temperatura corporea."}, {"unit": null, "mandatory": true, "expected_value": "completato", "parameter_name": "Esame obiettivo", "comparison_operator": "equals", "parameter_description": "Esame obiettivo cardiovascolare e sistemico con ricerca di segni di scompenso cardiaco, soffi cardiaci, segni di ipoperfusione periferica, turgore giugulare e rantoli polmonari."}, {"unit": null, "mandatory": true, "expected_value": "eseguito e interpretato", "parameter_name": "ECG a 12 derivazioni", "comparison_operator": "equals", "parameter_description": "Registrazione e interpretazione di un elettrocardiogramma a 12 derivazioni standard per identificare sopraslivellamento del tratto ST, sottoslivellamento, inversione dell''onda T o altre anomalie suggestive di ischemia acuta."}, {"unit": "ng/L", "mandatory": true, "expected_value": "dosata", "parameter_name": "Troponina cardiaca ad alta sensibilitÃ  (hs-cTn)", "comparison_operator": "equals", "parameter_description": "Dosaggio della troponina cardiaca ad alta sensibilitÃ  (hs-cTnI o hs-cTnT) su prelievo ematico per identificare danno miocardico acuto."}], "action_description": "Eseguire una valutazione diagnostica integrata e una stratificazione iniziale del rischio a breve termine della SCA basata sulla combinazione sistematica di: anamnesi clinica (inclusa storia cardiologica, fattori di rischio cardiovascolare, terapie in corso), valutazione dei sintomi (caratteristiche del dolore toracico, sintomi associati), rilevazione dei segni vitali (pressione arteriosa, frequenza cardiaca, frequenza respiratoria, saturazione di ossigeno), esame obiettivo (inclusi segni di scompenso cardiaco, soffi, segni di ipoperfusione), registrazione e interpretazione dell''ECG a 12 derivazioni, e dosaggio della troponina cardiaca ad alta sensibilitÃ  (hs-cTn).", "alternative_compliant_actions": ["In fase pre-ospedaliera, se il dosaggio della hs-cTn non Ã¨ disponibile, eseguire tutte le altre componenti della valutazione e assicurare il prelievo ematico piÃ¹ precoce possibile all''arrivo in Pronto Soccorso."]}, "deontic_strength": "mandatory", "evaluation_logic": {"notes": "Alcune componenti (anamnesi, esame obiettivo, valutazione dei sintomi) sono tipicamente documentate in formato narrativo non strutturato e possono richiedere estrazione inferenziale tramite NLP. La completezza della documentazione Ã¨ l''indicatore primario di compliance.", "ambiguity_policy": "review_required", "formal_expression": "IF (anamnesi_documentata == true AND sintomi_valutati == true AND segni_vitali_completi == true AND esame_obiettivo_documentato == true AND ECG_12_derivazioni_eseguito == true AND ECG_interpretato == true AND hs_cTn_risultato_disponibile == true AND diagnosi_di_lavoro_formulata == true) THEN status = ''compliant'' ELIF (exception_documented == true AND required_justification_present == true) THEN status = ''justified_deviation'' ELIF (any_component_missing == true AND no_justification == true) THEN status = ''non_compliant'' ELSE status = ''not_evaluable''", "missing_data_policy": "review_required", "natural_language_test": "Verificare che per il paziente con sospetta SCA siano presenti e documentate tutte e sei le componenti della valutazione diagnostica integrata: (1) anamnesi clinica, (2) valutazione dei sintomi, (3) segni vitali, (4) esame obiettivo, (5) ECG a 12 derivazioni eseguito e interpretato, (6) dosaggio della troponina ad alta sensibilitÃ  con risultato disponibile. Inoltre, verificare che sia stata formulata e documentata una diagnosi di lavoro con stratificazione del rischio iniziale basata sull''integrazione di tali elementi.", "conflict_resolution_policy": "human_review", "formal_expression_language": "pseudocode"}, "time_constraints": [{"description": "L''ECG a 12 derivazioni deve essere eseguito e interpretato entro 10 minuti dal primo contatto medico.", "anchor_event": "primo_contatto_medico", "constraint_id": "TC-001", "duration_unit": "minuti", "hard_deadline": true, "duration_value": 10, "relation_to_anchor": "within", "alert_threshold_unit": "minuti", "alert_threshold_value": 7}, {"description": "Il prelievo ematico per il dosaggio della troponina ad alta sensibilitÃ  deve essere effettuato il prima possibile e comunque contestualmente al primo accesso venoso.", "anchor_event": "primo_contatto_medico", "constraint_id": "TC-002", "duration_unit": "minuti", "hard_deadline": false, "duration_value": 20, "relation_to_anchor": "within", "alert_threshold_unit": "minuti", "alert_threshold_value": 15}, {"description": "La valutazione diagnostica integrata completa (inclusi anamnesi, sintomi, segni vitali, esame obiettivo, ECG interpretato e risultato hs-cTn) deve essere completata entro 60 minuti dal primo contatto medico.", "anchor_event": "primo_contatto_medico", "constraint_id": "TC-003", "duration_unit": "minuti", "hard_deadline": false, "duration_value": 60, "relation_to_anchor": "within", "alert_threshold_unit": "minuti", "alert_threshold_value": 45}], "evaluation_method": {"notes": "L''estrazione deterministica Ã¨ possibile per segni vitali, timestamp ECG e risultato hs-cTn. Per anamnesi, esame obiettivo e valutazione dei sintomi Ã¨ necessaria l''analisi del testo libero con verifica umana. La revisione manuale Ã¨ raccomandata per la conferma della completezza dell''integrazione diagnostica.", "primary_method": "hybrid", "minimum_confidence": 0.85, "human_review_required": true, "allowed_inference_sources": ["Verbale di Pronto Soccorso", "Note cliniche di triage", "Note cliniche del medico di PS", "Referto ECG", "Risultati di laboratorio", "Scheda 118 pre-ospedaliera"]}, "possible_outcomes": ["compliant", "non_compliant", "justified_deviation", "not_applicable", "not_evaluable", "probable_non_compliance"], "source_references": [{"issuer": "European Society of Cardiology (ESC)", "source_id": "ESC-ACS-2023", "citation_uri": "https://doi.org/10.1093/eurheartj/ehad191", "license_note": "Contenuto protetto da copyright ESC. Uso a fini clinici e di ricerca conforme alle condizioni di utilizzo dell''editore.", "source_level": "international", "document_title": "2023 ESC Guidelines for the management of acute coronary syndromes", "page_reference": null, "statement_quote": "It is recommended to base the diagnosis and initial short-term risk stratification of ACS on a combination of clinical history, symptoms, vital signs, other physical findings, ECG, and hs-cTn.", "document_version": "2023", "publication_date": "2023-08-25", "section_reference": "Sezione 3 - Diagnosi"}], "original_statement": "It is recommended to base the diagnosis and initial short-term risk stratification of ACS on a combination of clinical history, symptoms, vital signs, other physical findings, ECG, and hs-cTn.", "responsible_actors": [{"notes": "Responsabile principale della valutazione diagnostica iniziale integrata del paziente con sospetta SCA.", "role_name": "Medico di Pronto Soccorso", "organization_unit": "Pronto Soccorso / Dipartimento di Emergenza-Urgenza", "responsibility_type": "primary"}, {"notes": "Consulente per la conferma diagnostica e la stratificazione del rischio nei casi complessi.", "role_name": "Cardiologo di guardia", "organization_unit": "UnitÃ  di Terapia Intensiva Cardiologica (UTIC)", "responsibility_type": "consulted"}, {"notes": "Supporta la raccolta dei parametri vitali, l''esecuzione dell''ECG e il prelievo ematico per troponina.", "role_name": "Infermiere di Triage", "organization_unit": "Pronto Soccorso", "responsibility_type": "supporting"}, {"notes": "In fase pre-ospedaliera Ã¨ responsabile della valutazione clinica iniziale, dell''ECG e della trasmissione dei dati.", "role_name": "Medico del Servizio di Emergenza Territoriale", "organization_unit": "Servizio 118", "responsibility_type": "primary"}], "clinical_pathway_id": "PDTA-STEMI-001", "completion_criteria": {"description": "La regola Ã¨ soddisfatta quando tutte e sei le componenti della valutazione diagnostica integrata sono state eseguite e documentate: anamnesi clinica, valutazione dei sintomi, rilevazione dei segni vitali, esame obiettivo, ECG a 12 derivazioni interpretato e dosaggio della hs-cTn con risultato disponibile. La diagnosi di lavoro e la stratificazione iniziale del rischio devono essere documentate.", "success_condition": "anamnesi_completata == true AND sintomi_valutati == true AND segni_vitali_rilevati == true AND esame_obiettivo_completato == true AND ECG_12_derivazioni_eseguito == true AND ECG_interpretato == true AND hs_cTn_dosata == true AND diagnosi_di_lavoro_formulata == true", "minimum_occurrences": 1, "required_event_types": ["raccolta_anamnesi", "valutazione_sintomi", "rilevazione_segni_vitali", "esame_obiettivo", "registrazione_ECG_12_derivazioni", "dosaggio_hs_cTn", "formulazione_diagnosi_di_lavoro"], "required_documentation_elements": ["Referto anamnesi clinica nel verbale di Pronto Soccorso", "Descrizione dei sintomi di presentazione", "Parametri vitali registrati", "Referto dell''esame obiettivo", "Tracciato ECG a 12 derivazioni con interpretazione", "Risultato del dosaggio della troponina ad alta sensibilitÃ ", "Diagnosi di lavoro e stratificazione del rischio iniziale"]}, "extraction_metadata": {"validated_at": null, "validated_by": null, "ambiguity_flags": ["Il testo originale non specifica vincoli temporali espliciti per ciascuna componente; i tempi sono stati integrati da altre sezioni delle linee guida ESC 2023.", "La raccomandazione si riferisce genericamente ad ''ACS'' e non specificamente a STEMI; Ã¨ stata contestualizzata al pathway STEMI ma si applica anche a NSTEMI e angina instabile.", "Il livello di evidenza non Ã¨ esplicitamente indicato nel frammento di testo fornito; Ã¨ stato assegnato ''Livello B'' sulla base della raccomandazione completa nel documento ESC."], "generation_mode": "llm_inference", "extraction_confidence": 0.92, "human_validation_status": "not_reviewed", "source_interpretation_notes": "La raccomandazione originale ESC Ã¨ stata tradotta e contestualizzata al sistema sanitario italiano. Il termine ''hs-cTn'' Ã¨ stato mantenuto come sigla internazionale con traduzione esplicita ''troponina cardiaca ad alta sensibilitÃ ''. La forza della raccomandazione (''It is recommended'') Ã¨ stata mappata a Classe I ESC e forza deontica ''mandatory''. I vincoli temporali (10 minuti per ECG, 60 minuti per valutazione completa) sono stati derivati da altre raccomandazioni delle stesse linee guida ESC e dal contesto STEMI."}, "governance_metadata": {"version": "1.0.0", "rule_owner": "Direttore Clinico del Dipartimento di Emergenza-Urgenza", "approved_by": null, "effective_to": null, "review_cycle": "Ogni 12 mesi o in caso di aggiornamento delle linee guida ESC", "authoring_body": "Gruppo di Lavoro PDTA STEMI - Rete Cardiologica", "effective_from": "2024-01-01", "last_reviewed_at": null, "lifecycle_status": "draft"}, "risk_classification": {"rationale": "La mancata esecuzione di una valutazione diagnostica integrata completa per la SCA puÃ² portare a diagnosi mancate o ritardate, con conseguenze potenzialmente fatali (infarto miocardico non riconosciuto, ritardo nella riperfusione). L''omissione di singole componenti (es. ECG o troponina) riduce significativamente la sensibilitÃ  diagnostica e compromette la stratificazione del rischio.", "detectability": "moderate", "priority_score": 95, "process_risk_severity": "high", "clinical_risk_severity": "critical", "likelihood_if_violated": "likely"}, "normalized_statement": "La diagnosi e la stratificazione iniziale del rischio a breve termine della sindrome coronarica acuta devono essere basate sulla combinazione di anamnesi clinica, sintomi, segni vitali, altri reperti dell''esame obiettivo, elettrocardiogramma e troponina cardiaca ad alta sensibilitÃ .", "sequence_constraints": [{"description": "L''ECG a 12 derivazioni deve essere eseguito prima o contestualmente alla formulazione della diagnosi di lavoro e della stratificazione del rischio.", "allowed_order": "predecessor_first", "constraint_id": "SC-001", "successor_event": "formulazione_diagnosi_di_lavoro", "predecessor_event": "registrazione_ECG_12_derivazioni", "violation_condition": "La diagnosi di lavoro viene formulata senza che sia stato eseguito e interpretato un ECG a 12 derivazioni."}, {"description": "Il dosaggio della troponina ad alta sensibilitÃ  deve essere richiesto prima o in parallelo con il completamento dell''esame obiettivo.", "allowed_order": "any_order", "constraint_id": "SC-002", "successor_event": "completamento_esame_obiettivo", "predecessor_event": "richiesta_dosaggio_hs_cTn", "violation_condition": "Il dosaggio della hs-cTn non viene richiesto durante l''intero corso della valutazione diagnostica iniziale."}], "clinical_pathway_name": "Percorso Diagnostico Terapeutico Assistenziale per STEMI", "evidence_of_compliance": [{"description": "Presenza di documentazione dell''anamnesi clinica nel verbale di Pronto Soccorso con menzione di fattori di rischio cardiovascolare e storia cardiologica.", "evidence_id": "EOC-001", "evidence_type": "documentation", "time_reference": "Entro 60 minuti dal primo contatto medico.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-004"]}, {"description": "Registrazione completa dei segni vitali (PA, FC, FR, SpO2) nel sistema informatico.", "evidence_id": "EOC-002", "evidence_type": "result", "time_reference": "Entro 10 minuti dal primo contatto medico.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-005"]}, {"description": "Presenza di un ECG a 12 derivazioni eseguito e interpretato con timestamp coerente con i vincoli temporali.", "evidence_id": "EOC-003", "evidence_type": "result", "time_reference": "Entro 10 minuti dal primo contatto medico.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-006", "DE-007"]}, {"description": "Risultato numerico disponibile del dosaggio della troponina cardiaca ad alta sensibilitÃ  (hs-cTn).", "evidence_id": "EOC-004", "evidence_type": "result", "time_reference": "Entro 60 minuti dal primo contatto medico.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-008"]}, {"description": "Documentazione dell''esame obiettivo cardiovascolare nel verbale di Pronto Soccorso.", "evidence_id": "EOC-005", "evidence_type": "documentation", "time_reference": "Entro 60 minuti dal primo contatto medico.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-009"]}, {"description": "Diagnosi di lavoro e stratificazione del rischio iniziale documentate nel verbale di PS, con menzione esplicita dell''integrazione dei dati clinici, strumentali e di laboratorio.", "evidence_id": "EOC-006", "evidence_type": "documentation", "time_reference": "Entro 60 minuti dal primo contatto medico.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-004", "DE-005", "DE-007", "DE-008", "DE-009"]}], "required_data_elements": [{"name": "EtÃ  del paziente", "data_type": "numeric", "query_hint": "Estrarre dalla scheda anagrafica del paziente nel sistema di Pronto Soccorso.", "description": "EtÃ  anagrafica del paziente al momento della presentazione.", "coding_system": null, "data_element_id": "DE-001", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Motivo di accesso / sintomo principale", "data_type": "coded concept", "query_hint": "Campi di triage o motivo di accesso nel sistema di PS. Se non codificato, inferire dal testo libero di triage.", "description": "Sintomo o motivo principale di presentazione del paziente (es. dolore toracico, dispnea, sincope).", "coding_system": "ICD-10", "data_element_id": "DE-002", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "Timestamp primo contatto medico", "data_type": "datetime", "query_hint": "Orario di presa in carico medica o primo contatto 118 nel sistema informatico del PS o del 118.", "description": "Data e ora del primo contatto medico (First Medical Contact - FMC) con il paziente.", "coding_system": null, "data_element_id": "DE-003", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Anamnesi clinica documentata", "data_type": "text", "query_hint": "Sezione anamnesi del verbale di Pronto Soccorso. Verificare la presenza di menzioni di fattori di rischio CV e storia cardiologica.", "description": "Documentazione dell''anamnesi clinica inclusi fattori di rischio cardiovascolare, storia cardiologica pregressa, comorbilitÃ  e terapie in corso.", "coding_system": null, "data_element_id": "DE-004", "source_location": "ehr_unstructured", "extraction_method": "inferential", "required_for_evaluation": true}, {"name": "Segni vitali rilevati", "data_type": "numeric", "query_hint": "Tabella dei parametri vitali nel sistema di monitoraggio o nel modulo di triage/PS.", "description": "Set completo dei parametri vitali: pressione arteriosa sistolica e diastolica (mmHg), frequenza cardiaca (bpm), frequenza respiratoria (atti/min), saturazione O2 (%), temperatura corporea (Â°C).", "coding_system": "LOINC", "data_element_id": "DE-005", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "ECG a 12 derivazioni - timestamp esecuzione", "data_type": "datetime", "query_hint": "Timestamp di acquisizione dal sistema ECG o dall''ordine/risultato nel sistema informatico di PS.", "description": "Data e ora di esecuzione dell''elettrocardiogramma a 12 derivazioni.", "coding_system": null, "data_element_id": "DE-006", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "ECG a 12 derivazioni - referto interpretativo", "data_type": "text", "query_hint": "Referto ECG nel sistema di refertazione o nel verbale di PS. Cercare menzioni di STEMI, sopraslivellamento ST, ischemia.", "description": "Interpretazione clinica dell''ECG a 12 derivazioni con identificazione di eventuali segni di ischemia, sopraslivellamento ST, sottoslivellamento ST, inversione onde T, aritmie.", "coding_system": null, "data_element_id": "DE-007", "source_location": "ehr_unstructured", "extraction_method": "inferential", "required_for_evaluation": true}, {"name": "Risultato troponina ad alta sensibilitÃ  (hs-cTn)", "data_type": "numeric", "query_hint": "Risultato di laboratorio con codice LOINC 89579-7 (hs-cTnI) o 67151-1 (hs-cTnT). Verificare unitÃ  di misura (ng/L o pg/mL).", "description": "Valore numerico del dosaggio della troponina cardiaca ad alta sensibilitÃ  (hs-cTnI o hs-cTnT) con timestamp del prelievo e del risultato.", "coding_system": "LOINC", "data_element_id": "DE-008", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Esame obiettivo documentato", "data_type": "text", "query_hint": "Sezione esame obiettivo del verbale di Pronto Soccorso.", "description": "Documentazione dell''esame obiettivo cardiovascolare e sistemico, con menzione di eventuali segni di scompenso cardiaco, soffi, rantoli, turgore giugulare, segni di ipoperfusione.", "coding_system": null, "data_element_id": "DE-009", "source_location": "ehr_unstructured", "extraction_method": "inferential", "required_for_evaluation": true}, {"name": "Diagnosi alternativa non cardiaca confermata", "data_type": "coded concept", "query_hint": "Campo diagnosi nel sistema di PS. Se assente, verificare note cliniche per esclusione SCA documentata.", "description": "Eventuale diagnosi alternativa non cardiaca confermata che escluda il paziente dal sospetto di SCA.", "coding_system": "ICD-10", "data_element_id": "DE-010", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": false}], "recommendation_strength": "Classe I", "associated_weak_signal_ids": ["STEMI-WS-003", "STEMI-WS-004"], "documentation_requirements": {"mandatory_fields": ["Anamnesi clinica con fattori di rischio cardiovascolare", "Descrizione dei sintomi di presentazione", "Parametri vitali completi (PA, FC, FR, SpO2)", "Esame obiettivo cardiovascolare e generale", "Tracciato ECG a 12 derivazioni con interpretazione", "Risultato dosaggio hs-cTn con timestamp", "Diagnosi di lavoro e stratificazione del rischio"], "free_text_allowed": true, "justification_fields": ["Nota clinica nel verbale di Pronto Soccorso con motivazione della deviazione", "Campo note di eccezione nel sistema informativo di PS"], "acceptable_evidence_sources": ["Verbale di Pronto Soccorso", "Scheda di triage", "Sistema di refertazione ECG", "Sistema informativo di laboratorio (LIS)", "Scheda del Servizio 118", "Cartella clinica elettronica", "Sistema di monitoraggio parametri vitali"], "justification_required_when_deviating": true}, "evidence_of_non_compliance": [{"description": "Assenza di ECG a 12 derivazioni eseguito o assenza di interpretazione documentata entro i tempi previsti.", "evidence_id": "EONC-001", "evidence_type": "absence_of_event", "time_reference": "Oltre 10 minuti dal primo contatto medico senza evidenza di ECG.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-006", "DE-007"]}, {"description": "Assenza di dosaggio della troponina ad alta sensibilitÃ  o risultato non disponibile durante la fase diagnostica iniziale.", "evidence_id": "EONC-002", "evidence_type": "absence_of_event", "time_reference": "Entro 60 minuti dal primo contatto medico senza risultato hs-cTn.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-008"]}, {"description": "Assenza di documentazione dell''anamnesi clinica o dell''esame obiettivo nel verbale di Pronto Soccorso.", "evidence_id": "EONC-003", "evidence_type": "documentation_gap", "time_reference": "Al momento della chiusura del percorso diagnostico iniziale.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-004", "DE-009"]}, {"description": "Diagnosi di lavoro formulata senza integrazione documentata di tutte le componenti previste (anamnesi, sintomi, segni vitali, esame obiettivo, ECG, hs-cTn).", "evidence_id": "EONC-004", "evidence_type": "documentation_gap", "time_reference": "Al momento della formulazione della diagnosi di lavoro.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-004", "DE-005", "DE-007", "DE-008", "DE-009"]}]}');
INSERT INTO riskm_manager_model_evaluation.rule_definition OVERRIDING SYSTEM VALUE VALUES (3, 1, 'STEMI-DO-003', '{"title": "Esecuzione e interpretazione dell''ECG a 12 derivazioni entro 10 minuti dal primo contatto medico", "intent": "Garantire una diagnosi ECG rapida di STEMI per consentire l''attivazione tempestiva del percorso di riperfusione e ridurre il tempo totale di ischemia miocardica.", "rule_id": "STEMI-DO-003", "trigger": {"anchor_event": "primo_contatto_medico", "trigger_type": "event", "inference_allowed": true, "trigger_description": "Il primo contatto medico (First Medical Contact, FMC) con un paziente che presenta sintomi suggestivi di sindrome coronarica acuta / sospetto STEMI.", "end_of_applicability": "Fino al completamento della registrazione e interpretazione dell''ECG a 12 derivazioni, oppure fino alla decisione clinica di non procedere con l''ECG per motivazione documentata.", "trigger_data_elements": ["DE-timestamp-primo-contatto-medico", "DE-sintomo-presentazione"], "start_of_applicability": "Dal momento esatto del primo contatto medico con il paziente sintomatico."}, "rationale": "La diagnosi precoce mediante ECG a 12 derivazioni Ã¨ fondamentale per l''identificazione dello STEMI e l''attivazione immediata della strategia di riperfusione. Il ritardo nella registrazione e interpretazione dell''ECG comporta un prolungamento del tempo di ischemia, con conseguente aumento dell''area di necrosi miocardica e peggioramento degli esiti clinici.", "rule_type": "do", "exceptions": [{"label": "Arresto cardiaco con RCP in corso", "description": "L''ECG a 12 derivazioni non puÃ² essere eseguito in modo attendibile durante le manovre di rianimazione cardiopolmonare attiva. L''esecuzione viene differita fino al ripristino della circolazione spontanea (ROSC).", "exception_id": "STEMI-DO-003-EXP-01", "condition_logic": "stato_clinico == ''arresto_cardiaco'' AND RCP_in_corso == true", "required_evidence": ["Documentazione dello stato di arresto cardiaco", "Timestamp di inizio e fine RCP", "Timestamp del ROSC se ottenuto"], "required_justification": true}, {"label": "IndisponibilitÃ  temporanea dell''elettrocardiografo", "description": "L''apparecchio ECG non Ã¨ disponibile o malfunzionante al punto di primo contatto medico. In tal caso il paziente deve essere trasferito al piÃ¹ presto verso una sede dotata di ECG.", "exception_id": "STEMI-DO-003-EXP-02", "condition_logic": "disponibilita_ECG == false", "required_evidence": ["Documentazione dell''indisponibilitÃ  dell''apparecchio ECG", "Timestamp della segnalazione del malfunzionamento", "Azioni correttive intraprese (es. trasferimento rapido)"], "required_justification": true}, {"label": "Condizioni cliniche che impediscono l''esecuzione tecnica dell''ECG", "description": "Condizioni del paziente (es. agitazione psicomotoria estrema, ustioni toraciche estese) che rendono tecnicamente impossibile il posizionamento degli elettrodi e la registrazione dell''ECG.", "exception_id": "STEMI-DO-003-EXP-03", "condition_logic": "impedimento_tecnico_ECG == true", "required_evidence": ["Descrizione clinica dell''impedimento tecnico", "Documentazione delle azioni alternative intraprese"], "required_justification": true}], "short_label": "ECG 12 derivazioni â‰¤10 min da FMC", "applicability": {"care_context": "Fase pre-ospedaliera (primo contatto medico con equipaggio 118) o fase di arrivo in pronto soccorso, qualunque sia il punto di primo contatto medico.", "clinical_context": "Sospetto clinico di sindrome coronarica acuta / STEMI al primo contatto medico.", "exclusion_criteria": [{"label": "Arresto cardiaco in corso con rianimazione attiva", "description": "Paziente in arresto cardiaco con manovre di rianimazione cardiopolmonare in corso, per il quale l''ECG a 12 derivazioni non Ã¨ tecnicamente eseguibile in modo affidabile.", "criterion_id": "STEMI-DO-003-EXC-01", "data_elements": ["DE-stato-clinico", "DE-RCP-in-corso"], "logic_expression": "stato_clinico == ''arresto_cardiaco'' AND RCP_in_corso == true", "inference_allowed": true}], "inclusion_criteria": [{"label": "Dolore toracico acuto sospetto ischemico", "description": "Paziente adulto che presenta dolore toracico acuto o equivalente ischemico (dispnea, sudorazione algida, dolore epigastrico) suggestivo di sindrome coronarica acuta.", "criterion_id": "STEMI-DO-003-INC-01", "data_elements": ["DE-sintomo-presentazione", "DE-eta-paziente"], "logic_expression": "sintomo_presentazione IN (''dolore_toracico_acuto'', ''equivalente_ischemico'') AND etÃ  >= 18", "inference_allowed": true}, {"label": "Primo contatto medico avvenuto", "description": "Il paziente ha raggiunto il punto di primo contatto medico (first medical contact), sia in ambito pre-ospedaliero sia in pronto soccorso.", "criterion_id": "STEMI-DO-003-INC-02", "data_elements": ["DE-timestamp-primo-contatto-medico"], "logic_expression": "evento_primo_contatto_medico IS NOT NULL", "inference_allowed": false}], "population_description": "Pazienti adulti con sospetto clinico di sindrome coronarica acuta, in particolare con dolore toracico suggestivo di infarto miocardico acuto con sopraslivellamento del tratto ST (STEMI)."}, "care_settings": ["pre-ospedaliero (118/ambulanza)", "pronto soccorso", "punto di primo contatto medico"], "clinical_phase": "primo contatto medico / triage", "evidence_level": "B", "schema_version": "1.0.0", "expected_action": {"action_verb": "eseguire", "action_target": "ECG a 12 derivazioni", "action_parameters": [{"unit": "derivazioni", "mandatory": true, "expected_value": "12", "parameter_name": "numero_derivazioni", "comparison_operator": "equals", "parameter_description": "Numero minimo di derivazioni dell''ECG da registrare."}, {"unit": "minuti", "mandatory": true, "expected_value": "10", "parameter_name": "tempo_massimo_da_FMC", "comparison_operator": "less_than", "parameter_description": "Tempo massimo target dalla registrazione del primo contatto medico all''acquisizione e interpretazione dell''ECG."}, {"unit": null, "mandatory": true, "expected_value": "completata", "parameter_name": "interpretazione_ECG", "comparison_operator": "equals", "parameter_description": "L''ECG deve essere non solo registrato ma anche interpretato da personale qualificato per identificare un eventuale sopraslivellamento del tratto ST."}], "action_description": "Registrare e interpretare un ECG a 12 derivazioni il prima possibile al punto di primo contatto medico, con un obiettivo temporale inferiore a 10 minuti dal primo contatto medico.", "alternative_compliant_actions": ["Trasmissione telematica dell''ECG a 12 derivazioni a un centro hub per tele-interpretazione da parte di un cardiologo esperto, entro il medesimo limite temporale"]}, "deontic_strength": "recommended", "evaluation_logic": {"notes": "Il timestamp del primo contatto medico puÃ² provenire da fonti differenti (scheda 118, triage PS). In caso di discrepanza, utilizzare il timestamp piÃ¹ precoce documentato. L''interpretazione dell''ECG puÃ² essere effettuata anche mediante tele-refertazione.", "ambiguity_policy": "review_required", "formal_expression": "IF DE-timestamp-registrazione-ECG IS NOT NULL AND DE-referto-ECG IS NOT NULL AND DE-numero-derivazioni-ECG == 12 AND (DE-timestamp-interpretazione-ECG - DE-timestamp-primo-contatto-medico) < 10 min THEN ''compliant'' ELIF exception_documented == true THEN ''justified_deviation'' ELIF DE-timestamp-primo-contatto-medico IS NULL OR DE-timestamp-registrazione-ECG IS NULL THEN ''not_evaluable'' ELSE ''non_compliant''", "missing_data_policy": "not_evaluable", "natural_language_test": "Verificare che: (1) esista un ECG a 12 derivazioni registrato per il paziente dopo il primo contatto medico; (2) l''ECG sia stato interpretato con referto o annotazione diagnostica documentata; (3) il tempo trascorso tra il primo contatto medico e il completamento dell''interpretazione ECG sia inferiore a 10 minuti. Se tutte e tre le condizioni sono soddisfatte, la regola Ã¨ conforme. Se manca l''ECG o l''interpretazione, o se il tempo Ã¨ â‰¥ 10 minuti, la regola Ã¨ non conforme, salvo eccezione giustificata documentata.", "conflict_resolution_policy": "most_recent_source", "formal_expression_language": "pseudocode"}, "time_constraints": [{"description": "L''ECG a 12 derivazioni deve essere registrato e interpretato entro un obiettivo inferiore a 10 minuti dal primo contatto medico (FMC).", "anchor_event": "primo_contatto_medico", "constraint_id": "STEMI-DO-003-TC-01", "duration_unit": "minuti", "hard_deadline": true, "duration_value": 10, "relation_to_anchor": "within", "alert_threshold_unit": "minuti", "alert_threshold_value": 7}], "evaluation_method": {"notes": "La valutazione deterministica Ã¨ possibile quando i timestamp strutturati sono disponibili nel sistema. L''inferenza Ã¨ necessaria quando il timestamp del FMC o dell''interpretazione ECG devono essere estratti da documentazione non strutturata.", "primary_method": "hybrid", "minimum_confidence": 0.85, "human_review_required": false, "allowed_inference_sources": ["Note cliniche di pronto soccorso", "Scheda intervento 118", "Sistema di archiviazione ECG", "Verbale di triage"]}, "possible_outcomes": ["compliant", "non_compliant", "justified_deviation", "not_applicable", "not_evaluable", "probable_non_compliance"], "source_references": [{"issuer": "European Society of Cardiology (ESC)", "source_id": "ESC-STEMI-2023", "citation_uri": "https://doi.org/10.1093/eurheartj/ehad191", "license_note": "Contenuto soggetto a copyright ESC. Utilizzo ai fini di codifica interna del PDTA.", "source_level": "international", "document_title": "2023 ESC Guidelines for the management of acute coronary syndromes", "page_reference": null, "statement_quote": "Twelve-lead ECG recording and interpretation is recommended as soon as possible at the point of first medical contact, with a target of <10 min.", "document_version": "2023", "publication_date": "2023-08-25", "section_reference": "Sezione Diagnosi â€“ Raccomandazione ECG al primo contatto medico"}], "original_statement": "Twelve-lead ECG recording and interpretation is recommended as soon as possible at the point of first medical contact, with a target of <10 min.", "responsible_actors": [{"notes": "Responsabile principale dell''esecuzione e interpretazione dell''ECG a 12 derivazioni in ambito pre-ospedaliero.", "role_name": "Medico di emergenza territoriale (118)", "organization_unit": "Servizio di Emergenza Territoriale 118", "responsibility_type": "primary"}, {"notes": "Responsabile principale dell''esecuzione e interpretazione dell''ECG a 12 derivazioni se il primo contatto medico avviene in pronto soccorso.", "role_name": "Medico di pronto soccorso", "organization_unit": "Pronto Soccorso / DEA", "responsibility_type": "primary"}, {"notes": "Supporto nell''esecuzione dell''ECG a 12 derivazioni; puÃ² avviare la registrazione ECG prima della valutazione medica secondo protocollo locale.", "role_name": "Infermiere di triage", "organization_unit": "Pronto Soccorso / DEA", "responsibility_type": "supporting"}, {"notes": "Supporto tecnico per l''esecuzione dell''ECG nella fase pre-ospedaliera.", "role_name": "Equipaggio ambulanza (infermiere/tecnico)", "organization_unit": "Servizio di Emergenza Territoriale 118", "responsibility_type": "supporting"}], "clinical_pathway_id": "PDTA-STEMI-001", "completion_criteria": {"description": "La regola Ã¨ soddisfatta quando un ECG a 12 derivazioni Ã¨ stato registrato e interpretato (con refertazione o annotazione diagnostica documentata) entro 10 minuti dal momento del primo contatto medico.", "success_condition": "ECG_12_derivazioni_registrato == true AND ECG_interpretato == true AND (timestamp_ECG_interpretato - timestamp_primo_contatto_medico) < 10 minuti", "minimum_occurrences": 1, "required_event_types": ["registrazione_ECG_12_derivazioni", "interpretazione_ECG"], "required_documentation_elements": ["Tracciato ECG a 12 derivazioni memorizzato", "Timestamp di acquisizione dell''ECG", "Referto o annotazione diagnostica dell''interpretazione ECG"]}, "extraction_metadata": {"validated_at": null, "validated_by": null, "ambiguity_flags": ["Il timestamp esatto dell''interpretazione ECG potrebbe non essere sempre registrato separatamente dal timestamp di acquisizione", "La definizione operativa di ''primo contatto medico'' puÃ² variare tra contesti pre-ospedalieri e ospedalieri"], "generation_mode": "llm_inference", "extraction_confidence": 0.93, "human_validation_status": "not_reviewed", "source_interpretation_notes": "Il testo originale utilizza il termine ''recommended'' che nella classificazione ESC corrisponde a Classe I. Il target temporale ''<10 min'' Ã¨ stato codificato come vincolo temporale rigido (hard deadline). L''azione comprende sia la registrazione sia l''interpretazione dell''ECG, come esplicitamente indicato nella raccomandazione originale. Il concetto di ''point of first medical contact'' Ã¨ stato tradotto con il termine italiano ''primo contatto medico (FMC)'' secondo la terminologia standard PDTA STEMI."}, "governance_metadata": {"version": "1.0.0", "rule_owner": "Responsabile Clinico PDTA STEMI", "approved_by": null, "effective_to": null, "review_cycle": "12 mesi", "authoring_body": "Gruppo di lavoro PDTA STEMI â€“ Rete Cardiologica", "effective_from": null, "last_reviewed_at": null, "lifecycle_status": "draft"}, "risk_classification": {"rationale": "Il ritardo nella registrazione e interpretazione dell''ECG a 12 derivazioni Ã¨ direttamente correlato al ritardo nella diagnosi di STEMI e nell''attivazione del percorso di riperfusione. Ogni minuto di ritardo aumenta l''area di necrosi miocardica e peggiora la prognosi del paziente. La rilevabilitÃ  Ã¨ elevata grazie alla disponibilitÃ  di timestamp strutturati nei sistemi ECG.", "detectability": "easy", "priority_score": 95, "process_risk_severity": "high", "clinical_risk_severity": "critical", "likelihood_if_violated": "likely"}, "normalized_statement": "La registrazione e l''interpretazione dell''ECG a 12 derivazioni devono essere eseguite il prima possibile al punto di primo contatto medico, con un obiettivo temporale inferiore a 10 minuti.", "sequence_constraints": [{"description": "L''ECG a 12 derivazioni deve essere eseguito e interpretato prima dell''attivazione del laboratorio di emodinamica, poichÃ© la decisione di attivare il percorso di riperfusione dipende dall''interpretazione ECG.", "allowed_order": "predecessor_first", "constraint_id": "STEMI-DO-003-SC-01", "successor_event": "attivazione_laboratorio_emodinamica", "predecessor_event": "interpretazione_ECG_12_derivazioni", "violation_condition": "timestamp_attivazione_emodinamica < timestamp_interpretazione_ECG OR interpretazione_ECG IS NULL al momento dell''attivazione emodinamica"}, {"description": "Il primo contatto medico deve precedere la registrazione dell''ECG a 12 derivazioni.", "allowed_order": "predecessor_first", "constraint_id": "STEMI-DO-003-SC-02", "successor_event": "registrazione_ECG_12_derivazioni", "predecessor_event": "primo_contatto_medico", "violation_condition": "timestamp_registrazione_ECG < timestamp_primo_contatto_medico"}], "clinical_pathway_name": "Percorso Diagnostico Terapeutico Assistenziale per STEMI", "evidence_of_compliance": [{"description": "Tracciato ECG a 12 derivazioni registrato e archiviato nel sistema, con timestamp di acquisizione entro 10 minuti dal primo contatto medico.", "evidence_id": "STEMI-DO-003-EOC-01", "evidence_type": "execution", "time_reference": "Entro 10 minuti dal primo contatto medico", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-timestamp-primo-contatto-medico", "DE-timestamp-registrazione-ECG", "DE-numero-derivazioni-ECG"]}, {"description": "Referto o annotazione diagnostica dell''interpretazione dell''ECG presente nel sistema, con valutazione del tratto ST documentata.", "evidence_id": "STEMI-DO-003-EOC-02", "evidence_type": "documentation", "time_reference": "Entro 10 minuti dal primo contatto medico", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-referto-ECG", "DE-timestamp-interpretazione-ECG"]}, {"description": "Timestamp documentato attestante che la differenza tra il momento dell''interpretazione ECG e il momento del primo contatto medico Ã¨ inferiore a 10 minuti.", "evidence_id": "STEMI-DO-003-EOC-03", "evidence_type": "timestamp", "time_reference": "Differenza temporale < 10 minuti", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-timestamp-primo-contatto-medico", "DE-timestamp-interpretazione-ECG"]}], "required_data_elements": [{"name": "Timestamp del primo contatto medico (FMC)", "data_type": "datetime", "query_hint": "Cercare il timestamp nell''accettazione del 118 (orario arrivo sul posto) o nell''accettazione di triage in pronto soccorso, a seconda del punto di primo contatto.", "description": "Data e ora esatta del primo contatto tra il paziente con sospetta SCA e un operatore sanitario qualificato (medico o infermiere) in grado di acquisire e interpretare un ECG.", "coding_system": null, "data_element_id": "DE-timestamp-primo-contatto-medico", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Timestamp di registrazione dell''ECG a 12 derivazioni", "data_type": "datetime", "query_hint": "Estrarre il timestamp dall''header dell''ECG digitale o dal sistema di archiviazione ECG (MUSE, sistema di gestione ECG).", "description": "Data e ora di acquisizione del tracciato ECG a 12 derivazioni.", "coding_system": null, "data_element_id": "DE-timestamp-registrazione-ECG", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Timestamp di interpretazione dell''ECG", "data_type": "datetime", "query_hint": "PuÃ² coincidere con il timestamp della registrazione se l''interpretazione Ã¨ immediata. Verificare la presenza di un referto ECG o annotazione diagnostica nel sistema.", "description": "Data e ora in cui l''ECG a 12 derivazioni Ã¨ stato interpretato e refertato (anche sotto forma di annotazione clinica).", "coding_system": null, "data_element_id": "DE-timestamp-interpretazione-ECG", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "Sintomo di presentazione", "data_type": "coded concept", "query_hint": "Cercare nel campo ''motivo di accesso'' del triage o nel campo ''sintomo principale'' della scheda 118.", "description": "Sintomo principale riferito dal paziente o rilevato all''esame obiettivo al primo contatto medico (es. dolore toracico, dispnea, sincope).", "coding_system": "ICD-10 / codifica locale triage", "data_element_id": "DE-sintomo-presentazione", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "EtÃ  del paziente", "data_type": "numeric", "query_hint": "Calcolare dalla data di nascita nel sistema anagrafico.", "description": "EtÃ  del paziente in anni al momento del primo contatto medico.", "coding_system": null, "data_element_id": "DE-eta-paziente", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": false}, {"name": "Referto/interpretazione ECG", "data_type": "text", "query_hint": "Cercare nel sistema di archiviazione ECG il referto associato al tracciato. PuÃ² essere presente anche in nota clinica di pronto soccorso.", "description": "Contenuto testuale o codificato dell''interpretazione dell''ECG a 12 derivazioni, inclusa la valutazione del tratto ST.", "coding_system": null, "data_element_id": "DE-referto-ECG", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "Stato clinico del paziente al primo contatto", "data_type": "coded concept", "query_hint": "Verificare lo stato clinico nella scheda 118 o nella valutazione iniziale di triage.", "description": "Stato clinico complessivo del paziente (cosciente, incosciente, arresto cardiaco) al momento del primo contatto medico.", "coding_system": "Codifica locale", "data_element_id": "DE-stato-clinico", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": false}, {"name": "Numero di derivazioni dell''ECG", "data_type": "numeric", "query_hint": "Verificare dall''header del file ECG digitale o dalla descrizione del dispositivo utilizzato.", "description": "Numero di derivazioni registrate nell''ECG acquisito.", "coding_system": null, "data_element_id": "DE-numero-derivazioni-ECG", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}], "recommendation_strength": "Classe I (Raccomandato)", "associated_weak_signal_ids": ["STEMI-WS-003-A", "STEMI-WS-003-B", "STEMI-WS-003-C"], "documentation_requirements": {"mandatory_fields": ["Timestamp del primo contatto medico (FMC)", "Timestamp di registrazione dell''ECG a 12 derivazioni", "Tracciato ECG a 12 derivazioni archiviato", "Referto o annotazione diagnostica dell''interpretazione ECG", "Identificativo dell''operatore che ha interpretato l''ECG"], "free_text_allowed": true, "justification_fields": ["Motivo del ritardo o della mancata esecuzione dell''ECG", "Condizioni cliniche del paziente che hanno impedito l''esecuzione", "Azioni alternative intraprese", "Timestamp delle azioni correttive"], "acceptable_evidence_sources": ["Sistema di archiviazione ECG digitale (es. MUSE, Mortara)", "Cartella clinica elettronica di pronto soccorso", "Scheda intervento 118", "Verbale di triage", "Sistema di tele-ECG"], "justification_required_when_deviating": true}, "evidence_of_non_compliance": [{"description": "Assenza di tracciato ECG a 12 derivazioni registrato nel sistema per il paziente con sospetta SCA dopo il primo contatto medico.", "evidence_id": "STEMI-DO-003-EONC-01", "evidence_type": "absence_of_event", "time_reference": "Oltre 10 minuti dal primo contatto medico senza ECG registrato", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-timestamp-primo-contatto-medico", "DE-timestamp-registrazione-ECG"]}, {"description": "ECG registrato ma con intervallo temporale dal primo contatto medico superiore o uguale a 10 minuti.", "evidence_id": "STEMI-DO-003-EONC-02", "evidence_type": "timestamp", "time_reference": "Differenza temporale >= 10 minuti tra FMC e registrazione/interpretazione ECG", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-timestamp-primo-contatto-medico", "DE-timestamp-registrazione-ECG", "DE-timestamp-interpretazione-ECG"]}, {"description": "ECG registrato ma senza interpretazione o referto documentato.", "evidence_id": "STEMI-DO-003-EONC-03", "evidence_type": "documentation", "time_reference": "Dopo la registrazione dell''ECG", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-referto-ECG", "DE-timestamp-interpretazione-ECG"]}, {"description": "ECG registrato con numero di derivazioni inferiore a 12 senza giustificazione clinica documentata.", "evidence_id": "STEMI-DO-003-EONC-04", "evidence_type": "result", "time_reference": null, "minimum_occurrences": 1, "derived_from_data_elements": ["DE-numero-derivazioni-ECG"]}]}');
INSERT INTO riskm_manager_model_evaluation.rule_definition OVERRIDING SYSTEM VALUE VALUES (4, 1, 'STEMI-DO-004', '{"title": "Monitoraggio ECG continuo e disponibilitÃ  di defibrillatore nei pazienti con sospetto STEMI o SCA", "intent": "Garantire la sorveglianza elettrocardiografica continua e la capacitÃ  di defibrillazione immediata per la rilevazione e il trattamento tempestivo di aritmie potenzialmente fatali nei pazienti con sindrome coronarica acuta sospetta o confermata.", "rule_id": "STEMI-DO-004", "trigger": {"anchor_event": "primo_contatto_medico_con_sospetto_SCA", "trigger_type": "documented_symptom", "inference_allowed": true, "trigger_description": "Il trigger si attiva al momento del primo sospetto clinico di STEMI o SCA (basato su sintomi, ECG o anamnesi), oppure al momento della conferma diagnostica di infarto miocardico acuto.", "end_of_applicability": "Fino alla stabilizzazione clinica del paziente e alla dimissione dalla fase di monitoraggio intensivo, o fino al trasferimento in reparto senza indicazione a monitoraggio continuo.", "trigger_data_elements": ["DE-ECG-001", "DE-CHEST-PAIN-001", "DE-CLINICAL-SUSPICION-001", "DE-CLINICAL-SUSPICION-002", "DE-DIAGNOSIS-MI-001"], "start_of_applicability": "Dal momento del primo sospetto clinico di STEMI, SCA con alterazioni ECG, SCA con dolore toracico persistente, o dalla diagnosi confermata di infarto miocardico."}, "rationale": "I pazienti con STEMI o SCA sono a elevato rischio di aritmie ventricolari maligne, inclusa la fibrillazione ventricolare, specialmente nelle prime ore dall''esordio dei sintomi. Il monitoraggio ECG continuo consente la rilevazione precoce di aritmie, mentre la disponibilitÃ  immediata di un defibrillatore permette la defibrillazione tempestiva, riducendo significativamente la mortalitÃ  per arresto cardiaco.", "rule_type": "do", "exceptions": [{"label": "IndisponibilitÃ  tecnica temporanea del monitor ECG", "description": "In caso di indisponibilitÃ  tecnica temporanea del dispositivo di monitoraggio ECG (es. guasto, mancanza di apparecchiatura), Ã¨ necessario documentare il motivo e attivare immediatamente procedure alternative di sorveglianza clinica ravvicinata.", "exception_id": "STEMI-DO-004-EXP-01", "condition_logic": "ECG_monitor.available = false AND equipment_failure.documented = true", "required_evidence": ["Documentazione del guasto o indisponibilitÃ  dell''apparecchio", "Registrazione della sorveglianza clinica alternativa adottata", "Orario di ripristino del monitoraggio ECG"], "required_justification": true}, {"label": "Rifiuto del paziente", "description": "Il paziente, adeguatamente informato, rifiuta esplicitamente il monitoraggio ECG continuo. Il rifiuto deve essere documentato formalmente.", "exception_id": "STEMI-DO-004-EXP-02", "condition_logic": "patient.informed_refusal.ECG_monitoring = true", "required_evidence": ["Consenso informato con documentazione del rifiuto", "Nota medica attestante l''informazione fornita sui rischi"], "required_justification": true}], "short_label": "ECG continuo + defibrillatore", "applicability": {"care_context": "Fase pre-ospedaliera (118/ambulanza), pronto soccorso, triage, laboratorio di emodinamica, UTIC e qualsiasi setting in cui il paziente sia in fase acuta.", "clinical_context": "Sindrome coronarica acuta sospetta o confermata, inclusi STEMI, NSTEMI e angina instabile con alterazioni elettrocardiografiche o sintomatologia toracica persistente.", "exclusion_criteria": [{"label": "Paziente deceduto prima dell''applicazione", "description": "La regola non si applica se il paziente Ã¨ deceduto prima del primo contatto medico o se si Ã¨ deciso di non procedere a rianimazione.", "criterion_id": "STEMI-DO-004-EXC-01", "data_elements": ["DE-PATIENT-STATUS-001", "DE-DNR-001"], "logic_expression": "patient.status = ''deceased'' OR DNR_order = true", "inference_allowed": false}, {"label": "Diagnosi alternativa definitivamente confermata", "description": "La regola non si applica se una diagnosi alternativa non cardiaca Ã¨ stata definitivamente confermata e la SCA Ã¨ stata esclusa con certezza.", "criterion_id": "STEMI-DO-004-EXC-02", "data_elements": ["DE-ACS-EXCLUSION-001"], "logic_expression": "ACS_excluded = true AND alternative_diagnosis_confirmed = true", "inference_allowed": false}], "inclusion_criteria": [{"label": "Sospetto STEMI", "description": "Paziente con presentazione clinica e/o elettrocardiografica compatibile con sospetto infarto miocardico con sopraslivellamento del tratto ST.", "criterion_id": "STEMI-DO-004-INC-01", "data_elements": ["DE-ECG-001", "DE-CLINICAL-SUSPICION-001"], "logic_expression": "ECG.ST_elevation = true OR clinical_suspicion.STEMI = true", "inference_allowed": true}, {"label": "Sospetta SCA con alterazioni ECG", "description": "Paziente con sospetta sindrome coronarica acuta che presenta alterazioni elettrocardiografiche diverse dal sopraslivellamento ST (es. sottoslivellamento ST, inversione onda T, blocco di branca di nuova insorgenza).", "criterion_id": "STEMI-DO-004-INC-02", "data_elements": ["DE-ECG-001", "DE-CLINICAL-SUSPICION-002"], "logic_expression": "clinical_suspicion.ACS = true AND ECG.abnormal_changes = true", "inference_allowed": true}, {"label": "Sospetta SCA con dolore toracico in corso", "description": "Paziente con sospetta sindrome coronarica acuta e dolore toracico persistente al momento della valutazione.", "criterion_id": "STEMI-DO-004-INC-03", "data_elements": ["DE-CHEST-PAIN-001", "DE-CLINICAL-SUSPICION-002"], "logic_expression": "clinical_suspicion.ACS = true AND chest_pain.ongoing = true", "inference_allowed": true}, {"label": "Diagnosi confermata di infarto miocardico", "description": "Paziente con diagnosi confermata di infarto miocardico acuto (STEMI o NSTEMI) sulla base di criteri clinici, elettrocardiografici e bioumorali.", "criterion_id": "STEMI-DO-004-INC-04", "data_elements": ["DE-DIAGNOSIS-MI-001"], "logic_expression": "diagnosis.MI_confirmed = true", "inference_allowed": true}], "population_description": "Tutti i pazienti adulti con sospetto STEMI, sospetta sindrome coronarica acuta (SCA) con alterazioni ECG o dolore toracico in corso, oppure con diagnosi confermata di infarto miocardico."}, "care_settings": ["pronto soccorso", "ambulanza 118", "unitÃ  di terapia intensiva cardiologica", "laboratorio di emodinamica", "reparto di cardiologia"], "clinical_phase": "monitoraggio precoce", "evidence_level": "Livello di evidenza B", "schema_version": "1.0.0", "expected_action": {"action_verb": "attivare", "action_target": "monitoraggio ECG continuo e defibrillatore", "action_parameters": [{"unit": null, "mandatory": true, "expected_value": "continuo", "parameter_name": "modalitÃ _monitoraggio_ECG", "comparison_operator": "equals", "parameter_description": "Il monitoraggio ECG deve essere continuo (non intermittente) per consentire la rilevazione in tempo reale di aritmie."}, {"unit": null, "mandatory": true, "expected_value": "immediatamente disponibile", "parameter_name": "disponibilitÃ _defibrillatore", "comparison_operator": "equals", "parameter_description": "Un defibrillatore funzionante deve essere immediatamente disponibile nella stessa area in cui si trova il paziente."}, {"unit": null, "mandatory": true, "expected_value": "il prima possibile", "parameter_name": "tempistica_attivazione", "comparison_operator": null, "parameter_description": "L''attivazione del monitoraggio e la verifica della disponibilitÃ  del defibrillatore devono avvenire il prima possibile dal sospetto clinico."}], "action_description": "Attivare il monitoraggio ECG continuo e garantire la disponibilitÃ  immediata di un defibrillatore funzionante il prima possibile in tutti i pazienti con sospetto STEMI, sospetta SCA con alterazioni ECG o dolore toracico in corso, e in tutti i pazienti con diagnosi confermata di infarto miocardico.", "alternative_compliant_actions": ["Utilizzo di telemetria portatile con allarmi aritmici in caso di indisponibilitÃ  di monitor ECG fisso", "Utilizzo di defibrillatore automatico esterno (DAE) in sostituzione del defibrillatore manuale se quest''ultimo non Ã¨ disponibile"]}, "deontic_strength": "mandatory", "evaluation_logic": {"notes": "La definizione di ''il prima possibile'' (as soon as possible) Ã¨ soggetta a interpretazione operativa. Si raccomanda che venga considerata una tempistica entro pochi minuti dal primo contatto medico. In caso di dati mancanti sulla tempistica esatta, Ã¨ richiesta revisione manuale.", "ambiguity_policy": "review_required", "formal_expression": "IF (clinical_suspicion.STEMI = true OR (clinical_suspicion.ACS = true AND (ECG.abnormal_changes = true OR chest_pain.ongoing = true)) OR diagnosis.MI_confirmed = true) THEN REQUIRE (ECG_monitoring.continuous.start_timestamp IS NOT NULL AND defibrillator.available = true AND ECG_monitoring.continuous.start_timestamp <= first_medical_contact_timestamp + INTERVAL_ASAP)", "missing_data_policy": "review_required", "natural_language_test": "Verificare che per ogni paziente con sospetto STEMI, sospetta SCA con alterazioni ECG o dolore toracico in corso, o con diagnosi confermata di infarto miocardico, esista documentazione dell''attivazione del monitoraggio ECG continuo E della disponibilitÃ  di un defibrillatore funzionante, il prima possibile dal momento del sospetto o della conferma diagnostica.", "conflict_resolution_policy": "highest_risk_interpretation", "formal_expression_language": "pseudocode"}, "time_constraints": [{"description": "Il monitoraggio ECG continuo e la disponibilitÃ  del defibrillatore devono essere garantiti il prima possibile dal momento del sospetto clinico di STEMI/SCA o dalla conferma diagnostica di infarto miocardico.", "anchor_event": "primo_contatto_medico_con_sospetto_SCA", "constraint_id": "STEMI-DO-004-TC-01", "duration_unit": null, "hard_deadline": true, "duration_value": null, "relation_to_anchor": "immediate", "alert_threshold_unit": "minuti", "alert_threshold_value": 5}], "evaluation_method": {"notes": "La verifica della disponibilitÃ  del defibrillatore potrebbe richiedere inferenza da documentazione non strutturata. Il monitoraggio ECG continuo puÃ² essere verificato tramite log dei dispositivi o registrazioni infermieristiche. Si consiglia revisione umana per confermare la tempistica di attivazione.", "primary_method": "hybrid", "minimum_confidence": 0.8, "human_review_required": true, "allowed_inference_sources": ["note cliniche di pronto soccorso", "schede infermieristiche", "log dei dispositivi di monitoraggio", "verbale del 118", "cartella clinica elettronica", "checklist apparecchiature di reparto"]}, "possible_outcomes": ["compliant", "non_compliant", "justified_deviation", "not_applicable", "not_evaluable", "probable_non_compliance"], "source_references": [{"issuer": "European Society of Cardiology (ESC)", "source_id": "ESC-STEMI-2023", "citation_uri": "https://doi.org/10.1093/eurheartj/ehad191", "license_note": "Contenuto derivato dalle linee guida ESC; utilizzato a scopo clinico-assistenziale e di ricerca sotto fair use accademico.", "source_level": "international", "document_title": "2023 ESC Guidelines for the management of acute coronary syndromes", "page_reference": null, "statement_quote": "Continuous ECG monitoring and the availability of defibrillator capacity is recommended as soon as possible in all patients with suspected STEMI, in suspected ACS with other ECG changes or ongoing chest pain, and once the diagnosis of MI is made.", "document_version": "2023", "publication_date": "2023-08-25", "section_reference": "Sezione Monitoraggio e gestione delle aritmie nella fase acuta"}], "original_statement": "Continuous ECG monitoring and the availability of defibrillator capacity is recommended as soon as possible in all patients with suspected STEMI, in suspected ACS with other ECG changes or ongoing chest pain, and once the diagnosis of MI is made.", "responsible_actors": [{"notes": "Responsabile dell''attivazione tempestiva del monitoraggio ECG continuo e della verifica della disponibilitÃ  del defibrillatore al primo contatto con il paziente.", "role_name": "Medico d''emergenza", "organization_unit": "Pronto Soccorso / DEA", "responsibility_type": "primary"}, {"notes": "Supporto nell''applicazione immediata del monitoraggio ECG e nella verifica della funzionalitÃ  del defibrillatore.", "role_name": "Infermiere di triage", "organization_unit": "Pronto Soccorso / DEA", "responsibility_type": "supporting"}, {"notes": "Responsabile dell''avvio del monitoraggio ECG continuo e della disponibilitÃ  del defibrillatore in fase pre-ospedaliera.", "role_name": "Personale del 118", "organization_unit": "Servizio di Emergenza Territoriale 118", "responsibility_type": "primary"}, {"notes": "Consultato per la gestione avanzata del monitoraggio e per eventuali aritmie rilevate.", "role_name": "Cardiologo di guardia", "organization_unit": "UnitÃ  di Terapia Intensiva Cardiologica (UTIC)", "responsibility_type": "consulted"}, {"notes": "Responsabile della continuitÃ  del monitoraggio ECG durante il ricovero in UTIC.", "role_name": "Infermiere UTIC", "organization_unit": "UnitÃ  di Terapia Intensiva Cardiologica (UTIC)", "responsibility_type": "supporting"}], "clinical_pathway_id": "PDTA-STEMI-001", "completion_criteria": {"description": "La regola Ã¨ considerata soddisfatta quando il monitoraggio ECG continuo Ã¨ stato attivato e un defibrillatore funzionante Ã¨ stato reso disponibile nella prossimitÃ  del paziente, con documentazione dell''ora di attivazione.", "success_condition": "ECG_monitoring.continuous = true AND defibrillator.available = true AND documentation.timestamp IS NOT NULL", "minimum_occurrences": 1, "required_event_types": ["attivazione_monitoraggio_ECG_continuo", "verifica_disponibilitÃ _defibrillatore"], "required_documentation_elements": ["Orario di inizio del monitoraggio ECG continuo", "Conferma della disponibilitÃ  del defibrillatore", "Identificativo del dispositivo di monitoraggio utilizzato"]}, "extraction_metadata": {"validated_at": null, "validated_by": null, "ambiguity_flags": ["La definizione esatta di ''as soon as possible'' non Ã¨ quantificata in minuti nel testo sorgente", "Non Ã¨ specificato il tipo di defibrillatore richiesto (manuale vs automatico)", "Non Ã¨ esplicitata la durata minima del monitoraggio ECG continuo"], "generation_mode": "llm_inference", "extraction_confidence": 0.92, "human_validation_status": "not_reviewed", "source_interpretation_notes": "Il testo sorgente utilizza il termine ''recommended'' che, nel contesto delle linee guida ESC con classe di raccomandazione I, Ã¨ stato interpretato come ''mandatory'' (obbligatorio). L''espressione ''as soon as possible'' Ã¨ stata tradotta come ''il prima possibile'' e interpretata operativamente come tempistica immediata dall''insorgenza del sospetto clinico. La regola copre tre popolazioni distinte (sospetto STEMI, sospetta SCA con alterazioni ECG o dolore toracico persistente, diagnosi confermata di IM) che sono state tutte incluse come criteri di inclusione separati."}, "governance_metadata": {"version": "1.0.0", "rule_owner": "Direttore UOC Cardiologia / Responsabile Rete STEMI", "approved_by": null, "effective_to": null, "review_cycle": "ogni 12 mesi", "authoring_body": "Gruppo di Lavoro PDTA STEMI", "effective_from": "2024-01-01", "last_reviewed_at": null, "lifecycle_status": "draft"}, "risk_classification": {"rationale": "L''assenza di monitoraggio ECG continuo e/o di defibrillatore disponibile in pazienti con STEMI/SCA espone il paziente a rischio di morte improvvisa per fibrillazione ventricolare non rilevata o non trattata tempestivamente. La mortalitÃ  per aritmie ventricolari maligne non trattate Ã¨ estremamente elevata. La rilevabilitÃ  della violazione Ã¨ moderata perchÃ© la documentazione del monitoraggio potrebbe non essere sempre completa.", "detectability": "moderate", "priority_score": 95, "process_risk_severity": "high", "clinical_risk_severity": "critical", "likelihood_if_violated": "likely"}, "normalized_statement": "Il monitoraggio ECG continuo e la disponibilitÃ  di un defibrillatore devono essere garantiti il prima possibile in tutti i pazienti con sospetto STEMI, con sospetta SCA con alterazioni ECG o dolore toracico in corso, e una volta che la diagnosi di infarto miocardico sia stata posta.", "sequence_constraints": [{"description": "Il monitoraggio ECG continuo e la disponibilitÃ  del defibrillatore devono essere attivati prima di qualsiasi procedura interventistica o trasferimento intra-ospedaliero.", "allowed_order": "predecessor_first", "constraint_id": "STEMI-DO-004-SC-01", "successor_event": "trasferimento_laboratorio_emodinamica", "predecessor_event": "attivazione_monitoraggio_ECG_e_defibrillatore", "violation_condition": "Il paziente viene trasferito al laboratorio di emodinamica o sottoposto a intervento senza monitoraggio ECG continuo attivo e senza defibrillatore disponibile."}, {"description": "Il monitoraggio ECG continuo deve essere attivato contestualmente o immediatamente dopo il primo ECG diagnostico.", "allowed_order": "same_encounter", "constraint_id": "STEMI-DO-004-SC-02", "successor_event": "attivazione_monitoraggio_ECG_continuo", "predecessor_event": "esecuzione_ECG_diagnostico", "violation_condition": "Il monitoraggio ECG continuo non viene attivato durante lo stesso contatto clinico in cui viene eseguito l''ECG diagnostico."}], "clinical_pathway_name": "Percorso Diagnostico Terapeutico Assistenziale per STEMI", "evidence_of_compliance": [{"description": "Registrazione documentata dell''attivazione del monitoraggio ECG continuo con orario di inizio.", "evidence_id": "STEMI-DO-004-EOC-01", "evidence_type": "timestamp", "time_reference": "Entro i primi minuti dal sospetto clinico di STEMI/SCA o dalla diagnosi di infarto miocardico.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-ECG-MONITOR-001"]}, {"description": "Documentazione della disponibilitÃ  e funzionalitÃ  del defibrillatore nell''area del paziente.", "evidence_id": "STEMI-DO-004-EOC-02", "evidence_type": "documentation", "time_reference": "Contestualmente all''attivazione del monitoraggio ECG continuo.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-DEFIB-001"]}, {"description": "Presenza di tracciati ECG continui nel sistema di monitoraggio a partire dalla fase acuta.", "evidence_id": "STEMI-DO-004-EOC-03", "evidence_type": "execution", "time_reference": "Dalla fase acuta del sospetto/diagnosi fino alla stabilizzazione clinica.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-ECG-MONITOR-001"]}], "required_data_elements": [{"name": "Risultato ECG a 12 derivazioni", "data_type": "coded concept", "query_hint": "Cercare risultati ECG con codici LOINC pertinenti (es. 11524-6) e referto interpretativo.", "description": "Tracciato e referto dell''elettrocardiogramma a 12 derivazioni eseguito al primo contatto, inclusa la presenza di sopraslivellamento ST o altre alterazioni.", "coding_system": "LOINC", "data_element_id": "DE-ECG-001", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Dolore toracico in corso", "data_type": "boolean", "query_hint": "Cercare menzione di dolore toracico in corso, persistente o acuto nelle note di triage o di pronto soccorso.", "description": "Presenza di dolore toracico persistente al momento della valutazione clinica.", "coding_system": "ICD-10 R07.9", "data_element_id": "DE-CHEST-PAIN-001", "source_location": "ehr_unstructured", "extraction_method": "inferential", "required_for_evaluation": true}, {"name": "Sospetto clinico di STEMI", "data_type": "boolean", "query_hint": "Cercare codice di attivazione percorso STEMI, diagnosi provvisoria I21.x o nota clinica con sospetto STEMI.", "description": "Documentazione del sospetto clinico di STEMI basato su presentazione clinica e/o ECG.", "coding_system": "ICD-10 I21", "data_element_id": "DE-CLINICAL-SUSPICION-001", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "Sospetto clinico di SCA", "data_type": "boolean", "query_hint": "Cercare diagnosi provvisoria di SCA, NSTEMI o angina instabile nelle note cliniche o nel sistema di triage.", "description": "Documentazione del sospetto clinico di sindrome coronarica acuta (SCA) non-STEMI.", "coding_system": "ICD-10 I20-I21", "data_element_id": "DE-CLINICAL-SUSPICION-002", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "Diagnosi confermata di infarto miocardico", "data_type": "coded concept", "query_hint": "Cercare diagnosi definitiva codificata I21.x nel sistema di cartella clinica.", "description": "Diagnosi confermata di infarto miocardico acuto (STEMI o NSTEMI) basata su criteri clinici, ECG e biomarcatori.", "coding_system": "ICD-10 I21", "data_element_id": "DE-DIAGNOSIS-MI-001", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Stato monitoraggio ECG continuo", "data_type": "datetime", "query_hint": "Cercare registrazioni di inizio monitoraggio ECG continuo nel sistema di monitoraggio o nella cartella infermieristica.", "description": "Registrazione dell''attivazione del monitoraggio ECG continuo, incluso orario di inizio e identificativo del dispositivo.", "coding_system": null, "data_element_id": "DE-ECG-MONITOR-001", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "DisponibilitÃ  defibrillatore", "data_type": "boolean", "query_hint": "Cercare checklist di verifica apparecchiature, log del defibrillatore o note infermieristiche che confermino la disponibilitÃ .", "description": "Conferma della disponibilitÃ  e funzionalitÃ  di un defibrillatore nell''area del paziente.", "coding_system": null, "data_element_id": "DE-DEFIB-001", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "Stato vitale del paziente", "data_type": "coded concept", "query_hint": "Verificare lo stato del paziente nel sistema ADT.", "description": "Stato vitale corrente del paziente (vivo, deceduto).", "coding_system": null, "data_element_id": "DE-PATIENT-STATUS-001", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": false}, {"name": "Ordine di non rianimazione (DNR)", "data_type": "boolean", "query_hint": "Cercare ordini DNR o disposizioni anticipate di trattamento nel fascicolo del paziente.", "description": "Presenza di un ordine documentato di non rianimazione cardio-polmonare.", "coding_system": null, "data_element_id": "DE-DNR-001", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": false}, {"name": "Esclusione di SCA", "data_type": "boolean", "query_hint": "Cercare nota clinica di esclusione di SCA con diagnosi alternativa confermata.", "description": "Documentazione dell''esclusione definitiva di sindrome coronarica acuta con diagnosi alternativa confermata.", "coding_system": null, "data_element_id": "DE-ACS-EXCLUSION-001", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": false}], "recommendation_strength": "Classe I", "associated_weak_signal_ids": ["STEMI-WS-004-01", "STEMI-WS-004-02", "STEMI-WS-004-03"], "documentation_requirements": {"mandatory_fields": ["Orario di attivazione del monitoraggio ECG continuo", "Conferma della disponibilitÃ  del defibrillatore", "Identificativo del dispositivo di monitoraggio ECG", "Nome dell''operatore che ha attivato il monitoraggio", "Setting in cui Ã¨ stato attivato il monitoraggio (ambulanza, PS, UTIC)"], "free_text_allowed": true, "justification_fields": ["Motivo della deviazione dalla regola", "Misure alternative adottate", "Orario previsto di ripristino del monitoraggio", "Firma del medico responsabile"], "acceptable_evidence_sources": ["Cartella clinica elettronica", "Scheda infermieristica", "Log dei dispositivi di monitoraggio", "Verbale del 118", "Checklist apparecchiature", "Report sistema di telemetria"], "justification_required_when_deviating": true}, "evidence_of_non_compliance": [{"description": "Assenza di documentazione di attivazione del monitoraggio ECG continuo durante la fase acuta del sospetto o della diagnosi di STEMI/SCA/IM.", "evidence_id": "STEMI-DO-004-EONC-01", "evidence_type": "absence_of_event", "time_reference": "Dall''esordio del sospetto clinico fino al ricovero in UTIC o al trasferimento in emodinamica.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-ECG-MONITOR-001"]}, {"description": "Assenza di documentazione della disponibilitÃ  del defibrillatore nell''area del paziente.", "evidence_id": "STEMI-DO-004-EONC-02", "evidence_type": "absence_of_event", "time_reference": "Dall''esordio del sospetto clinico fino al ricovero in UTIC.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-DEFIB-001"]}, {"description": "Ritardo significativo nell''attivazione del monitoraggio ECG continuo rispetto al primo contatto medico con sospetto clinico.", "evidence_id": "STEMI-DO-004-EONC-03", "evidence_type": "timestamp", "time_reference": "PiÃ¹ di 10 minuti dal primo contatto medico con sospetto di SCA/STEMI.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-ECG-MONITOR-001", "DE-CLINICAL-SUSPICION-001", "DE-CLINICAL-SUSPICION-002"]}]}');
INSERT INTO riskm_manager_model_evaluation.rule_definition OVERRIDING SYSTEM VALUE VALUES (5, 1, 'STEMI-DO-005', '{"title": "Utilizzo di derivazioni ECG aggiuntive (V3R, V4R e V7â€“V9) in caso di STEMI inferiore o sospetta occlusione coronarica totale con derivazioni standard non conclusive", "intent": "Migliorare la sensibilitÃ  diagnostica dell''ECG per identificare l''estensione dell''infarto al ventricolo destro e alla parete posteriore, nonchÃ© per confermare un''occlusione coronarica totale quando le derivazioni standard sono non conclusive.", "rule_id": "STEMI-DO-005", "trigger": {"anchor_event": "Registrazione ECG a 12 derivazioni standard", "trigger_type": "diagnostic_finding", "inference_allowed": true, "trigger_description": "Riscontro di sopraslivellamento del tratto ST in sede inferiore all''ECG standard a 12 derivazioni oppure elevato sospetto clinico di occlusione coronarica totale con ECG standard non conclusivo.", "end_of_applicability": "Fino al completamento della registrazione ECG con derivazioni aggiuntive o fino alla decisione definitiva sulla strategia di riperfusione.", "trigger_data_elements": ["DE-005-01", "DE-005-02", "DE-005-03", "DE-005-04"], "start_of_applicability": "Immediatamente dopo l''identificazione di STEMI inferiore o del sospetto di occlusione coronarica totale con ECG non conclusivo."}, "rationale": "Le derivazioni standard a 12 canali possono non evidenziare il sopraslivellamento del tratto ST nel coinvolgimento del ventricolo destro o della parete posteriore. Le derivazioni destre (V3R, V4R) rilevano l''infarto del ventricolo destro, mentre le derivazioni posteriori (V7â€“V9) rilevano l''infarto posteriore. La mancata identificazione di tali territori puÃ² comportare una sottovalutazione dell''estensione dell''infarto e un trattamento inadeguato.", "rule_type": "do", "exceptions": [{"label": "ImpossibilitÃ  tecnica di posizionamento degli elettrodi aggiuntivi", "description": "Lesioni cutanee estese, ustioni o altre condizioni anatomiche che rendono impossibile il posizionamento degli elettrodi nelle posizioni V3R, V4R, V7â€“V9.", "exception_id": "EXC-005-01", "condition_logic": "electrode_placement_impossible == true", "required_evidence": ["Documentazione clinica della condizione che impedisce il posizionamento", "Nota infermieristica o medica nel verbale di pronto soccorso"], "required_justification": true}, {"label": "PrioritÃ  di intervento immediato per instabilitÃ  emodinamica critica", "description": "Il paziente presenta arresto cardiaco, shock cardiogeno grave o altra emergenza che richiede interventi salvavita immediati, rendendo la registrazione delle derivazioni aggiuntive non prioritaria in quel momento.", "exception_id": "EXC-005-02", "condition_logic": "hemodynamic_instability_critical == true AND life_saving_intervention_priority == true", "required_evidence": ["Documentazione dell''instabilitÃ  emodinamica critica", "Registrazione delle manovre di rianimazione o stabilizzazione eseguite"], "required_justification": true}], "short_label": "ECG derivazioni aggiuntive STEMI inferiore", "applicability": {"care_context": "Fase diagnostica in pronto soccorso, in ambiente pre-ospedaliero o in UTIC.", "clinical_context": "Infarto miocardico acuto con sopraslivellamento del tratto ST in sede inferiore (derivazioni II, III, aVF) oppure quadro clinico suggestivo di occlusione coronarica acuta con ECG standard non diagnostico.", "exclusion_criteria": [{"label": "ImpossibilitÃ  tecnica di posizionamento elettrodi aggiuntivi", "description": "Condizioni cliniche o anatomiche che impediscono fisicamente il posizionamento degli elettrodi nelle sedi V3R, V4R, V7â€“V9 (ad es. estese lesioni cutanee toraciche, ustioni).", "criterion_id": "EXCL-005-01", "data_elements": ["DE-005-05"], "logic_expression": "electrode_placement_impossible == true", "inference_allowed": true}], "inclusion_criteria": [{"label": "STEMI inferiore all''ECG standard", "description": "Sopraslivellamento del tratto ST â‰¥ 1 mm in almeno due derivazioni contigue tra II, III e aVF all''ECG a 12 derivazioni.", "criterion_id": "INCL-005-01", "data_elements": ["DE-005-01", "DE-005-02"], "logic_expression": "ST_elevation(II) >= 1mm AND (ST_elevation(III) >= 1mm OR ST_elevation(aVF) >= 1mm)", "inference_allowed": true}, {"label": "Sospetta occlusione coronarica totale con ECG standard non conclusivo", "description": "Quadro clinico altamente suggestivo di sindrome coronarica acuta con occlusione totale (dolore toracico tipico, instabilitÃ  emodinamica) ma ECG a 12 derivazioni non diagnostico per sopraslivellamento ST.", "criterion_id": "INCL-005-02", "data_elements": ["DE-005-03", "DE-005-04"], "logic_expression": "clinical_suspicion_total_occlusion == true AND standard_ECG_inconclusive == true", "inference_allowed": true}], "population_description": "Pazienti adulti con sospetto clinico o diagnosi elettrocardiografica di STEMI inferiore oppure con sospetta occlusione coronarica totale e derivazioni ECG standard non conclusive."}, "care_settings": ["pronto soccorso", "unitÃ  di terapia intensiva cardiologica", "pre-ospedaliero (ambulanza medicalizzata)"], "clinical_phase": "diagnosi", "evidence_level": "Livello di evidenza C", "schema_version": "1.0.0", "expected_action": {"action_verb": "eseguire", "action_target": "ECG a derivazioni aggiuntive (V3R, V4R, V7â€“V9)", "action_parameters": [{"unit": null, "mandatory": true, "expected_value": "V3R, V4R", "parameter_name": "Derivazioni destre", "comparison_operator": "equals", "parameter_description": "Derivazioni precordiali destre da registrare per identificare l''infarto del ventricolo destro."}, {"unit": null, "mandatory": true, "expected_value": "V7, V8, V9", "parameter_name": "Derivazioni posteriori", "comparison_operator": "equals", "parameter_description": "Derivazioni posteriori da registrare per identificare l''infarto della parete posteriore."}, {"unit": "mm", "mandatory": false, "expected_value": "0.5", "parameter_name": "Soglia sopraslivellamento ST derivazioni posteriori", "comparison_operator": "greater_than", "parameter_description": "Soglia di sopraslivellamento del tratto ST nelle derivazioni posteriori considerata significativa."}], "action_description": "Eseguire la registrazione di un ECG con derivazioni aggiuntive destre (V3R, V4R) e posteriori (V7, V8, V9) per valutare il coinvolgimento del ventricolo destro e della parete posteriore.", "alternative_compliant_actions": ["Esecuzione di ECG a 15 derivazioni (12 standard + V3R, V4R, V7â€“V9) in unica registrazione", "Esecuzione di ECG a 18 derivazioni se disponibile apparecchiatura idonea"]}, "deontic_strength": "recommended", "evaluation_logic": {"notes": "La valutazione puÃ² richiedere l''analisi del testo libero del referto ECG per determinare se le derivazioni aggiuntive sono state effettivamente registrate, in particolare quando il sistema non struttura automaticamente il tipo di derivazioni.", "ambiguity_policy": "review_required", "formal_expression": "IF (ST_elevation_inferior == true OR (clinical_suspicion_total_occlusion == true AND standard_ECG_inconclusive == true)) THEN IF (ECG_additional_leads_recorded == true AND leads_include(V3R, V4R, V7, V8, V9) AND time_diff(ECG_additional_timestamp, ECG_standard_timestamp) <= 10 min) THEN ''compliant'' ELSE IF (exception_documented == true AND justification_present == true) THEN ''justified_deviation'' ELSE ''non_compliant'' ELSE ''not_applicable''", "missing_data_policy": "review_required", "natural_language_test": "Verificare se, in presenza di STEMI inferiore (sopraslivellamento ST â‰¥ 1 mm in almeno due derivazioni tra II, III, aVF) oppure di sospetta occlusione coronarica totale con ECG standard non conclusivo, sia stato registrato e interpretato un ECG con derivazioni aggiuntive V3R, V4R, V7â€“V9 entro 10 minuti dall''ECG standard. Nel caso di eccezione documentata e giustificata, la deviazione Ã¨ considerata giustificata.", "conflict_resolution_policy": "human_review", "formal_expression_language": "pseudocode"}, "time_constraints": [{"description": "L''ECG con derivazioni aggiuntive deve essere eseguito il prima possibile e comunque entro 10 minuti dalla registrazione dell''ECG standard che ha evidenziato lo STEMI inferiore o il sospetto di occlusione coronarica totale.", "anchor_event": "Registrazione ECG standard a 12 derivazioni con riscontro diagnostico", "constraint_id": "TC-005-01", "duration_unit": "minuti", "hard_deadline": false, "duration_value": 10, "relation_to_anchor": "within", "alert_threshold_unit": "minuti", "alert_threshold_value": 5}], "evaluation_method": {"notes": "In molti sistemi informativi ospedalieri il tipo di derivazioni ECG non Ã¨ codificato strutturalmente; potrebbe essere necessario analizzare il tracciato PDF o il referto testuale per verificare la presenza delle derivazioni aggiuntive.", "primary_method": "hybrid", "minimum_confidence": 0.85, "human_review_required": true, "allowed_inference_sources": ["Referti ECG in testo libero", "Note cliniche del medico d''emergenza", "Note infermieristiche", "Tracciati ECG allegati in formato digitale"]}, "possible_outcomes": ["compliant", "non_compliant", "justified_deviation", "not_applicable", "not_evaluable"], "source_references": [{"issuer": "European Society of Cardiology (ESC)", "source_id": "ESC-STEMI-GL-2023", "citation_uri": "https://doi.org/10.1093/eurheartj/ehad191", "license_note": "Contenuto soggetto a copyright ESC. Utilizzato a scopo di sintesi clinica non commerciale.", "source_level": "international", "document_title": "2023 ESC Guidelines for the management of acute coronary syndromes", "page_reference": null, "statement_quote": "The use of additional ECG leads (V3R, V4R, and V7â€“V9) is recommended in cases of inferior STEMI or if total vessel occlusion is suspected and standard leads are inconclusive.", "document_version": "2023", "publication_date": "2023-08-25", "section_reference": "Sezione Diagnosi â€“ Raccomandazioni ECG"}], "original_statement": "The use of additional ECG leads (V3R, V4R, and V7â€“V9) is recommended in cases of inferior STEMI or if total vessel occlusion is suspected and standard leads are inconclusive.", "responsible_actors": [{"notes": "Responsabile dell''esecuzione e dell''interpretazione dell''ECG a 12 derivazioni e delle derivazioni aggiuntive.", "role_name": "Medico d''emergenza", "organization_unit": "Pronto Soccorso", "responsibility_type": "primary"}, {"notes": "Esegue materialmente la registrazione ECG con le derivazioni aggiuntive su indicazione medica.", "role_name": "Infermiere di triage/emergenza", "organization_unit": "Pronto Soccorso", "responsibility_type": "supporting"}, {"notes": "PuÃ² essere consultato per l''interpretazione delle derivazioni aggiuntive e per la pianificazione dell''eventuale coronarografia.", "role_name": "Cardiologo interventista", "organization_unit": "Emodinamica / UTIC", "responsibility_type": "consulted"}], "clinical_pathway_id": "PDTA-STEMI-001", "completion_criteria": {"description": "La regola si considera soddisfatta quando Ã¨ stata registrata e documentata in cartella clinica almeno una traccia ECG che includa le derivazioni aggiuntive V3R, V4R e V7â€“V9, con relativa interpretazione medica.", "success_condition": "ECG_additional_leads_recorded == true AND ECG_additional_leads_interpreted == true AND leads_set CONTAINS {''V3R'',''V4R'',''V7'',''V8'',''V9''}", "minimum_occurrences": 1, "required_event_types": ["Registrazione ECG con derivazioni aggiuntive", "Interpretazione medica del tracciato ECG aggiuntivo"], "required_documentation_elements": ["Tracciato ECG con derivazioni aggiuntive allegato in cartella", "Referto interpretativo delle derivazioni aggiuntive"]}, "extraction_metadata": {"validated_at": null, "validated_by": null, "ambiguity_flags": ["Il testo originale non specifica un limite temporale esplicito per l''esecuzione delle derivazioni aggiuntive; il vincolo di 10 minuti Ã¨ stato derivato per analogia clinica.", "Il termine ''inconclusive'' per le derivazioni standard richiede interpretazione clinica contestuale e potrebbe avere soglie variabili in diversi contesti."], "generation_mode": "llm_inference", "extraction_confidence": 0.88, "human_validation_status": "not_reviewed", "source_interpretation_notes": "Il testo originale in lingua inglese utilizza il termine ''recommended'', interpretato come raccomandazione forte (Classe I). Le condizioni di applicabilitÃ  sono state suddivise in due criteri di inclusione distinti: STEMI inferiore e sospetta occlusione coronarica totale con ECG non conclusivo. Il vincolo temporale di 10 minuti Ã¨ stato aggiunto come buona pratica clinica in analogia con le raccomandazioni ESC sull''ECG iniziale, poichÃ© non Ã¨ esplicitato nel testo originale."}, "governance_metadata": {"version": "1.0.0", "rule_owner": "Direttore UOC Cardiologia d''Urgenza", "approved_by": null, "effective_to": null, "review_cycle": "12 mesi", "authoring_body": "Comitato PDTA Cardiovascolare", "effective_from": null, "last_reviewed_at": null, "lifecycle_status": "draft"}, "risk_classification": {"rationale": "La mancata esecuzione delle derivazioni aggiuntive puÃ² comportare il mancato riconoscimento dell''estensione dell''infarto al ventricolo destro o alla parete posteriore, con conseguente sottostima della gravitÃ  clinica e potenziale inadeguatezza del trattamento (ad es. mancata somministrazione di fluidi nello shock del ventricolo destro, ritardo nella strategia di riperfusione).", "detectability": "moderate", "priority_score": 7.5, "process_risk_severity": "moderate", "clinical_risk_severity": "high", "likelihood_if_violated": "possible"}, "normalized_statement": "In presenza di STEMI inferiore o di sospetta occlusione coronarica totale con derivazioni ECG standard non conclusive, si raccomanda l''esecuzione di un ECG con derivazioni aggiuntive V3R, V4R e V7â€“V9.", "sequence_constraints": [{"description": "L''ECG a 12 derivazioni standard deve essere stato eseguito e interpretato prima della registrazione delle derivazioni aggiuntive, in quanto il riscontro di STEMI inferiore o la non conclusivitÃ  dell''ECG standard Ã¨ il presupposto per l''indicazione alle derivazioni aggiuntive.", "allowed_order": "predecessor_first", "constraint_id": "SC-005-01", "successor_event": "Registrazione ECG con derivazioni aggiuntive V3R, V4R, V7â€“V9", "predecessor_event": "Registrazione e interpretazione ECG standard a 12 derivazioni", "violation_condition": "Le derivazioni aggiuntive vengono registrate senza che sia stato prima completato e interpretato l''ECG standard a 12 derivazioni."}, {"description": "L''ECG con derivazioni aggiuntive deve essere completato prima dell''attivazione del laboratorio di emodinamica, cosÃ¬ da fornire informazioni diagnostiche complete per la pianificazione dell''intervento.", "allowed_order": "predecessor_first", "constraint_id": "SC-005-02", "successor_event": "Attivazione laboratorio di emodinamica", "predecessor_event": "Registrazione ECG con derivazioni aggiuntive V3R, V4R, V7â€“V9", "violation_condition": "Il laboratorio di emodinamica viene attivato senza aver prima registrato le derivazioni aggiuntive nei casi indicati, salvo giustificazione clinica documentata."}], "clinical_pathway_name": "Percorso Diagnostico-Terapeutico Assistenziale per STEMI", "evidence_of_compliance": [{"description": "Presenza in cartella clinica di un tracciato ECG con derivazioni aggiuntive V3R, V4R, V7â€“V9 registrato dopo l''identificazione dello STEMI inferiore o del sospetto di occlusione coronarica totale.", "evidence_id": "EC-005-01", "evidence_type": "execution", "time_reference": "Entro 10 minuti dall''ECG standard diagnostico", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-005-06", "DE-005-07"]}, {"description": "Referto medico che documenta l''interpretazione delle derivazioni aggiuntive con indicazione della presenza o assenza di sopraslivellamento ST nelle derivazioni destre e posteriori.", "evidence_id": "EC-005-02", "evidence_type": "documentation", "time_reference": "Contestualmente o subito dopo la registrazione dell''ECG aggiuntivo", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-005-06"]}], "required_data_elements": [{"name": "Tracciato ECG a 12 derivazioni standard", "data_type": "documento/tracciato", "query_hint": "Cercare l''ultimo ECG registrato con timestamp nel contesto dell''episodio acuto.", "description": "Registrazione elettrocardiografica completa a 12 derivazioni standard con timestamp e valori di sopraslivellamento ST.", "coding_system": "LOINC 11524-6", "data_element_id": "DE-005-01", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Sopraslivellamento ST in derivazioni inferiori", "data_type": "numeric (mm)", "query_hint": "Estrarre i valori di ST elevation dalle derivazioni II, III, aVF dal referto ECG automatico o dal referto medico.", "description": "Presenza e misura del sopraslivellamento del tratto ST nelle derivazioni II, III e aVF.", "coding_system": null, "data_element_id": "DE-005-02", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "Sospetto clinico di occlusione coronarica totale", "data_type": "boolean", "query_hint": "Cercare nelle note cliniche espressioni come ''sospetta occlusione totale'', ''STEMI equivalente'', ''occlusione acuta coronarica''.", "description": "Indicazione documentata del sospetto clinico di occlusione coronarica totale basata su sintomi, segni clinici ed eventuale imaging.", "coding_system": null, "data_element_id": "DE-005-03", "source_location": "ehr_unstructured", "extraction_method": "inferential", "required_for_evaluation": true}, {"name": "ECG standard non conclusivo", "data_type": "boolean", "query_hint": "Cercare nel referto ECG o nelle note cliniche espressioni come ''non conclusivo'', ''non diagnostico'', ''dubbio'', ''da completare con derivazioni aggiuntive''.", "description": "Indicazione che l''ECG a 12 derivazioni standard non Ã¨ conclusivo per la diagnosi di STEMI o occlusione coronarica.", "coding_system": null, "data_element_id": "DE-005-04", "source_location": "ehr_unstructured", "extraction_method": "inferential", "required_for_evaluation": true}, {"name": "ImpossibilitÃ  posizionamento elettrodi aggiuntivi", "data_type": "boolean", "query_hint": "Cercare nelle note cliniche o infermieristiche espressioni relative a impossibilitÃ  di posizionamento elettrodi.", "description": "Documentazione di condizioni cliniche o anatomiche che impediscono il posizionamento degli elettrodi nelle posizioni aggiuntive.", "coding_system": null, "data_element_id": "DE-005-05", "source_location": "ehr_unstructured", "extraction_method": "inferential", "required_for_evaluation": false}, {"name": "Tracciato ECG con derivazioni aggiuntive", "data_type": "documento/tracciato", "query_hint": "Cercare tracciato ECG con indicazione di derivazioni aggiuntive (15 o 18 derivazioni) registrato dopo l''ECG standard nel contesto dell''episodio acuto.", "description": "Registrazione ECG che include le derivazioni V3R, V4R, V7, V8, V9 con relativo timestamp.", "coding_system": "LOINC 11524-6", "data_element_id": "DE-005-06", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Timestamp registrazione ECG aggiuntivo", "data_type": "datetime", "query_hint": "Estrarre il timestamp dal tracciato ECG aggiuntivo o dal sistema di refertazione.", "description": "Data e ora di esecuzione dell''ECG con derivazioni aggiuntive.", "coding_system": null, "data_element_id": "DE-005-07", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}], "recommendation_strength": "Classe I", "associated_weak_signal_ids": ["STEMI-WS-005-01", "STEMI-WS-005-02"], "documentation_requirements": {"mandatory_fields": ["Tracciato ECG con derivazioni aggiuntive V3R, V4R, V7â€“V9", "Data e ora di esecuzione dell''ECG aggiuntivo", "Referto interpretativo delle derivazioni aggiuntive", "Indicazione clinica per l''esecuzione delle derivazioni aggiuntive"], "free_text_allowed": true, "justification_fields": ["Nota clinica che documenta il motivo della mancata esecuzione delle derivazioni aggiuntive", "Descrizione della condizione di emergenza che ha impedito l''esecuzione"], "acceptable_evidence_sources": ["Tracciato ECG digitale in cartella clinica elettronica", "Referto ECG firmato dal medico", "Nota clinica del medico d''emergenza", "Stampa cartacea del tracciato ECG allegata alla documentazione"], "justification_required_when_deviating": true}, "evidence_of_non_compliance": [{"description": "Assenza di tracciato ECG con derivazioni aggiuntive in cartella clinica nonostante la presenza di STEMI inferiore o sospetta occlusione coronarica totale con ECG standard non conclusivo, senza documentazione di eccezione o giustificazione clinica.", "evidence_id": "ENC-005-01", "evidence_type": "absence_of_event", "time_reference": "Nell''intero episodio di cura acuto", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-005-01", "DE-005-02", "DE-005-03", "DE-005-04", "DE-005-06"]}, {"description": "Ritardo significativo (oltre 10 minuti) nell''esecuzione dell''ECG con derivazioni aggiuntive rispetto all''ECG standard diagnostico.", "evidence_id": "ENC-005-02", "evidence_type": "timestamp", "time_reference": "Differenza tra timestamp ECG aggiuntivo e timestamp ECG standard > 10 minuti", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-005-07", "DE-005-01"]}]}');
INSERT INTO riskm_manager_model_evaluation.rule_definition OVERRIDING SYSTEM VALUE VALUES (6, 1, 'STEMI-DO-006', '{"title": "Esecuzione di un ECG a 12 derivazioni aggiuntivo in caso di sintomi ricorrenti o incertezza diagnostica", "intent": "Garantire una rivalutazione elettrocardiografica tempestiva nei pazienti con sospetto STEMI che presentano sintomi ricorrenti o in cui persiste incertezza diagnostica, al fine di identificare variazioni ischemiche evolutive e supportare decisioni terapeutiche appropriate.", "rule_id": "STEMI-DO-006", "trigger": {"anchor_event": "Esecuzione del primo ECG a 12 derivazioni", "trigger_type": "documented_symptom", "inference_allowed": true, "trigger_description": "Il trigger si attiva quando il paziente con sospetto STEMI presenta una recidiva di sintomi ischemici (es. dolore toracico, dispnea, sudorazione) dopo l''ECG iniziale, oppure quando il clinico documenta un''incertezza diagnostica relativa all''interpretazione dell''ECG iniziale.", "end_of_applicability": "Fino alla conferma o all''esclusione della diagnosi di STEMI, oppure fino all''attivazione della strategia di riperfusione.", "trigger_data_elements": ["DE-STEMI-006-01", "DE-STEMI-006-02", "DE-STEMI-006-03"], "start_of_applicability": "Dal momento della comparsa di sintomi ricorrenti o della documentazione di incertezza diagnostica dopo il primo ECG."}, "rationale": "Un ECG a 12 derivazioni aggiuntivo consente di identificare alterazioni del segmento ST di nuova insorgenza o in evoluzione, migliorando l''accuratezza diagnostica nei casi di incertezza e nei pazienti con sintomi ricorrenti suggestivi di ischemia in corso. L''omissione di tale controllo potrebbe ritardare il riconoscimento di uno STEMI e la conseguente rivascolarizzazione.", "rule_type": "do", "exceptions": [{"label": "Paziente in arresto cardiaco non recuperato", "description": "Il paziente Ã¨ in arresto cardiaco refrattario e l''esecuzione di un ECG aggiuntivo non Ã¨ tecnicamente praticabile o clinicamente prioritaria rispetto alle manovre rianimatorie in corso.", "exception_id": "STEMI-DO-006-EXP-01", "condition_logic": "cardiac_arrest_ongoing == true AND ROSC == false", "required_evidence": ["Documentazione dello stato di arresto cardiaco", "Registrazione delle manovre rianimatorie in corso"], "required_justification": true}, {"label": "Trasferimento emergente in atto verso sala di emodinamica", "description": "Il paziente Ã¨ giÃ  in trasferimento emergente verso il laboratorio di emodinamica e la sosta per un ECG aggiuntivo comporterebbe un ritardo clinicamente inaccettabile nella riperfusione.", "exception_id": "STEMI-DO-006-EXP-02", "condition_logic": "emergent_transfer_to_cath_lab == true AND delay_unacceptable == true", "required_evidence": ["Documentazione del trasferimento emergente in corso", "Motivazione clinica del mancato ECG aggiuntivo"], "required_justification": true}], "short_label": "ECG aggiuntivo per sintomi ricorrenti/incertezza", "applicability": {"care_context": "Fase diagnostica del percorso STEMI, applicabile in ambito pre-ospedaliero, pronto soccorso e unitÃ  di terapia intensiva coronarica.", "clinical_context": "Sospetto STEMI con sintomatologia ricorrente (es. dolore toracico recidivante) o tracciato ECG iniziale non conclusivo per la diagnosi.", "exclusion_criteria": [{"label": "Diagnosi STEMI giÃ  confermata e trattamento avviato", "description": "Il paziente ha giÃ  una diagnosi STEMI confermata e la strategia di riperfusione Ã¨ giÃ  stata attivata. In questo caso l''ECG aggiuntivo non modifica la gestione immediata.", "criterion_id": "STEMI-DO-006-EXC-01", "data_elements": ["DE-STEMI-006-05", "DE-STEMI-006-06"], "logic_expression": "stemi_confirmed == true AND reperfusion_activated == true", "inference_allowed": false}], "inclusion_criteria": [{"label": "Sintomi ricorrenti suggestivi di ischemia", "description": "Il paziente presenta recidiva di dolore toracico o sintomi equivalenti ischemici dopo l''esecuzione del primo ECG a 12 derivazioni.", "criterion_id": "STEMI-DO-006-INC-01", "data_elements": ["DE-STEMI-006-01", "DE-STEMI-006-02"], "logic_expression": "recurrent_ischemic_symptoms == true", "inference_allowed": true}, {"label": "Incertezza diagnostica persistente", "description": "Il tracciato ECG iniziale non Ã¨ conclusivo per la diagnosi di STEMI (es. blocco di branca sinistra preesistente, ritmo da pacemaker, alterazioni aspecifiche del tratto ST) oppure il quadro clinico Ã¨ discordante rispetto ai reperti elettrocardiografici.", "criterion_id": "STEMI-DO-006-INC-02", "data_elements": ["DE-STEMI-006-03", "DE-STEMI-006-04"], "logic_expression": "diagnostic_uncertainty == true", "inference_allowed": true}], "population_description": "Pazienti adulti con sospetto clinico di infarto miocardico con sopraslivellamento del tratto ST (STEMI) che presentano sintomi ricorrenti o in cui persiste incertezza diagnostica dopo l''ECG iniziale."}, "care_settings": ["pronto soccorso", "unitÃ  di terapia intensiva coronarica", "pre-ospedaliero", "reparto di cardiologia"], "clinical_phase": "diagnosi", "evidence_level": "Livello di evidenza C", "schema_version": "1.0.0", "expected_action": {"action_verb": "eseguire", "action_target": "ECG a 12 derivazioni", "action_parameters": [{"unit": "derivazioni", "mandatory": true, "expected_value": "12", "parameter_name": "Numero di derivazioni", "comparison_operator": "equals", "parameter_description": "L''ECG deve includere almeno tutte le 12 derivazioni standard."}, {"unit": null, "mandatory": true, "expected_value": "presente", "parameter_name": "Interpretazione clinica documentata", "comparison_operator": "equals", "parameter_description": "Il tracciato deve essere interpretato da un medico e l''esito documentato nel fascicolo clinico."}, {"unit": null, "mandatory": false, "expected_value": null, "parameter_name": "Derivazioni aggiuntive opzionali", "comparison_operator": null, "parameter_description": "In caso di sospetto infarto posteriore o del ventricolo destro, possono essere aggiunte derivazioni V7-V9 e V3R-V4R."}], "action_description": "Eseguire un ECG a 12 derivazioni aggiuntivo con acquisizione completa di tutte le derivazioni standard, provvedendo a un''interpretazione rapida del tracciato con ricerca di alterazioni del tratto ST, nuove onde Q, o altri segni indicativi di ischemia acuta.", "alternative_compliant_actions": ["Monitoraggio ECG continuo con registrazione periodica del tracciato a 12 derivazioni se l''ECG aggiuntivo non Ã¨ immediatamente disponibile"]}, "deontic_strength": "recommended", "evaluation_logic": {"notes": "L''incertezza diagnostica Ã¨ spesso documentata in formato narrativo e richiede estrazione inferenziale dalle note cliniche. In caso di dubbio sulla presenza del trigger, Ã¨ necessaria la revisione umana.", "ambiguity_policy": "review_required", "formal_expression": "IF (recurrent_symptoms == TRUE OR diagnostic_uncertainty == TRUE) AND NOT (stemi_confirmed == TRUE AND reperfusion_activated == TRUE) THEN IF additional_ecg_performed == TRUE AND ecg_interpretation_documented == TRUE THEN status = ''compliant'' ELSE IF exception_documented == TRUE THEN status = ''justified_deviation'' ELSE status = ''non_compliant'' ELSE status = ''not_applicable''", "missing_data_policy": "review_required", "natural_language_test": "Verificare se, in presenza di sintomi ricorrenti documentati OPPURE incertezza diagnostica documentata dopo il primo ECG, Ã¨ stato eseguito almeno un ECG a 12 derivazioni aggiuntivo con relativa interpretazione clinica registrata nel fascicolo del paziente. La regola Ã¨ soddisfatta se il tracciato ECG aggiuntivo e il referto sono presenti; Ã¨ non conforme se mancano nonostante la presenza dei trigger.", "conflict_resolution_policy": "human_review", "formal_expression_language": "pseudocode"}, "time_constraints": [{"description": "L''ECG aggiuntivo a 12 derivazioni deve essere eseguito entro 10 minuti dalla comparsa dei sintomi ricorrenti o dal riconoscimento dell''incertezza diagnostica.", "anchor_event": "Comparsa di sintomi ricorrenti o riconoscimento di incertezza diagnostica", "constraint_id": "STEMI-DO-006-TC-01", "duration_unit": "minuti", "hard_deadline": false, "duration_value": 10, "relation_to_anchor": "within", "alert_threshold_unit": "minuti", "alert_threshold_value": 5}], "evaluation_method": {"notes": "L''identificazione dell''incertezza diagnostica richiede analisi testuale inferenziale. La verifica dell''avvenuta esecuzione dell''ECG aggiuntivo puÃ² essere deterministica se il timestamp Ã¨ disponibile nel sistema ECG. La revisione umana Ã¨ consigliata per confermare la corretta identificazione del trigger.", "primary_method": "hybrid", "minimum_confidence": 0.8, "human_review_required": true, "allowed_inference_sources": ["note cliniche di pronto soccorso", "referti ECG", "lettere di dimissione", "registrazioni infermieristiche", "sistema di gestione emergenze"]}, "possible_outcomes": ["compliant", "non_compliant", "justified_deviation", "not_applicable", "not_evaluable"], "source_references": [{"issuer": "European Society of Cardiology (ESC)", "source_id": "ESC-STEMI-2023", "citation_uri": "https://doi.org/10.1093/eurheartj/ehad191", "license_note": "Contenuto soggetto a copyright ESC. Uso a fini clinici e di ricerca secondo i termini dell''editore.", "source_level": "international", "document_title": "2023 ESC Guidelines for the management of acute coronary syndromes", "page_reference": null, "statement_quote": "An additional 12-lead ECG is recommended in cases with recurrent symptoms or diagnostic uncertainty.", "document_version": "2023", "publication_date": "2023-08-25", "section_reference": "Sezione Diagnosi â€“ Elettrocardiogramma"}], "original_statement": "An additional 12-lead ECG is recommended in cases with recurrent symptoms or diagnostic uncertainty.", "responsible_actors": [{"notes": "Responsabile della decisione clinica di eseguire un ECG aggiuntivo e dell''interpretazione del tracciato.", "role_name": "Medico d''emergenza", "organization_unit": "Pronto Soccorso", "responsibility_type": "primary"}, {"notes": "Responsabile dell''esecuzione tecnica dell''ECG a 12 derivazioni su indicazione medica.", "role_name": "Infermiere di pronto soccorso", "organization_unit": "Pronto Soccorso", "responsibility_type": "supporting"}, {"notes": "Consultato in caso di persistenza dell''incertezza diagnostica dopo l''ECG aggiuntivo.", "role_name": "Cardiologo di guardia", "organization_unit": "Cardiologia / UTIC", "responsibility_type": "consulted"}], "clinical_pathway_id": "PDTA-STEMI-001", "completion_criteria": {"description": "L''azione Ã¨ considerata completata quando un ECG a 12 derivazioni aggiuntivo Ã¨ stato acquisito, interpretato da un medico e il risultato Ã¨ stato documentato nel fascicolo clinico del paziente.", "success_condition": "ECG a 12 derivazioni aggiuntivo acquisito AND interpretazione documentata nel fascicolo clinico AND timestamp registrato", "minimum_occurrences": 1, "required_event_types": ["acquisizione_ecg_12_derivazioni", "interpretazione_ecg", "documentazione_referto_ecg"], "required_documentation_elements": ["Tracciato ECG a 12 derivazioni acquisito", "Referto di interpretazione con indicazione della presenza o assenza di alterazioni ischemiche", "Timestamp di acquisizione dell''ECG aggiuntivo"]}, "extraction_metadata": {"validated_at": null, "validated_by": null, "ambiguity_flags": ["Il concetto di ''incertezza diagnostica'' non Ã¨ definito in modo univoco nella linea guida; la sua operazionalizzazione dipende dall''interpretazione clinica locale.", "Non Ã¨ specificato un vincolo temporale esplicito nella raccomandazione originale; il limite di 10 minuti Ã¨ stato derivato dalla pratica clinica standard per ECG in contesto emergenziale."], "generation_mode": "llm_inference", "extraction_confidence": 0.88, "human_validation_status": "not_reviewed", "source_interpretation_notes": "La raccomandazione originale utilizza il termine ''recommended'', interpretato come forza deontica ''raccomandato'' (non obbligatorio). I trigger ''recurrent symptoms'' e ''diagnostic uncertainty'' sono stati tradotti e operazionalizzati rispettivamente come sintomi ischemici ricorrenti e incertezza diagnostica documentata. L''incertezza diagnostica Ã¨ un concetto soggettivo che richiede estrazione inferenziale dalle note cliniche."}, "governance_metadata": {"version": "1.0.0", "rule_owner": "Dipartimento di Cardiologia d''Urgenza", "approved_by": null, "effective_to": null, "review_cycle": "ogni 12 mesi", "authoring_body": "Gruppo di lavoro PDTA STEMI", "effective_from": "2024-01-01", "last_reviewed_at": null, "lifecycle_status": "draft"}, "risk_classification": {"rationale": "La mancata esecuzione di un ECG aggiuntivo in caso di sintomi ricorrenti o incertezza diagnostica puÃ² portare al mancato riconoscimento di uno STEMI in evoluzione, con conseguente ritardo nella riperfusione e aumento del rischio di danno miocardico irreversibile e mortalitÃ .", "detectability": "moderate", "priority_score": 7.5, "process_risk_severity": "moderate", "clinical_risk_severity": "high", "likelihood_if_violated": "possible"}, "normalized_statement": "In presenza di sintomi ricorrenti o incertezza diagnostica, Ã¨ raccomandata l''esecuzione di un ECG a 12 derivazioni aggiuntivo.", "sequence_constraints": [{"description": "L''ECG aggiuntivo deve essere eseguito dopo la comparsa dei sintomi ricorrenti o della documentazione di incertezza diagnostica, e prima della decisione definitiva sulla strategia di riperfusione.", "allowed_order": "predecessor_first", "constraint_id": "STEMI-DO-006-SC-01", "successor_event": "Esecuzione ECG a 12 derivazioni aggiuntivo", "predecessor_event": "Comparsa di sintomi ricorrenti o incertezza diagnostica documentata", "violation_condition": "L''ECG aggiuntivo non Ã¨ stato eseguito nonostante la documentazione di sintomi ricorrenti o incertezza diagnostica."}], "clinical_pathway_name": "Percorso Diagnostico Terapeutico Assistenziale per STEMI", "evidence_of_compliance": [{"description": "Presenza di un tracciato ECG a 12 derivazioni aggiuntivo acquisito e documentato nel fascicolo clinico del paziente dopo la comparsa di sintomi ricorrenti o incertezza diagnostica.", "evidence_id": "STEMI-DO-006-EOC-01", "evidence_type": "execution", "time_reference": "Dopo la comparsa dei sintomi ricorrenti o la documentazione di incertezza diagnostica", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-STEMI-006-07", "DE-STEMI-006-08"]}, {"description": "Documentazione dell''interpretazione clinica del tracciato ECG aggiuntivo con valutazione delle alterazioni ischemiche.", "evidence_id": "STEMI-DO-006-EOC-02", "evidence_type": "documentation", "time_reference": "Contestualmente o immediatamente dopo l''acquisizione dell''ECG aggiuntivo", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-STEMI-006-08"]}], "required_data_elements": [{"name": "Presenza di sintomi ricorrenti", "data_type": "boolean", "query_hint": "Cercare documentazione di recidiva di dolore toracico o sintomi equivalenti ischemici nelle note cliniche o nel sistema di monitoraggio.", "description": "Indicazione della recidiva di sintomi ischemici (dolore toracico, dispnea, sudorazione) dopo l''ECG iniziale.", "coding_system": null, "data_element_id": "DE-STEMI-006-01", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "Timestamp comparsa sintomi ricorrenti", "data_type": "datetime", "query_hint": "Verificare la registrazione temporale degli eventi clinici nel sistema di gestione del pronto soccorso.", "description": "Data e ora della comparsa dei sintomi ischemici ricorrenti.", "coding_system": null, "data_element_id": "DE-STEMI-006-02", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Incertezza diagnostica documentata", "data_type": "boolean", "query_hint": "Analizzare le note cliniche per espressioni di dubbio diagnostico, ECG non conclusivo, alterazioni aspecifiche del tratto ST.", "description": "Documentazione da parte del clinico di un''incertezza nell''interpretazione dell''ECG iniziale o nel quadro clinico complessivo.", "coding_system": null, "data_element_id": "DE-STEMI-006-03", "source_location": "ehr_unstructured", "extraction_method": "inferential", "required_for_evaluation": true}, {"name": "Referto ECG iniziale", "data_type": "text", "query_hint": "Recuperare il referto del primo ECG eseguito nel percorso STEMI dal sistema di cardiologia o dal fascicolo di PS.", "description": "Referto dell''ECG a 12 derivazioni iniziale con interpretazione clinica.", "coding_system": null, "data_element_id": "DE-STEMI-006-04", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Diagnosi STEMI confermata", "data_type": "boolean", "query_hint": "Verificare la presenza di codice ICD-10 I21.x confermato o diagnosi clinica di STEMI.", "description": "Indicazione se la diagnosi di STEMI Ã¨ stata confermata definitivamente.", "coding_system": "ICD-10", "data_element_id": "DE-STEMI-006-05", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Attivazione strategia di riperfusione", "data_type": "boolean", "query_hint": "Verificare l''attivazione del percorso emodinamica o la somministrazione di fibrinolitico nel sistema ordini.", "description": "Indicazione se la strategia di riperfusione (PCI primaria o fibrinolisi) Ã¨ giÃ  stata attivata.", "coding_system": null, "data_element_id": "DE-STEMI-006-06", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Timestamp ECG aggiuntivo", "data_type": "datetime", "query_hint": "Recuperare il timestamp del secondo o successivo ECG a 12 derivazioni dal sistema ECG o dal fascicolo clinico.", "description": "Data e ora di acquisizione dell''ECG a 12 derivazioni aggiuntivo.", "coding_system": null, "data_element_id": "DE-STEMI-006-07", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Referto ECG aggiuntivo", "data_type": "text", "query_hint": "Recuperare il referto dell''ECG aggiuntivo dal sistema di cardiologia o dal fascicolo di PS.", "description": "Referto dell''ECG a 12 derivazioni aggiuntivo con interpretazione clinica documentata.", "coding_system": null, "data_element_id": "DE-STEMI-006-08", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}], "recommendation_strength": "Classe I", "associated_weak_signal_ids": ["STEMI-WS-006-01", "STEMI-WS-006-02"], "documentation_requirements": {"mandatory_fields": ["Tracciato ECG a 12 derivazioni aggiuntivo", "Referto di interpretazione dell''ECG aggiuntivo", "Timestamp di acquisizione dell''ECG aggiuntivo", "Indicazione clinica per l''esecuzione dell''ECG aggiuntivo (sintomi ricorrenti o incertezza diagnostica)"], "free_text_allowed": true, "justification_fields": ["Motivazione clinica per la mancata esecuzione dell''ECG aggiuntivo", "Condizione clinica del paziente al momento della decisione"], "acceptable_evidence_sources": ["Sistema ECG digitale", "Fascicolo clinico elettronico", "Note mediche di pronto soccorso", "Registrazioni infermieristiche", "Sistema di gestione emergenze"], "justification_required_when_deviating": true}, "evidence_of_non_compliance": [{"description": "Assenza di un ECG a 12 derivazioni aggiuntivo nel fascicolo clinico nonostante la documentazione di sintomi ricorrenti o di incertezza diagnostica.", "evidence_id": "STEMI-DO-006-EONC-01", "evidence_type": "absence_of_event", "time_reference": "Dall''insorgenza dei sintomi ricorrenti o dell''incertezza diagnostica fino alla chiusura dell''episodio diagnostico", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-STEMI-006-01", "DE-STEMI-006-03", "DE-STEMI-006-07"]}, {"description": "ECG aggiuntivo eseguito ma privo di referto o interpretazione clinica documentata.", "evidence_id": "STEMI-DO-006-EONC-02", "evidence_type": "documentation", "time_reference": "Dopo l''acquisizione dell''ECG aggiuntivo", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-STEMI-006-07", "DE-STEMI-006-08"]}]}');
INSERT INTO riskm_manager_model_evaluation.rule_definition OVERRIDING SYSTEM VALUE VALUES (7, 1, 'STEMI-DO-007', '{"title": "Dosaggio delle troponine cardiache con metodo ad alta sensibilitÃ  immediatamente dopo la presentazione e ottenimento dei risultati entro 60 minuti dal prelievo ematico", "intent": "Garantire una diagnosi biochimica tempestiva di necrosi miocardica mediante il dosaggio rapido delle troponine cardiache ad alta sensibilitÃ  per supportare la diagnosi differenziale e la stratificazione del rischio nei pazienti con sospetto STEMI.", "rule_id": "STEMI-DO-007", "trigger": {"anchor_event": "presentazione_paziente_ps", "trigger_type": "event", "inference_allowed": true, "trigger_description": "Presentazione del paziente al pronto soccorso con sospetto clinico di STEMI o sindrome coronarica acuta con sopraslivellamento del tratto ST.", "end_of_applicability": "Alla ricezione del risultato della troponina hs o alla conferma diagnostica attraverso altro percorso.", "trigger_data_elements": ["DE-STEMI-007-01", "DE-STEMI-007-02", "DE-STEMI-007-03"], "start_of_applicability": "Immediatamente al momento della presentazione del paziente al pronto soccorso con sospetto di STEMI."}, "rationale": "Il dosaggio precoce delle troponine cardiache con metodo ad alta sensibilitÃ  consente di confermare o escludere rapidamente la necrosi miocardica, supportando le decisioni terapeutiche urgenti come l''attivazione del laboratorio di emodinamica. Un tempo di refertazione entro 60 minuti dal prelievo Ã¨ essenziale per non ritardare la strategia di riperfusione e migliorare gli outcome clinici.", "rule_type": "do", "exceptions": [{"label": "Diagnosi STEMI evidente con trasferimento immediato in sala di emodinamica", "description": "Nei casi in cui la diagnosi di STEMI Ã¨ chiaramente evidente dall''ECG e il paziente viene immediatamente trasferito al laboratorio di emodinamica per angioplastica primaria, il prelievo per la troponina puÃ² essere eseguito ma il risultato potrebbe non essere disponibile prima dell''inizio della procedura. L''assenza del risultato prima della procedura non costituisce una non conformitÃ  se il prelievo Ã¨ stato effettuato.", "exception_id": "STEMI-DO-007-EXC-COND-01", "condition_logic": "ecg.stemi_clear == true AND cath_lab.activation_immediate == true AND blood_sample.troponin_ordered == true", "required_evidence": ["ECG con chiaro sopraslivellamento ST", "Ordine di attivazione immediata della sala di emodinamica", "Documentazione dell''avvenuto prelievo ematico per troponina"], "required_justification": true}, {"label": "IndisponibilitÃ  temporanea del metodo ad alta sensibilitÃ ", "description": "Il metodo ad alta sensibilitÃ  non Ã¨ temporaneamente disponibile per guasto strumentale o indisponibilitÃ  del reagente. In tal caso Ã¨ accettabile l''uso di un metodo convenzionale come misura temporanea, con documentazione della causa.", "exception_id": "STEMI-DO-007-EXC-COND-02", "condition_logic": "lab.hs_troponin_assay_available == false AND lab.instrument_failure == true", "required_evidence": ["Documentazione del guasto strumentale o della mancata disponibilitÃ  del reagente", "Risultato con metodo convenzionale come alternativa"], "required_justification": true}], "short_label": "Troponina hs entro 60 min", "applicability": {"care_context": "Pronto soccorso o dipartimento di emergenza-urgenza, fase di valutazione diagnostica iniziale.", "clinical_context": "Sospetto clinico di infarto miocardico acuto con sopraslivellamento del tratto ST, fase diagnostica iniziale.", "exclusion_criteria": [{"label": "Diagnosi alternativa certa all''arrivo", "description": "Ãˆ stata giÃ  identificata con certezza una diagnosi alternativa non cardiaca che spiega completamente il quadro clinico, rendendo non necessario il dosaggio delle troponine.", "criterion_id": "STEMI-DO-007-EXC-01", "data_elements": ["DE-STEMI-007-08"], "logic_expression": "diagnosis.alternative_confirmed == true AND diagnosis.cardiac_excluded == true", "inference_allowed": false}], "inclusion_criteria": [{"label": "Presentazione con dolore toracico sospetto per SCA", "description": "Il paziente si presenta con dolore toracico o sintomi equivalenti suggestivi di sindrome coronarica acuta.", "criterion_id": "STEMI-DO-007-INC-01", "data_elements": ["DE-STEMI-007-01", "DE-STEMI-007-02"], "logic_expression": "symptom.chief_complaint IN (''dolore_toracico'', ''dispnea_acuta'', ''sincope'', ''dolore_epigastrico_sospetto'') OR clinical_suspicion.acs == true", "inference_allowed": true}, {"label": "Alterazioni ECG compatibili con STEMI", "description": "L''elettrocardiogramma mostra un sopraslivellamento del tratto ST o equivalenti elettrocardiografici suggestivi di STEMI.", "criterion_id": "STEMI-DO-007-INC-02", "data_elements": ["DE-STEMI-007-03"], "logic_expression": "ecg.st_elevation == true OR ecg.lbbb_new_onset == true OR ecg.stemi_equivalent == true", "inference_allowed": true}], "population_description": "Pazienti adulti che si presentano al pronto soccorso con sospetta sindrome coronarica acuta con sopraslivellamento del tratto ST (STEMI)."}, "care_settings": ["pronto soccorso", "dipartimento di emergenza-urgenza", "unitÃ  di terapia intensiva cardiologica"], "clinical_phase": "diagnosi", "evidence_level": "Livello B", "schema_version": "1.0.0", "expected_action": {"action_verb": "dosare", "action_target": "troponina cardiaca ad alta sensibilitÃ  (hs-cTnI o hs-cTnT)", "action_parameters": [{"unit": null, "mandatory": true, "expected_value": "alta sensibilitÃ  (hs)", "parameter_name": "metodo_analitico", "comparison_operator": "equals", "parameter_description": "Tipo di metodo analitico utilizzato per il dosaggio della troponina cardiaca."}, {"unit": null, "mandatory": true, "expected_value": "immediato", "parameter_name": "tempistica_prelievo", "comparison_operator": "equals", "parameter_description": "Momento in cui deve essere effettuato il prelievo ematico rispetto alla presentazione del paziente."}, {"unit": "minuti", "mandatory": true, "expected_value": "60", "parameter_name": "tempo_massimo_refertazione", "comparison_operator": "less_than", "parameter_description": "Tempo massimo entro il quale il risultato del dosaggio della troponina deve essere disponibile dal momento del prelievo ematico."}], "action_description": "Eseguire il prelievo ematico per il dosaggio delle troponine cardiache con metodo ad alta sensibilitÃ  (hs-cTn) immediatamente dopo la presentazione del paziente e garantire che i risultati siano disponibili entro 60 minuti dal momento del prelievo.", "alternative_compliant_actions": ["Utilizzo di dosaggio della troponina con metodo point-of-care ad alta sensibilitÃ  se disponibile e validato, con refertazione entro 60 minuti dal prelievo"]}, "deontic_strength": "mandatory", "evaluation_logic": {"notes": "Il vincolo di 15 minuti per il prelievo Ã¨ un''operazionalizzazione del termine ''immediatamente'' presente nella raccomandazione originale. Il vincolo di 60 minuti dal prelievo alla refertazione Ã¨ esplicito nel testo della linea guida. In caso di dati mancanti relativi ai timestamp, Ã¨ necessaria una revisione manuale per determinare la conformitÃ .", "ambiguity_policy": "review_required", "formal_expression": "IF (patient.suspected_stemi == true) THEN { LET t_pres = timestamp_presentazione; LET t_prel = timestamp_prelievo_troponina; LET t_ref = timestamp_refertazione_troponina; LET method = metodo_analitico; IF (t_prel IS NOT NULL AND t_ref IS NOT NULL AND method == ''hs'') THEN { IF ((t_prel - t_pres) <= 15 min AND (t_ref - t_prel) <= 60 min) THEN RETURN ''compliant''; ELSE IF (exception_documented == true) THEN RETURN ''justified_deviation''; ELSE RETURN ''non_compliant''; } ELSE IF (t_prel IS NULL OR t_ref IS NULL) THEN { IF (exception_documented == true) THEN RETURN ''justified_deviation''; ELSE RETURN ''non_compliant''; } } ELSE RETURN ''not_applicable'';", "missing_data_policy": "review_required", "natural_language_test": "Verificare che: (1) il paziente con sospetto STEMI abbia avuto un prelievo ematico per troponina hs eseguito immediatamente dopo la presentazione (entro 15 minuti); (2) il metodo analitico utilizzato sia ad alta sensibilitÃ ; (3) il risultato sia stato refertato e reso disponibile nel sistema informativo entro 60 minuti dal momento del prelievo ematico. Se tutti e tre i criteri sono soddisfatti, la regola Ã¨ conforme. Se uno qualsiasi dei criteri non Ã¨ soddisfatto, la regola Ã¨ non conforme a meno che non sia presente una deviazione giustificata documentata.", "conflict_resolution_policy": "human_review", "formal_expression_language": "pseudocode"}, "time_constraints": [{"description": "Il prelievo ematico per il dosaggio della troponina ad alta sensibilitÃ  deve essere eseguito immediatamente dopo la presentazione del paziente.", "anchor_event": "presentazione_paziente_ps", "constraint_id": "STEMI-DO-007-TC-01", "duration_unit": "minuti", "hard_deadline": true, "duration_value": 15, "relation_to_anchor": "immediate", "alert_threshold_unit": "minuti", "alert_threshold_value": 10}, {"description": "I risultati del dosaggio della troponina cardiaca ad alta sensibilitÃ  devono essere disponibili entro 60 minuti dal prelievo ematico.", "anchor_event": "prelievo_ematico_troponina", "constraint_id": "STEMI-DO-007-TC-02", "duration_unit": "minuti", "hard_deadline": true, "duration_value": 60, "relation_to_anchor": "within", "alert_threshold_unit": "minuti", "alert_threshold_value": 45}], "evaluation_method": {"notes": "La valutazione primaria Ã¨ deterministica basata sui timestamp strutturati. Il metodo inferenziale Ã¨ necessario solo quando i timestamp strutturati non sono disponibili e occorre estrarre le informazioni temporali dalle note cliniche.", "primary_method": "hybrid", "minimum_confidence": 0.85, "human_review_required": false, "allowed_inference_sources": ["note cliniche di pronto soccorso", "registro di triage", "sistema informativo di laboratorio (LIS)", "cartella clinica elettronica"]}, "possible_outcomes": ["compliant", "non_compliant", "justified_deviation", "not_applicable", "not_evaluable", "probable_non_compliance"], "source_references": [{"issuer": "European Society of Cardiology (ESC)", "source_id": "ESC-STEMI-GL-2023", "citation_uri": "https://doi.org/10.1093/eurheartj/ehad191", "license_note": "Contenuto utilizzato a scopo di derivazione di regole cliniche in conformitÃ  con le linee guida ESC. Copyright European Society of Cardiology.", "source_level": "international", "document_title": "2023 ESC Guidelines for the management of acute coronary syndromes", "page_reference": null, "statement_quote": "It is recommended to measure cardiac troponins with high-sensitivity assays immediately after presentation and to obtain the results within 60 min of blood sampling.", "document_version": "2023", "publication_date": "2023-08-25", "section_reference": "Sezione 4 - Diagnosi"}], "original_statement": "It is recommended to measure cardiac troponins with high-sensitivity assays immediately after presentation and to obtain the results within 60 min of blood sampling.", "responsible_actors": [{"notes": "Responsabile della prescrizione del dosaggio della troponina ad alta sensibilitÃ  al momento della presentazione del paziente.", "role_name": "medico di pronto soccorso", "organization_unit": "pronto soccorso", "responsibility_type": "primary"}, {"notes": "Responsabile dell''esecuzione del prelievo ematico e dell''invio del campione al laboratorio secondo protocollo fast-track.", "role_name": "infermiere di triage", "organization_unit": "pronto soccorso", "responsibility_type": "supporting"}, {"notes": "Responsabile dell''elaborazione del campione e della refertazione della troponina hs nel tempo stabilito.", "role_name": "tecnico di laboratorio biomedico", "organization_unit": "laboratorio analisi d''urgenza", "responsibility_type": "primary"}, {"notes": "Consultato per l''interpretazione clinica del risultato della troponina nel contesto del sospetto STEMI.", "role_name": "cardiologo di guardia", "organization_unit": "unitÃ  di terapia intensiva coronarica", "responsibility_type": "consulted"}], "clinical_pathway_id": "PDTA-STEMI-001", "completion_criteria": {"description": "La regola Ã¨ considerata soddisfatta quando il prelievo ematico per la troponina hs Ã¨ stato eseguito immediatamente dopo la presentazione e il risultato Ã¨ stato ricevuto e registrato nel sistema informativo clinico entro 60 minuti dal momento del prelievo.", "success_condition": "(timestamp_prelievo - timestamp_presentazione <= 15 minuti) AND (timestamp_refertazione - timestamp_prelievo <= 60 minuti) AND metodo == ''alta_sensibilitÃ ''", "minimum_occurrences": 1, "required_event_types": ["ordine_dosaggio_troponina_hs", "prelievo_ematico", "refertazione_troponina_hs"], "required_documentation_elements": ["timestamp_ordine_troponina", "timestamp_prelievo_ematico", "timestamp_refertazione_risultato", "valore_troponina_hs", "metodo_analitico_utilizzato"]}, "extraction_metadata": {"validated_at": null, "validated_by": null, "ambiguity_flags": ["Il termine ''immediately'' Ã¨ stato interpretato come ''entro 15 minuti'' - soglia da validare con il comitato clinico locale", "Non Ã¨ specificato se il vincolo di 60 minuti si applica anche ai dosaggi point-of-care"], "generation_mode": "llm_inference", "extraction_confidence": 0.93, "human_validation_status": "not_reviewed", "source_interpretation_notes": "Il testo originale specifica ''immediately after presentation'' che Ã¨ stato operazionalizzato come entro 15 minuti dalla presentazione, un valore soglia comunemente adottato nella pratica clinica per definire l''immediatezza in contesto di emergenza. Il vincolo di 60 minuti dal prelievo alla disponibilitÃ  dei risultati Ã¨ esplicito nel testo. Il termine ''high-sensitivity assays'' Ã¨ stato tradotto come ''metodo ad alta sensibilitÃ  (hs)'' in conformitÃ  con la terminologia clinica italiana."}, "governance_metadata": {"version": "1.0.0", "rule_owner": "Direttore del Dipartimento di Emergenza-Urgenza", "approved_by": null, "effective_to": null, "review_cycle": "12 mesi", "authoring_body": "Gruppo di lavoro PDTA STEMI", "effective_from": null, "last_reviewed_at": null, "lifecycle_status": "draft"}, "risk_classification": {"rationale": "Il ritardo nel dosaggio e nella refertazione della troponina hs puÃ² determinare un ritardo diagnostico significativo nei pazienti con STEMI, con conseguente ritardo nella strategia di riperfusione e peggioramento dell''outcome clinico. Il rischio clinico Ã¨ elevato perchÃ© il mancato rispetto di questa regola puÃ² contribuire a un ritardo complessivo del door-to-balloon time. La violazione Ã¨ facilmente rilevabile attraverso i timestamp registrati nei sistemi informativi.", "detectability": "easy", "priority_score": 8.5, "process_risk_severity": "high", "clinical_risk_severity": "high", "likelihood_if_violated": "possible"}, "normalized_statement": "Si raccomanda di dosare le troponine cardiache con metodo ad alta sensibilitÃ  immediatamente dopo la presentazione del paziente e di ottenere i risultati entro 60 minuti dal prelievo ematico.", "sequence_constraints": [{"description": "Il prelievo ematico per la troponina deve avvenire prima della refertazione del risultato.", "allowed_order": "predecessor_first", "constraint_id": "STEMI-DO-007-SC-01", "successor_event": "refertazione_troponina_hs", "predecessor_event": "prelievo_ematico_troponina", "violation_condition": "timestamp_refertazione <= timestamp_prelievo OR prelievo_ematico non documentato"}, {"description": "La presentazione del paziente deve precedere l''ordine e il prelievo per la troponina.", "allowed_order": "predecessor_first", "constraint_id": "STEMI-DO-007-SC-02", "successor_event": "prelievo_ematico_troponina", "predecessor_event": "presentazione_paziente_ps", "violation_condition": "timestamp_prelievo < timestamp_presentazione"}], "clinical_pathway_name": "Percorso Diagnostico Terapeutico Assistenziale per STEMI", "evidence_of_compliance": [{"description": "Ordine di dosaggio della troponina cardiaca con metodo ad alta sensibilitÃ  registrato nel sistema informativo clinico.", "evidence_id": "STEMI-DO-007-EOC-01", "evidence_type": "order", "time_reference": "Entro i primi minuti dalla presentazione del paziente al pronto soccorso.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-STEMI-007-04", "DE-STEMI-007-05"]}, {"description": "Prelievo ematico per troponina hs eseguito immediatamente dopo la presentazione del paziente.", "evidence_id": "STEMI-DO-007-EOC-02", "evidence_type": "execution", "time_reference": "Immediatamente dopo la presentazione (entro 15 minuti).", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-STEMI-007-04", "DE-STEMI-007-05"]}, {"description": "Risultato della troponina hs disponibile e registrato entro 60 minuti dal prelievo ematico.", "evidence_id": "STEMI-DO-007-EOC-03", "evidence_type": "result", "time_reference": "Entro 60 minuti dal prelievo ematico.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-STEMI-007-05", "DE-STEMI-007-06", "DE-STEMI-007-07"]}, {"description": "Presenza del timestamp di refertazione che conferma il rispetto del vincolo temporale di 60 minuti dal prelievo.", "evidence_id": "STEMI-DO-007-EOC-04", "evidence_type": "timestamp", "time_reference": "Differenza tra timestamp refertazione e timestamp prelievo â‰¤ 60 minuti.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-STEMI-007-05", "DE-STEMI-007-06"]}], "required_data_elements": [{"name": "Motivo di accesso al pronto soccorso", "data_type": "coded concept", "query_hint": "Ricercare nei campi di triage il motivo di accesso con codici correlati a dolore toracico (R07.x) o infarto miocardico (I21.x).", "description": "Motivo principale di presentazione del paziente, incluso il sintomo guida (es. dolore toracico).", "coding_system": "ICD-10-CM", "data_element_id": "DE-STEMI-007-01", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Sospetto clinico di sindrome coronarica acuta", "data_type": "boolean", "query_hint": "Ricercare nelle note di triage e nella valutazione medica iniziale riferimenti a sospetto SCA, STEMI, infarto miocardico.", "description": "Valutazione clinica iniziale che documenta il sospetto di SCA o STEMI.", "coding_system": null, "data_element_id": "DE-STEMI-007-02", "source_location": "ehr_unstructured", "extraction_method": "inferential", "required_for_evaluation": true}, {"name": "Risultato ECG a 12 derivazioni", "data_type": "coded concept", "query_hint": "Ricercare nel referto ECG la presenza di sopraslivellamento ST, blocco di branca sinistra di nuova insorgenza, o equivalenti STEMI.", "description": "Referto dell''ECG con indicazione di sopraslivellamento del tratto ST o equivalenti STEMI.", "coding_system": "SNOMED CT", "data_element_id": "DE-STEMI-007-03", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "Timestamp di presentazione del paziente", "data_type": "datetime", "query_hint": "Campo datetime del sistema di triage o del registro accessi di pronto soccorso.", "description": "Data e ora di registrazione del paziente al triage o al pronto soccorso.", "coding_system": null, "data_element_id": "DE-STEMI-007-04", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Timestamp del prelievo ematico per troponina", "data_type": "datetime", "query_hint": "Ricercare il timestamp di raccolta campione associato all''ordine di troponina nel sistema di laboratorio (LIS) o nell''ordine infermieristico.", "description": "Data e ora di esecuzione del prelievo ematico per il dosaggio della troponina cardiaca.", "coding_system": null, "data_element_id": "DE-STEMI-007-05", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Timestamp di refertazione del risultato della troponina", "data_type": "datetime", "query_hint": "Ricercare il timestamp di validazione/refertazione del risultato nel LIS o il timestamp di ricezione nel sistema di cartella clinica elettronica.", "description": "Data e ora in cui il risultato del dosaggio della troponina hs Ã¨ stato reso disponibile nel sistema informativo clinico.", "coding_system": null, "data_element_id": "DE-STEMI-007-06", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Valore della troponina cardiaca ad alta sensibilitÃ ", "data_type": "numeric", "query_hint": "Ricercare i codici LOINC per hs-cTnI (89579-7) o hs-cTnT (67151-1) nel risultato di laboratorio.", "description": "Valore numerico del risultato del dosaggio della troponina cardiaca (hs-cTnI o hs-cTnT).", "coding_system": "LOINC", "data_element_id": "DE-STEMI-007-07", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Diagnosi alternativa confermata", "data_type": "coded concept", "query_hint": "Ricercare diagnosi confermate non cardiache registrate nel sistema al momento del triage o della prima valutazione.", "description": "Eventuale diagnosi alternativa non cardiaca confermata che esclude la necessitÃ  del dosaggio della troponina nel contesto STEMI.", "coding_system": "ICD-10-CM", "data_element_id": "DE-STEMI-007-08", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": false}], "recommendation_strength": "Classe I", "associated_weak_signal_ids": ["STEMI-WS-007-01", "STEMI-WS-007-02", "STEMI-WS-007-03"], "documentation_requirements": {"mandatory_fields": ["timestamp_presentazione_paziente", "timestamp_prelievo_ematico_troponina", "timestamp_refertazione_troponina", "valore_troponina_hs", "metodo_analitico_troponina", "unitÃ _di_misura_troponina"], "free_text_allowed": true, "justification_fields": ["nota_clinica_di_deviazione", "motivo_di_ritardo_refertazione", "motivo_di_utilizzo_metodo_non_hs"], "acceptable_evidence_sources": ["sistema informativo di laboratorio (LIS)", "cartella clinica elettronica", "sistema di gestione ordini", "registro infermieristico di pronto soccorso", "sistema di triage"], "justification_required_when_deviating": true}, "evidence_of_non_compliance": [{"description": "Assenza di ordine per dosaggio della troponina cardiaca ad alta sensibilitÃ  in un paziente con sospetto STEMI.", "evidence_id": "STEMI-DO-007-EONC-01", "evidence_type": "absence_of_event", "time_reference": "Nessun ordine registrato entro 30 minuti dalla presentazione.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-STEMI-007-04", "DE-STEMI-007-05"]}, {"description": "Risultato della troponina non disponibile entro 60 minuti dal prelievo ematico, indicando un ritardo nel processo di refertazione.", "evidence_id": "STEMI-DO-007-EONC-02", "evidence_type": "timestamp", "time_reference": "Differenza tra timestamp refertazione e timestamp prelievo > 60 minuti.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-STEMI-007-05", "DE-STEMI-007-06"]}, {"description": "Utilizzo di un metodo non ad alta sensibilitÃ  per il dosaggio della troponina senza documentazione di giustificazione.", "evidence_id": "STEMI-DO-007-EONC-03", "evidence_type": "derived_fact", "time_reference": "Al momento della refertazione del risultato.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-STEMI-007-07"]}, {"description": "Ritardo significativo tra la presentazione del paziente e l''esecuzione del prelievo ematico (superiore a 15 minuti).", "evidence_id": "STEMI-DO-007-EONC-04", "evidence_type": "timestamp", "time_reference": "Differenza tra timestamp prelievo e timestamp presentazione > 15 minuti.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-STEMI-007-04", "DE-STEMI-007-05"]}]}');
INSERT INTO riskm_manager_model_evaluation.rule_definition OVERRIDING SYSTEM VALUE VALUES (8, 1, 'STEMI-DO-008', '{"title": "Utilizzo dell''approccio algoritmico ESC con dosaggi seriati di troponina cardiaca ad alta sensibilitÃ  (hs-cTn) per confermare o escludere NSTEMI", "intent": "Garantire una stratificazione diagnostica rapida e accurata dei pazienti con sospetta sindrome coronarica acuta senza sopraslivellamento del tratto ST, utilizzando un algoritmo validato basato su dosaggi seriati di hs-cTn per confermare o escludere NSTEMI.", "rule_id": "STEMI-DO-008", "trigger": {"anchor_event": "primo_contatto_medico_PS", "trigger_type": "documented_symptom", "inference_allowed": true, "trigger_description": "Presentazione in pronto soccorso di un paziente con sintomatologia suggestiva di sindrome coronarica acuta e assenza di sopraslivellamento persistente del tratto ST all''ECG iniziale, con necessitÃ  di differenziazione diagnostica NSTEMI vs altre cause.", "end_of_applicability": "Fino al completamento dell''algoritmo diagnostico hs-cTn con conferma o esclusione di NSTEMI, oppure fino a eventuale riclassificazione come STEMI.", "trigger_data_elements": ["DE-008-01", "DE-008-02"], "start_of_applicability": "Dal momento della presentazione in pronto soccorso con sospetto clinico di SCA e ECG non diagnostico per STEMI."}, "rationale": "L''algoritmo ESC basato su dosaggi seriati di hs-cTn a 0h/1h o 0h/2h consente un rapido rule-in e rule-out dell''NSTEMI con elevata accuratezza diagnostica (VPN >99%), riducendo i tempi di permanenza in pronto soccorso, migliorando l''allocazione delle risorse e garantendo un trattamento tempestivo nei pazienti con infarto miocardico confermato.", "rule_type": "do", "exceptions": [{"label": "Presentazione molto tardiva (>72 ore dall''esordio dei sintomi)", "description": "In caso di presentazione molto tardiva con esordio dei sintomi oltre 72 ore prima, la troponina potrebbe essere in fase discendente e l''algoritmo 0h/1h-2h potrebbe non essere affidabile; in tal caso si richiede valutazione clinica individuale.", "exception_id": "EX-008-01", "condition_logic": "symptom_onset_to_presentation > 72 hours", "required_evidence": ["Documentazione del tempo stimato dall''esordio dei sintomi", "Nota clinica con giustificazione della variazione dell''approccio diagnostico"], "required_justification": true}, {"label": "Insufficienza renale terminale con troponina cronicamente elevata", "description": "Nei pazienti con insufficienza renale cronica terminale (eGFR <15 ml/min o in dialisi), i livelli basali di hs-cTn possono essere cronicamente elevati, richiedendo soglie e interpretazioni differenti o l''uso di delta assoluti specifici.", "exception_id": "EX-008-02", "condition_logic": "eGFR < 15 OR dialysis_status == true", "required_evidence": ["Valore di eGFR o stato di dialisi documentato", "Valori basali noti di hs-cTn se disponibili", "Nota clinica con motivazione dell''approccio diagnostico alternativo"], "required_justification": true}, {"label": "Test hs-cTn non disponibile", "description": "In caso di indisponibilitÃ  temporanea del dosaggio ad alta sensibilitÃ  della troponina, si puÃ² ricorrere ad un dosaggio convenzionale con protocollo standard (0h/3h-6h) o trasferimento del paziente verso struttura dotata di hs-cTn.", "exception_id": "EX-008-03", "condition_logic": "hs_cTn_assay_available == false", "required_evidence": ["Documentazione dell''indisponibilitÃ  del test hs-cTn", "Nota clinica indicante il protocollo alternativo adottato"], "required_justification": true}], "short_label": "Algoritmo ESC hs-cTn 0h/1h o 0h/2h", "applicability": {"care_context": "Fase diagnostica iniziale presso il pronto soccorso o l''unitÃ  di dolore toracico.", "clinical_context": "Sospetta sindrome coronarica acuta (SCA) senza sopraslivellamento persistente del tratto ST, nell''ambito del percorso diagnostico differenziale STEMI/NSTEMI.", "exclusion_criteria": [{"label": "STEMI conclamato all''ECG", "description": "Paziente con sopraslivellamento persistente del tratto ST diagnostico di STEMI che richiede riperfusione immediata (percorso STEMI diretto).", "criterion_id": "EC-008-01", "data_elements": ["DE-008-02"], "logic_expression": "ecg_finding == ''STEMI_persistente''", "inference_allowed": false}, {"label": "Arresto cardiaco in corso con instabilitÃ  emodinamica severa", "description": "Pazienti in arresto cardiaco refrattario o con instabilitÃ  emodinamica critica che preclude l''attesa dei risultati seriati di troponina.", "criterion_id": "EC-008-02", "data_elements": ["DE-008-04"], "logic_expression": "hemodynamic_status == ''arresto_cardiaco_refrattario'' OR hemodynamic_status == ''shock_cardiogeno_severo''", "inference_allowed": true}], "inclusion_criteria": [{"label": "Dolore toracico suggestivo di SCA", "description": "Paziente con dolore toracico acuto o equivalente ischemico sospetto per sindrome coronarica acuta.", "criterion_id": "IC-008-01", "data_elements": ["DE-008-01"], "logic_expression": "presenting_complaint IN (''dolore toracico'', ''dispnea acuta'', ''sincope'', ''equivalente ischemico'')", "inference_allowed": true}, {"label": "ECG senza sopraslivellamento persistente ST", "description": "ECG al primo contatto che non mostra un sopraslivellamento persistente del tratto ST (esclusione di STEMI evidente).", "criterion_id": "IC-008-02", "data_elements": ["DE-008-02"], "logic_expression": "ecg_finding != ''STEMI_persistente''", "inference_allowed": true}, {"label": "DisponibilitÃ  del dosaggio hs-cTn", "description": "Il laboratorio o il sistema point-of-care deve disporre di un test di troponina cardiaca ad alta sensibilitÃ  validato.", "criterion_id": "IC-008-03", "data_elements": ["DE-008-03"], "logic_expression": "hs_cTn_assay_available == true", "inference_allowed": false}], "population_description": "Pazienti adulti che si presentano in pronto soccorso con sospetta sindrome coronarica acuta, in particolare quelli senza sopraslivellamento persistente del tratto ST all''ECG, in cui Ã¨ necessario confermare o escludere un NSTEMI."}, "care_settings": ["pronto soccorso", "dipartimento di emergenza-urgenza", "unitÃ  di dolore toracico"], "clinical_phase": "diagnosi", "evidence_level": "Livello di evidenza B", "schema_version": "1.0.0", "expected_action": {"action_verb": "eseguire", "action_target": "Dosaggio seriato di troponina cardiaca ad alta sensibilitÃ  (hs-cTn)", "action_parameters": [{"unit": "ora", "mandatory": true, "expected_value": "1", "parameter_name": "Protocollo temporale primario", "comparison_operator": "equals", "parameter_description": "Intervallo temporale tra il primo e il secondo dosaggio di hs-cTn secondo il protocollo ESC raccomandato."}, {"unit": "ore", "mandatory": false, "expected_value": "2", "parameter_name": "Protocollo temporale alternativo", "comparison_operator": "equals", "parameter_description": "Intervallo temporale alternativo tra il primo e il secondo dosaggio di hs-cTn quando il protocollo a 1 ora non Ã¨ utilizzabile."}, {"unit": null, "mandatory": true, "expected_value": "alta sensibilitÃ  (hs-cTn)", "parameter_name": "Tipo di dosaggio", "comparison_operator": "equals", "parameter_description": "Il dosaggio della troponina deve essere eseguito con un test ad alta sensibilitÃ  (hs-cTn, troponina T o I ad alta sensibilitÃ ) validato."}, {"unit": "prelievi", "mandatory": true, "expected_value": "2", "parameter_name": "Numero minimo di prelievi", "comparison_operator": "greater_than", "parameter_description": "Numero minimo di prelievi seriati richiesti per l''applicazione dell''algoritmo ESC (tempo 0 + almeno un prelievo successivo)."}, {"unit": null, "mandatory": true, "expected_value": "Algoritmo ESC 0h/1h o 0h/2h applicato", "parameter_name": "Applicazione algoritmo ESC di rule-in/rule-out", "comparison_operator": "equals", "parameter_description": "I risultati dei dosaggi seriati devono essere interpretati secondo le soglie e i delta previsti dall''algoritmo ESC specifico per il test hs-cTn utilizzato (rule-in, rule-out, zona grigia/osservazione)."}], "action_description": "Eseguire dosaggi seriati di troponina cardiaca ad alta sensibilitÃ  (hs-cTn) secondo l''approccio algoritmico ESC con protocollo 0h/1h o, in alternativa, 0h/2h, al fine di confermare (rule-in) o escludere (rule-out) la diagnosi di NSTEMI nei pazienti con sospetta sindrome coronarica acuta.", "alternative_compliant_actions": ["Utilizzo del protocollo ESC 0h/2h in alternativa al protocollo 0h/1h quando quest''ultimo non Ã¨ disponibile per il test hs-cTn utilizzato", "In caso di zona grigia (observe zone), esecuzione di un ulteriore dosaggio di hs-cTn a 3 ore dal primo prelievo con rivalutazione clinica"]}, "deontic_strength": "recommended", "evaluation_logic": {"notes": "L''intervallo accettabile tra i due prelievi include una tolleranza operativa di Â±10 minuti rispetto ai tempi nominali (1h o 2h). Le soglie specifiche di rule-in/rule-out variano in base al tipo di test hs-cTn utilizzato (es. hs-cTnT Roche, hs-cTnI Abbott) e devono essere configurate localmente.", "ambiguity_policy": "review_required", "formal_expression": "IF (sospetta_SCA == true AND ecg_STEMI == false) THEN { ASSERT count(hs_cTn_results) >= 2; LET t0 = timestamp(hs_cTn_prelievo_0); LET t1 = timestamp(hs_cTn_prelievo_seriato); LET intervallo = t1 - t0; ASSERT (intervallo BETWEEN 50min AND 70min) OR (intervallo BETWEEN 110min AND 130min); LET delta = abs(hs_cTn_seriato - hs_cTn_basale); ASSERT esito_algoritmo_ESC IN (''rule_in'', ''rule_out'', ''observe''); ASSERT documentazione_esito_presente == true; RETURN ''compliant''; } ELSE IF (eccezione_documentata == true) THEN RETURN ''justified_deviation''; ELSE RETURN ''non_compliant'';", "missing_data_policy": "not_evaluable", "natural_language_test": "Verificare che per il paziente con sospetta SCA senza STEMI siano stati eseguiti almeno due dosaggi di troponina cardiaca ad alta sensibilitÃ  (hs-cTn) con un intervallo conforme al protocollo ESC (circa 1 ora o circa 2 ore), che i risultati siano stati interpretati secondo l''algoritmo ESC con calcolo del delta assoluto e che la classificazione diagnostica risultante (rule-in, rule-out o osservazione) sia stata documentata in cartella clinica.", "conflict_resolution_policy": "human_review", "formal_expression_language": "pseudocode"}, "time_constraints": [{"description": "Il primo prelievo ematico per il dosaggio di hs-cTn (tempo 0) deve essere effettuato il prima possibile dopo il primo contatto medico in pronto soccorso.", "anchor_event": "primo_contatto_medico_PS", "constraint_id": "TC-008-01", "duration_unit": "minuti", "hard_deadline": false, "duration_value": 10, "relation_to_anchor": "immediate", "alert_threshold_unit": null, "alert_threshold_value": null}, {"description": "Il secondo prelievo ematico per hs-cTn deve essere eseguito a 1 ora dal primo prelievo nel protocollo 0h/1h.", "anchor_event": "prelievo_hs_cTn_tempo_0", "constraint_id": "TC-008-02", "duration_unit": "ora", "hard_deadline": true, "duration_value": 1, "relation_to_anchor": "after", "alert_threshold_unit": "minuti", "alert_threshold_value": 50}, {"description": "In alternativa, il secondo prelievo ematico per hs-cTn deve essere eseguito a 2 ore dal primo prelievo nel protocollo 0h/2h.", "anchor_event": "prelievo_hs_cTn_tempo_0", "constraint_id": "TC-008-03", "duration_unit": "ore", "hard_deadline": true, "duration_value": 2, "relation_to_anchor": "after", "alert_threshold_unit": "minuti", "alert_threshold_value": 100}, {"description": "I risultati del dosaggio di hs-cTn devono essere disponibili entro 60 minuti dal prelievo (turn-around time laboratorio).", "anchor_event": "prelievo_hs_cTn", "constraint_id": "TC-008-04", "duration_unit": "minuti", "hard_deadline": false, "duration_value": 60, "relation_to_anchor": "within", "alert_threshold_unit": "minuti", "alert_threshold_value": 45}], "evaluation_method": {"notes": "La valutazione primaria Ã¨ deterministica basata sui dati strutturati di laboratorio (valori hs-cTn e timestamp). In caso di dati incompleti, si ricorre all''estrazione inferenziale dalle note cliniche per verificare la documentazione dell''interpretazione algoritmica.", "primary_method": "hybrid", "minimum_confidence": 0.85, "human_review_required": false, "allowed_inference_sources": ["referti di laboratorio strutturati", "note cliniche del pronto soccorso", "ordini di laboratorio nel sistema informatico ospedaliero", "lettera di dimissione dal pronto soccorso"]}, "possible_outcomes": ["compliant", "non_compliant", "justified_deviation", "not_applicable", "not_evaluable", "probable_non_compliance"], "source_references": [{"issuer": "European Society of Cardiology (ESC)", "source_id": "ESC-ACS-2023", "citation_uri": "https://doi.org/10.1093/eurheartj/ehad191", "license_note": "Contenuto soggetto a copyright ESC. Uso a fini clinici e di qualitÃ  interna.", "source_level": "international", "document_title": "2023 ESC Guidelines for the management of acute coronary syndromes", "page_reference": null, "statement_quote": "It is recommended to use an ESC algorithmic approach with serial hs-cTn measurements (0 h/1 h or 0 h/2 h) to rule in and rule out NSTEMI.", "document_version": "2023", "publication_date": "2023-08-25", "section_reference": "Sezione 3.3 â€“ Diagnosi biochimica: troponina cardiaca ad alta sensibilitÃ "}], "original_statement": "It is recommended to use an ESC algorithmic approach with serial hs-cTn measurements (0 h/1 h or 0 h/2 h) to rule in and rule out NSTEMI.", "responsible_actors": [{"notes": "Responsabile della richiesta e interpretazione dei dosaggi seriati di hs-cTn secondo l''algoritmo ESC.", "role_name": "Medico d''urgenza", "organization_unit": "Pronto Soccorso / Dipartimento di Emergenza-Urgenza", "responsibility_type": "primary"}, {"notes": "Consulente per interpretazione di risultati ambigui o per conferma diagnostica di NSTEMI.", "role_name": "Cardiologo", "organization_unit": "Cardiologia / UnitÃ  di Terapia Intensiva Coronarica", "responsibility_type": "consulted"}, {"notes": "Supporta il prelievo ematico al tempo 0 e garantisce il prelievo seriato nei tempi previsti dall''algoritmo.", "role_name": "Infermiere di triage", "organization_unit": "Pronto Soccorso", "responsibility_type": "supporting"}, {"notes": "Responsabile dell''esecuzione del dosaggio hs-cTn con tempi di refertazione rapidi (turn-around time â‰¤ 60 minuti).", "role_name": "Laboratorio analisi", "organization_unit": "Laboratorio centralizzato / Point-of-care", "responsibility_type": "supporting"}], "clinical_pathway_id": "PDTA-STEMI-001", "completion_criteria": {"description": "L''azione Ã¨ considerata completata quando sono stati eseguiti almeno due dosaggi seriati di hs-cTn secondo i tempi previsti dall''algoritmo ESC (0h e 1h o 0h e 2h), i risultati sono stati interpretati secondo le soglie algoritmiche ESC e la decisione clinica di rule-in, rule-out o osservazione Ã¨ stata documentata.", "success_condition": "Due dosaggi di hs-cTn eseguiti nei tempi previsti (0h e 1h oppure 0h e 2h) AND risultati interpretati secondo algoritmo ESC AND decisione documentata di rule-in, rule-out o prosecuzione dell''osservazione.", "minimum_occurrences": 1, "required_event_types": ["prelievo_hs_cTn_tempo_0", "prelievo_hs_cTn_tempo_1h_o_2h", "referto_laboratorio_hs_cTn", "interpretazione_algoritmo_ESC"], "required_documentation_elements": ["Valore di hs-cTn al tempo 0 con timestamp del prelievo", "Valore di hs-cTn al tempo 1h o 2h con timestamp del prelievo", "Delta assoluto di hs-cTn calcolato", "Classificazione algoritmata: rule-in, rule-out o zona di osservazione", "Decisione clinica conseguente documentata in cartella"]}, "extraction_metadata": {"validated_at": null, "validated_by": null, "ambiguity_flags": ["La raccomandazione si riferisce a NSTEMI ma Ã¨ inserita nel percorso STEMI: verificare se il contesto clinico previsto Ã¨ solo la diagnosi differenziale o include anche il monitoraggio post-STEMI.", "Le soglie specifiche di rule-in/rule-out dipendono dal tipo di test hs-cTn utilizzato e devono essere configurate localmente.", "Il livello di evidenza non Ã¨ esplicitamente indicato nel testo sorgente; Ã¨ stato assegnato Livello B come plausibile sulla base delle linee guida ESC 2023."], "generation_mode": "llm_inference", "extraction_confidence": 0.92, "human_validation_status": "not_reviewed", "source_interpretation_notes": "La raccomandazione originale Ã¨ riferita specificamente all''NSTEMI ma Ã¨ inserita nel contesto del percorso STEMI poichÃ© la diagnosi differenziale STEMI/NSTEMI Ã¨ parte integrante del pathway. Il testo originale Ã¨ in inglese e utilizza ''is recommended'' che corrisponde a Classe I ESC. I protocolli 0h/1h e 0h/2h sono presentati come alternative equivalenti."}, "governance_metadata": {"version": "1.0.0", "rule_owner": "Direttore del Dipartimento di Emergenza-Urgenza", "approved_by": null, "effective_to": null, "review_cycle": "12 mesi", "authoring_body": "Team Clinical Pathway STEMI - QualitÃ  e Sicurezza delle Cure", "effective_from": null, "last_reviewed_at": null, "lifecycle_status": "draft"}, "risk_classification": {"rationale": "Il mancato utilizzo dell''algoritmo ESC con dosaggi seriati di hs-cTn puÃ² portare a una diagnosi errata o ritardata di NSTEMI, con conseguente ritardo nel trattamento antitrombotico e nella strategia invasiva, aumentando il rischio di eventi cardiovascolari avversi maggiori (MACE). La violazione Ã¨ facilmente rilevabile tramite i dati strutturati di laboratorio.", "detectability": "easy", "priority_score": 8.5, "process_risk_severity": "high", "clinical_risk_severity": "high", "likelihood_if_violated": "possible"}, "normalized_statement": "Si raccomanda di utilizzare l''approccio algoritmico ESC con dosaggi seriati di troponina cardiaca ad alta sensibilitÃ  (hs-cTn) a 0h/1h oppure 0h/2h per confermare o escludere la diagnosi di NSTEMI.", "sequence_constraints": [{"description": "L''ECG a 12 derivazioni deve essere eseguito prima o contestualmente al primo prelievo di hs-cTn per escludere STEMI.", "allowed_order": "predecessor_first", "constraint_id": "SC-008-01", "successor_event": "prelievo_hs_cTn_tempo_0", "predecessor_event": "esecuzione_ECG_12_derivazioni", "violation_condition": "Il primo prelievo di hs-cTn viene eseguito senza un ECG precedente o concomitante che escluda STEMI."}, {"description": "Il prelievo di hs-cTn al tempo 0 deve precedere il prelievo seriato al tempo 1h o 2h.", "allowed_order": "predecessor_first", "constraint_id": "SC-008-02", "successor_event": "prelievo_hs_cTn_tempo_1h_o_2h", "predecessor_event": "prelievo_hs_cTn_tempo_0", "violation_condition": "Il prelievo seriato viene eseguito prima del prelievo basale o senza il prelievo basale documentato."}, {"description": "L''interpretazione dell''algoritmo ESC deve avvenire dopo la disponibilitÃ  dei risultati di entrambi i dosaggi seriati.", "allowed_order": "predecessor_first", "constraint_id": "SC-008-03", "successor_event": "interpretazione_algoritmo_ESC", "predecessor_event": "referto_hs_cTn_seriato_completo", "violation_condition": "La decisione diagnostica viene presa senza attendere i risultati completi dei dosaggi seriati."}], "clinical_pathway_name": "Percorso Diagnostico Terapeutico Assistenziale per STEMI", "evidence_of_compliance": [{"description": "Presenza nel sistema informativo di laboratorio di almeno due risultati di hs-cTn con timestamp compatibili con il protocollo 0h/1h o 0h/2h.", "evidence_id": "EOC-008-01", "evidence_type": "result", "time_reference": "Entro 3 ore dal primo contatto medico in pronto soccorso", "minimum_occurrences": 2, "derived_from_data_elements": ["DE-008-05", "DE-008-06", "DE-008-07", "DE-008-08"]}, {"description": "Documentazione clinica della classificazione algoritmica ESC (rule-in, rule-out o zona di osservazione) con riferimento ai valori e al delta di hs-cTn.", "evidence_id": "EOC-008-02", "evidence_type": "documentation", "time_reference": "Dopo la disponibilitÃ  del secondo dosaggio di hs-cTn", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-008-09", "DE-008-10"]}, {"description": "Ordine di laboratorio per dosaggio seriato di hs-cTn documentato nel sistema informatico ospedaliero.", "evidence_id": "EOC-008-03", "evidence_type": "order", "time_reference": "Entro 10 minuti dal primo contatto medico", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-008-05", "DE-008-07"]}], "required_data_elements": [{"name": "Sintomo di presentazione", "data_type": "coded concept", "query_hint": "Campo motivo di accesso / chief complaint nella scheda di triage.", "description": "Motivo di accesso al pronto soccorso (dolore toracico, dispnea, sincope o equivalente ischemico).", "coding_system": "ICD-10 / codifica locale di triage", "data_element_id": "DE-008-01", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Referto ECG 12 derivazioni", "data_type": "coded concept", "query_hint": "Referto ECG strutturato o interpretazione automatica del dispositivo ECG; verificare anche note cliniche se non strutturato.", "description": "Risultato dell''elettrocardiogramma a 12 derivazioni con indicazione della presenza o assenza di sopraslivellamento del tratto ST.", "coding_system": "Codifica locale ECG / SNOMED CT", "data_element_id": "DE-008-02", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "DisponibilitÃ  test hs-cTn", "data_type": "boolean", "query_hint": "Configurazione di sistema del catalogo analisi del laboratorio; verificare disponibilitÃ  del test hs-cTn.", "description": "Indicazione sulla disponibilitÃ  di un dosaggio di troponina cardiaca ad alta sensibilitÃ  nel laboratorio di riferimento.", "coding_system": null, "data_element_id": "DE-008-03", "source_location": "other", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Stato emodinamico del paziente", "data_type": "coded concept", "query_hint": "Parametri vitali, note di triage, documentazione medica d''urgenza.", "description": "Valutazione dello stato emodinamico (stabile, instabile, shock cardiogeno, arresto cardiaco).", "coding_system": "Codifica locale / SNOMED CT", "data_element_id": "DE-008-04", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "Valore hs-cTn al tempo 0", "data_type": "numeric", "query_hint": "Risultato di laboratorio per hs-cTnT (LOINC 67151-1) o hs-cTnI (LOINC 89579-7) con timestamp del prelievo.", "description": "Concentrazione di troponina cardiaca ad alta sensibilitÃ  misurata al momento del primo prelievo (baseline).", "coding_system": "LOINC", "data_element_id": "DE-008-05", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Valore hs-cTn al tempo 1h o 2h", "data_type": "numeric", "query_hint": "Risultato di laboratorio per hs-cTn seriata con timestamp del prelievo; calcolare intervallo dal primo prelievo.", "description": "Concentrazione di troponina cardiaca ad alta sensibilitÃ  misurata al secondo prelievo seriato (1 ora o 2 ore dopo il basale).", "coding_system": "LOINC", "data_element_id": "DE-008-06", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Timestamp prelievo hs-cTn tempo 0", "data_type": "datetime", "query_hint": "Timestamp associato all''ordine o all''esecuzione del prelievo ematico per troponina basale.", "description": "Data e ora del primo prelievo ematico per il dosaggio di hs-cTn.", "coding_system": null, "data_element_id": "DE-008-07", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Timestamp prelievo hs-cTn seriato", "data_type": "datetime", "query_hint": "Timestamp associato all''ordine o all''esecuzione del secondo prelievo ematico per troponina seriata.", "description": "Data e ora del secondo prelievo ematico per il dosaggio seriato di hs-cTn.", "coding_system": null, "data_element_id": "DE-008-08", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Delta assoluto hs-cTn", "data_type": "numeric", "query_hint": "Calcolare: |hs-cTn(1h o 2h) - hs-cTn(0h)|. Utilizzare le soglie specifiche del test hs-cTn impiegato.", "description": "Variazione assoluta della concentrazione di hs-cTn tra il primo e il secondo dosaggio, calcolata per l''applicazione dell''algoritmo ESC.", "coding_system": null, "data_element_id": "DE-008-09", "source_location": "derived", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Esito algoritmo ESC (rule-in / rule-out / observe)", "data_type": "coded concept", "query_hint": "Derivato dall''applicazione delle soglie algoritmiche ESC ai valori di hs-cTn basale e delta; verificare documentazione clinica.", "description": "Risultato dell''applicazione dell''algoritmo ESC: conferma (rule-in), esclusione (rule-out) o zona di osservazione.", "coding_system": "Codifica locale (rule_in, rule_out, observe)", "data_element_id": "DE-008-10", "source_location": "derived", "extraction_method": "hybrid", "required_for_evaluation": true}], "recommendation_strength": "Classe I", "associated_weak_signal_ids": ["WS-STEMI-008-01", "WS-STEMI-008-02", "WS-STEMI-008-03"], "documentation_requirements": {"mandatory_fields": ["Valore di hs-cTn al tempo 0 con timestamp", "Valore di hs-cTn al tempo 1h o 2h con timestamp", "Delta assoluto di hs-cTn", "Classificazione algoritmo ESC (rule-in / rule-out / observe)", "Decisione clinica conseguente (ricovero, dimissione, osservazione)"], "free_text_allowed": true, "justification_fields": ["Nota clinica di giustificazione nel diario medico di pronto soccorso", "Motivazione documentata per l''utilizzo di protocollo alternativo", "Documentazione dell''eccezione clinica applicabile"], "acceptable_evidence_sources": ["Sistema informativo di laboratorio (LIS)", "Cartella clinica elettronica del pronto soccorso", "Ordini di laboratorio nel sistema informatico ospedaliero", "Note cliniche strutturate o narrative del medico d''urgenza", "Lettera di dimissione dal pronto soccorso"], "justification_required_when_deviating": true}, "evidence_of_non_compliance": [{"description": "Assenza di dosaggio seriato di hs-cTn: un solo valore di troponina disponibile oppure nessun dosaggio eseguito per il paziente con sospetta SCA.", "evidence_id": "EONC-008-01", "evidence_type": "absence_of_event", "time_reference": "Entro 3 ore dal primo contatto medico in pronto soccorso", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-008-05", "DE-008-06"]}, {"description": "Intervallo tra i due prelievi di hs-cTn non conforme al protocollo ESC (significativamente diverso da 1 ora o 2 ore).", "evidence_id": "EONC-008-02", "evidence_type": "timestamp", "time_reference": "Intervallo tra primo e secondo prelievo", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-008-07", "DE-008-08"]}, {"description": "Utilizzo di un dosaggio di troponina convenzionale (non ad alta sensibilitÃ ) senza giustificazione documentata.", "evidence_id": "EONC-008-03", "evidence_type": "result", "time_reference": null, "minimum_occurrences": 1, "derived_from_data_elements": ["DE-008-03", "DE-008-05"]}, {"description": "Assenza di documentazione dell''interpretazione algoritmica ESC (rule-in/rule-out/observe) nonostante la disponibilitÃ  dei risultati di hs-cTn seriati.", "evidence_id": "EONC-008-04", "evidence_type": "documentation_gap", "time_reference": "Dopo la disponibilitÃ  del secondo risultato di hs-cTn", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-008-10"]}]}');
INSERT INTO riskm_manager_model_evaluation.rule_definition OVERRIDING SYSTEM VALUE VALUES (9, 1, 'STEMI-DO-009', '{"title": "Eseguire test aggiuntivo di hs-cTn dopo 3 ore in caso di risultati inconcludenti dell''algoritmo 0 h/1 h", "intent": "Garantire che i pazienti con sospetta sindrome coronarica acuta e risultati inconcludenti dell''algoritmo rapido 0 h/1 h di hs-cTn ricevano un ulteriore dosaggio a 3 ore per raggiungere una diagnosi definitiva, evitando dimissioni inappropriate o ritardi diagnostici.", "rule_id": "STEMI-DO-009", "trigger": {"anchor_event": "completamento_algoritmo_0h1h_inconcludente", "trigger_type": "result", "inference_allowed": false, "trigger_description": "Il risultato dell''algoritmo 0 h/1 h di hs-cTn Ã¨ classificato come inconcludente (zona grigia) dopo la valutazione delle prime due misurazioni, e non Ã¨ stata formulata alcuna diagnosi alternativa plausibile.", "end_of_applicability": "Fino all''esecuzione del dosaggio aggiuntivo di hs-cTn a 3 ore o fino alla formulazione di una diagnosi alternativa che spieghi il quadro clinico.", "trigger_data_elements": ["DE-algoritmo_0h1h_esito", "DE-hs_cTn_0h_valore", "DE-hs_cTn_1h_valore", "DE-diagnosi_alternativa"], "start_of_applicability": "Dal momento in cui l''esito dell''algoritmo 0 h/1 h viene classificato come inconcludente e si conferma l''assenza di diagnosi alternative."}, "rationale": "L''algoritmo 0 h/1 h di hs-cTn consente di escludere o confermare l''infarto miocardico nella maggior parte dei pazienti, ma una quota di casi rimane nella zona inconcludente. Il dosaggio aggiuntivo a 3 ore, in assenza di diagnosi alternative, aumenta la sensibilitÃ  diagnostica e permette di identificare pazienti con infarto miocardico a cinetica piÃ¹ lenta della troponina, riducendo il rischio di mancata diagnosi.", "rule_type": "do", "exceptions": [{"label": "Diagnosi alternativa sopravvenuta", "description": "Una diagnosi alternativa plausibile viene formulata e documentata tra il completamento dell''algoritmo 0 h/1 h e il tempo previsto per il dosaggio aggiuntivo a 3 ore, rendendo non necessario il prelievo aggiuntivo.", "exception_id": "STEMI-DO-009-EXP-01", "condition_logic": "diagnosi_alternativa_formulata == true AND tempo_diagnosi < tempo_prelievo_3h", "required_evidence": ["Documentazione della diagnosi alternativa nel referto clinico", "Esami o indagini a supporto della diagnosi alternativa"], "required_justification": true}, {"label": "InstabilitÃ  emodinamica con necessitÃ  di intervento urgente", "description": "Il paziente sviluppa instabilitÃ  emodinamica o deterioramento clinico acuto che richiede un intervento terapeutico immediato (es. coronarografia urgente, rianimazione), rendendo il dosaggio aggiuntivo di hs-cTn non prioritario.", "exception_id": "STEMI-DO-009-EXP-02", "condition_logic": "instabilita_emodinamica == true OR intervento_urgente_richiesto == true", "required_evidence": ["Documentazione di parametri vitali indicativi di instabilitÃ ", "Registrazione dell''intervento urgente e sua motivazione"], "required_justification": true}, {"label": "Dimissione volontaria del paziente", "description": "Il paziente rifiuta il completamento dell''iter diagnostico e richiede la dimissione volontaria, impedendo il prelievo a 3 ore.", "exception_id": "STEMI-DO-009-EXP-03", "condition_logic": "dimissione_volontaria == true AND consenso_informato_rifiuto_documentato == true", "required_evidence": ["Modulo di dimissione volontaria firmato dal paziente", "Documentazione dell''informazione fornita sui rischi"], "required_justification": true}], "short_label": "hs-cTn aggiuntiva a 3 h se inconcludente", "applicability": {"care_context": "Pronto soccorso o unitÃ  di dolore toracico durante la fase diagnostica iniziale.", "clinical_context": "Sospetta sindrome coronarica acuta (SCA) con risultati inconcludenti dell''algoritmo diagnostico rapido 0 h/1 h di hs-cTn, in assenza di una diagnosi alternativa definita.", "exclusion_criteria": [{"label": "Diagnosi alternativa confermata", "description": "Ãˆ stata identificata e confermata una diagnosi alternativa che spiega completamente il quadro clinico del paziente.", "criterion_id": "STEMI-DO-009-EXC-01", "data_elements": ["DE-diagnosi_alternativa", "DE-diagnosi_alternativa_confermata"], "logic_expression": "diagnosi_alternativa_formulata == true AND diagnosi_alternativa_confermata == true", "inference_allowed": true}, {"label": "Algoritmo 0 h/1 h giÃ  conclusivo", "description": "L''algoritmo 0 h/1 h ha giÃ  fornito un risultato conclusivo (rule-in o rule-out definitivo per infarto miocardico acuto).", "criterion_id": "STEMI-DO-009-EXC-02", "data_elements": ["DE-algoritmo_0h1h_esito"], "logic_expression": "algoritmo_0h1h_esito IN (''rule_in'', ''rule_out'')", "inference_allowed": false}, {"label": "STEMI evidente all''ECG", "description": "Il paziente presenta un sopraslivellamento del segmento ST diagnostico all''ECG che configura uno STEMI franco e richiede un percorso di riperfusione immediata senza necessitÃ  di ulteriori dosaggi di troponina.", "criterion_id": "STEMI-DO-009-EXC-03", "data_elements": ["DE-ECG_risultato"], "logic_expression": "ECG_STEMI == true", "inference_allowed": false}], "inclusion_criteria": [{"label": "Risultato inconcludente algoritmo 0 h/1 h", "description": "Le prime due misurazioni di hs-cTn eseguite secondo l''algoritmo 0 h/1 h non hanno consentito nÃ© di escludere nÃ© di confermare l''infarto miocardico acuto (risultato nella zona grigia/inconcludente).", "criterion_id": "STEMI-DO-009-INC-01", "data_elements": ["DE-hs_cTn_0h_valore", "DE-hs_cTn_1h_valore", "DE-algoritmo_0h1h_esito"], "logic_expression": "hs_cTn_0h_result == ''inconcludente'' AND hs_cTn_1h_result == ''inconcludente'' AND algoritmo_0h1h_esito == ''inconcludente''", "inference_allowed": false}, {"label": "Assenza di diagnosi alternativa", "description": "Non Ã¨ stata formulata alcuna diagnosi alternativa che possa spiegare adeguatamente il quadro clinico del paziente (ad esempio embolia polmonare, miocardite, dissecazione aortica, cause non cardiache).", "criterion_id": "STEMI-DO-009-INC-02", "data_elements": ["DE-diagnosi_alternativa"], "logic_expression": "diagnosi_alternativa_formulata == false", "inference_allowed": true}, {"label": "Sospetto clinico di SCA", "description": "Paziente con presentazione clinica compatibile con sindrome coronarica acuta (dolore toracico, dispnea, alterazioni ECG suggestive o anamnesi compatibile).", "criterion_id": "STEMI-DO-009-INC-03", "data_elements": ["DE-sospetto_SCA", "DE-sintomo_dolore_toracico"], "logic_expression": "sospetto_SCA == true", "inference_allowed": true}], "population_description": "Pazienti adulti che si presentano in pronto soccorso con sospetta sindrome coronarica acuta e dolore toracico, sottoposti all''algoritmo rapido 0 h/1 h di troponina cardiaca ad alta sensibilitÃ  (hs-cTn), i cui risultati sono risultati inconcludenti."}, "care_settings": ["pronto soccorso", "unitÃ  di dolore toracico", "medicina d''urgenza"], "clinical_phase": "diagnosi", "evidence_level": "B", "schema_version": "1.0.0", "expected_action": {"action_verb": "eseguire", "action_target": "Dosaggio hs-cTn (troponina cardiaca ad alta sensibilitÃ ) a 3 ore", "action_parameters": [{"unit": "ore", "mandatory": true, "expected_value": "3", "parameter_name": "tempo_prelievo", "comparison_operator": "equals", "parameter_description": "Tempo di esecuzione del prelievo aggiuntivo rispetto alla presentazione iniziale (tempo 0)."}, {"unit": null, "mandatory": true, "expected_value": "hs-cTn (troponina cardiaca ad alta sensibilitÃ )", "parameter_name": "analita", "comparison_operator": "equals", "parameter_description": "Tipo di biomarcatore da dosare nel prelievo aggiuntivo."}, {"unit": null, "mandatory": true, "expected_value": "sangue venoso", "parameter_name": "tipo_campione", "comparison_operator": "equals", "parameter_description": "Tipo di campione biologico richiesto per il dosaggio."}], "action_description": "Eseguire un dosaggio aggiuntivo di troponina cardiaca ad alta sensibilitÃ  (hs-cTn) mediante prelievo ematico a 3 ore dalla presentazione iniziale (tempo 0), in seguito a risultati inconcludenti dell''algoritmo 0 h/1 h e in assenza di diagnosi alternative.", "alternative_compliant_actions": ["Dosaggio hs-cTn a 3 ore con differente assay hs-cTn validato, se il medesimo assay non Ã¨ disponibile", "Dosaggio hs-cTn a 3 ore associato a rivalutazione clinica ed ECG come parte di un approccio integrato"]}, "deontic_strength": "recommended", "evaluation_logic": {"notes": "La classificazione dell''esito dell''algoritmo 0 h/1 h come inconcludente puÃ² dipendere dal kit diagnostico e dai cut-off locali. Ãˆ necessario verificare la coerenza tra i valori di hs-cTn e i soglie specifiche del saggio in uso. Il termine ''circa 3 ore'' ammette una tolleranza ragionevole di Â±30 minuti.", "ambiguity_policy": "review_required", "formal_expression": "IF algoritmo_0h1h_esito == ''inconcludente'' AND diagnosi_alternativa_formulata == false THEN IF EXISTS(hs_cTn_3h_valore) AND ABS(timestamp_prelievo_3h - timestamp_presentazione - 3h) <= 30min AND valutazione_clinica_3h_documentata == true THEN ''compliant'' ELSE IF EXISTS(diagnosi_alternativa_sopravvenuta) AND diagnosi_alternativa_sopravvenuta_documentata == true THEN ''justified_deviation'' ELSE IF hs_cTn_3h_valore IS NULL AND tempo_attuale - timestamp_presentazione > 4h THEN ''non_compliant'' ELSE ''not_evaluable'' END", "missing_data_policy": "review_required", "natural_language_test": "Verificare se, in un paziente con sospetta SCA il cui algoritmo 0 h/1 h di hs-cTn ha dato esito inconcludente e per il quale non Ã¨ stata formulata alcuna diagnosi alternativa, Ã¨ stato eseguito un dosaggio aggiuntivo di hs-cTn a circa 3 ore dalla presentazione iniziale, e se il risultato Ã¨ stato valutato clinicamente. Se il dosaggio Ã¨ presente con timestamp appropriato e la rivalutazione Ã¨ documentata, la regola Ã¨ conforme. Se il dosaggio Ã¨ assente oppure molto ritardato senza giustificazione, la regola Ã¨ non conforme.", "conflict_resolution_policy": "human_review", "formal_expression_language": "pseudocode"}, "time_constraints": [{"description": "Il prelievo aggiuntivo di hs-cTn deve essere eseguito a 3 ore dalla presentazione iniziale del paziente (tempo 0). Una tolleranza ragionevole di circa Â±30 minuti Ã¨ accettabile nella pratica clinica.", "anchor_event": "presentazione_iniziale_tempo_0", "constraint_id": "STEMI-DO-009-TC-01", "duration_unit": "ore", "hard_deadline": false, "duration_value": 3, "relation_to_anchor": "after", "alert_threshold_unit": "ore", "alert_threshold_value": 2.5}, {"description": "Il risultato del dosaggio a 3 ore deve essere disponibile al medico entro 60 minuti dall''esecuzione del prelievo per garantire una decisione tempestiva.", "anchor_event": "prelievo_ematico_3h", "constraint_id": "STEMI-DO-009-TC-02", "duration_unit": "minuti", "hard_deadline": false, "duration_value": 60, "relation_to_anchor": "within", "alert_threshold_unit": "minuti", "alert_threshold_value": 45}], "evaluation_method": {"notes": "L''assenza di diagnosi alternativa richiede spesso inferenza da note cliniche non strutturate. La classificazione dell''esito dell''algoritmo 0 h/1 h come inconcludente puÃ² non essere sempre codificata in modo strutturato e potrebbe richiedere derivazione dai valori numerici di hs-cTn rispetto ai cut-off del saggio locale.", "primary_method": "hybrid", "minimum_confidence": 0.85, "human_review_required": true, "allowed_inference_sources": ["note cliniche di pronto soccorso", "referti di laboratorio", "lettere di dimissione", "schede di triage", "ordini di laboratorio nel sistema informativo"]}, "possible_outcomes": ["compliant", "non_compliant", "justified_deviation", "not_applicable", "not_evaluable", "probable_non_compliance"], "source_references": [{"issuer": "European Society of Cardiology (ESC)", "source_id": "ESC-ACS-2023", "citation_uri": "https://doi.org/10.1093/eurheartj/ehad191", "license_note": "Contenuto utilizzato a fini di supporto decisionale clinico conformemente alle linee guida ESC.", "source_level": "international", "document_title": "2023 ESC Guidelines for the management of acute coronary syndromes", "page_reference": null, "statement_quote": "Additional testing after 3 h is recommended if the first two hs-cTn measurements of the 0 h/1 h algorithm are inconclusive and no alternative diagnoses explaining the condition have been made.", "document_version": "2023", "publication_date": "2023-08-25", "section_reference": "Sezione Diagnosi - Algoritmo 0 h/1 h hs-cTn, raccomandazione sui casi inconcludenti"}], "original_statement": "Additional testing after 3 h is recommended if the first two hs-cTn measurements of the 0 h/1 h algorithm are inconclusive and no alternative diagnoses explaining the condition have been made.", "responsible_actors": [{"notes": "Responsabile della decisione di richiedere il terzo dosaggio di hs-cTn dopo 3 ore e della rivalutazione clinica.", "role_name": "medico di pronto soccorso", "organization_unit": "Pronto Soccorso", "responsibility_type": "primary"}, {"notes": "Responsabile dell''esecuzione del prelievo ematico al tempo stabilito e dell''invio del campione al laboratorio.", "role_name": "infermiere di triage/pronto soccorso", "organization_unit": "Pronto Soccorso", "responsibility_type": "supporting"}, {"notes": "Responsabile dell''esecuzione e refertazione tempestiva del dosaggio hs-cTn.", "role_name": "laboratorista", "organization_unit": "Laboratorio Analisi Urgenti", "responsibility_type": "supporting"}, {"notes": "Consultato in caso di risultati persistentemente dubbi o peggioramento clinico.", "role_name": "cardiologo", "organization_unit": "Cardiologia", "responsibility_type": "consulted"}], "clinical_pathway_id": "PDTA-STEMI-001", "completion_criteria": {"description": "Il dosaggio aggiuntivo di hs-cTn Ã¨ considerato completato quando il prelievo ematico Ã¨ stato eseguito a circa 3 ore dalla presentazione, il campione Ã¨ stato analizzato dal laboratorio e il risultato Ã¨ stato refertato e reso disponibile al medico richiedente, che lo ha integrato nella valutazione diagnostica.", "success_condition": "risultato_hs_cTn_3h IS NOT NULL AND timestamp_prelievo_3h IS NOT NULL AND valutazione_clinica_3h_documentata == true", "minimum_occurrences": 1, "required_event_types": ["prelievo ematico a 3 ore", "refertazione risultato hs-cTn", "valutazione clinica del risultato"], "required_documentation_elements": ["Orario del prelievo ematico a 3 ore", "Valore numerico del dosaggio hs-cTn a 3 ore", "Interpretazione clinica del risultato nel contesto dell''algoritmo diagnostico"]}, "extraction_metadata": {"validated_at": null, "validated_by": null, "ambiguity_flags": ["I cut-off per definire l''esito ''inconcludente'' dell''algoritmo 0 h/1 h variano in base al tipo di saggio hs-cTn utilizzato (hs-cTnI vs hs-cTnT) e al produttore del kit diagnostico.", "Il testo non specifica una tolleranza temporale esatta per il prelievo a 3 ore; Ã¨ stata assunta una tolleranza di Â±30 minuti come ragionevole nella pratica clinica.", "La definizione di ''diagnosi alternativa'' Ã¨ ampia e richiede giudizio clinico per stabilire se una diagnosi sia sufficientemente plausibile da spiegare il quadro."], "generation_mode": "llm_inference", "extraction_confidence": 0.92, "human_validation_status": "not_reviewed", "source_interpretation_notes": "Il testo originale in inglese utilizza il termine ''recommended'' che Ã¨ stato mappato a forza deontica ''recommended''. L''algoritmo 0 h/1 h si riferisce al protocollo rapido ESC per il dosaggio seriale di hs-cTn con prelievi al tempo 0 e a 1 ora. Il termine ''inconclusive'' Ã¨ stato tradotto come ''inconcludente'' e si riferisce ai pazienti che non soddisfano i criteri di rule-in nÃ© di rule-out dopo le prime due misurazioni. La condizione ''no alternative diagnoses'' Ã¨ stata interpretata come assenza di qualsiasi diagnosi alternativa plausibile documentata."}, "governance_metadata": {"version": "1.0.0", "rule_owner": "Direttore UOC Cardiologia e Pronto Soccorso", "approved_by": null, "effective_to": null, "review_cycle": "12 mesi", "authoring_body": "Gruppo di Lavoro PDTA STEMI", "effective_from": null, "last_reviewed_at": null, "lifecycle_status": "draft"}, "risk_classification": {"rationale": "La mancata esecuzione del dosaggio aggiuntivo di hs-cTn a 3 ore in pazienti con risultato inconcludente dell''algoritmo 0 h/1 h puÃ² portare a dimissioni inappropriate di pazienti con infarto miocardico acuto non diagnosticato, con elevato rischio di eventi avversi maggiori (morte cardiaca improvvisa, scompenso cardiaco acuto, aritmie fatali). Il rischio clinico Ã¨ classificato come alto perchÃ© l''omissione diagnostica puÃ² avere conseguenze potenzialmente fatali.", "detectability": "moderate", "priority_score": 8.5, "process_risk_severity": "high", "clinical_risk_severity": "high", "likelihood_if_violated": "possible"}, "normalized_statement": "Si raccomanda l''esecuzione di un dosaggio aggiuntivo di troponina cardiaca ad alta sensibilitÃ  (hs-cTn) dopo 3 ore dalla presentazione quando le prime due misurazioni dell''algoritmo 0 h/1 h risultano inconcludenti e non Ã¨ stata formulata alcuna diagnosi alternativa che spieghi la condizione clinica.", "sequence_constraints": [{"description": "Le prime due misurazioni di hs-cTn dell''algoritmo 0 h/1 h devono essere state completate e classificate come inconcludenti prima dell''esecuzione del dosaggio aggiuntivo a 3 ore.", "allowed_order": "predecessor_first", "constraint_id": "STEMI-DO-009-SC-01", "successor_event": "prelievo_hs_cTn_3h", "predecessor_event": "completamento_algoritmo_0h1h_inconcludente", "violation_condition": "prelievo_hs_cTn_3h eseguito PRIMA del completamento e classificazione dell''algoritmo 0 h/1 h come inconcludente"}, {"description": "La rivalutazione clinica del paziente deve essere effettuata dopo la disponibilitÃ  del risultato del dosaggio aggiuntivo a 3 ore.", "allowed_order": "predecessor_first", "constraint_id": "STEMI-DO-009-SC-02", "successor_event": "rivalutazione_clinica_post_3h", "predecessor_event": "refertazione_hs_cTn_3h", "violation_condition": "rivalutazione_clinica_post_3h non effettuata OPPURE effettuata prima della disponibilitÃ  del referto hs-cTn a 3 ore"}], "clinical_pathway_name": "Percorso Diagnostico Terapeutico Assistenziale per STEMI", "evidence_of_compliance": [{"description": "Presenza di un risultato di laboratorio per hs-cTn con timestamp compatibile con 3 ore (Â±30 minuti) dalla presentazione iniziale, successivo a un esito inconcludente dell''algoritmo 0 h/1 h.", "evidence_id": "STEMI-DO-009-EOC-01", "evidence_type": "result", "time_reference": "Circa 3 ore dopo la presentazione iniziale (tempo 0), con tolleranza Â±30 minuti", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-hs_cTn_3h_valore", "DE-timestamp_prelievo_3h", "DE-timestamp_presentazione"]}, {"description": "Documentazione clinica della rivalutazione del paziente basata sul risultato del dosaggio aggiuntivo di hs-cTn a 3 ore, inclusa l''interpretazione diagnostica.", "evidence_id": "STEMI-DO-009-EOC-02", "evidence_type": "documentation", "time_reference": "Dopo la disponibilitÃ  del risultato hs-cTn a 3 ore", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-hs_cTn_3h_valore", "DE-algoritmo_0h1h_esito"]}, {"description": "Ordine di laboratorio per dosaggio hs-cTn a 3 ore presente nel sistema informativo, con motivazione clinica coerente.", "evidence_id": "STEMI-DO-009-EOC-03", "evidence_type": "order", "time_reference": "Tra il completamento dell''algoritmo 0 h/1 h inconcludente e le 3 ore dalla presentazione", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-hs_cTn_3h_valore", "DE-timestamp_prelievo_3h"]}], "required_data_elements": [{"name": "Valore hs-cTn al tempo 0", "data_type": "numeric", "query_hint": "Cercare risultato di laboratorio con codice LOINC per hs-cTn (es. 89579-7 per hs-cTnI o 67151-1 per hs-cTnT) con timestamp corrispondente al tempo 0.", "description": "Valore numerico del dosaggio di troponina cardiaca ad alta sensibilitÃ  al momento della presentazione iniziale (tempo 0).", "coding_system": "LOINC", "data_element_id": "DE-hs_cTn_0h_valore", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Valore hs-cTn a 1 ora", "data_type": "numeric", "query_hint": "Cercare risultato di laboratorio hs-cTn con timestamp circa 1 ora dopo il tempo 0.", "description": "Valore numerico del dosaggio di troponina cardiaca ad alta sensibilitÃ  a 1 ora dalla presentazione iniziale.", "coding_system": "LOINC", "data_element_id": "DE-hs_cTn_1h_valore", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Esito algoritmo 0 h/1 h", "data_type": "coded concept", "query_hint": "Verificare se esiste un campo strutturato per l''esito dell''algoritmo. In alternativa, derivare dai valori di hs-cTn 0h e 1h e dalla variazione assoluta secondo i cut-off del kit diagnostico in uso.", "description": "Classificazione dell''esito dell''algoritmo diagnostico rapido 0 h/1 h di hs-cTn: rule-in, rule-out o inconcludente.", "coding_system": null, "data_element_id": "DE-algoritmo_0h1h_esito", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "Diagnosi alternativa formulata", "data_type": "boolean", "query_hint": "Cercare diagnosi codificate in cartella clinica o note cliniche che documentino una diagnosi alternativa alla SCA (es. embolia polmonare, miocardite, scompenso cardiaco, cause muscoloscheletriche).", "description": "Indicatore della presenza di una diagnosi alternativa documentata che spieghi il quadro clinico, rendendo non necessario il dosaggio aggiuntivo.", "coding_system": "ICD-10", "data_element_id": "DE-diagnosi_alternativa", "source_location": "ehr_unstructured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "Valore hs-cTn a 3 ore", "data_type": "numeric", "query_hint": "Cercare risultato di laboratorio hs-cTn con timestamp circa 3 ore dopo il tempo 0.", "description": "Valore numerico del dosaggio aggiuntivo di troponina cardiaca ad alta sensibilitÃ  eseguito a 3 ore dalla presentazione iniziale.", "coding_system": "LOINC", "data_element_id": "DE-hs_cTn_3h_valore", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Timestamp presentazione iniziale (tempo 0)", "data_type": "datetime", "query_hint": "Utilizzare il timestamp di registrazione in triage o di primo accesso al pronto soccorso.", "description": "Data e ora della presentazione iniziale del paziente in pronto soccorso, utilizzata come riferimento temporale per l''algoritmo 0 h/1 h/3 h.", "coding_system": null, "data_element_id": "DE-timestamp_presentazione", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Timestamp prelievo ematico a 3 ore", "data_type": "datetime", "query_hint": "Cercare il timestamp di prelievo del campione associato al terzo dosaggio di hs-cTn.", "description": "Data e ora dell''esecuzione del prelievo ematico per il dosaggio aggiuntivo di hs-cTn a 3 ore.", "coding_system": null, "data_element_id": "DE-timestamp_prelievo_3h", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Sospetto clinico di SCA", "data_type": "boolean", "query_hint": "Cercare nelle note cliniche di accesso indicatori di sospetto SCA, dolore toracico acuto, o richiesta di dosaggio troponina con motivazione clinica compatibile.", "description": "Indicatore del sospetto clinico di sindrome coronarica acuta formulato dal medico al momento della valutazione iniziale.", "coding_system": null, "data_element_id": "DE-sospetto_SCA", "source_location": "ehr_unstructured", "extraction_method": "inferential", "required_for_evaluation": true}, {"name": "Dolore toracico", "data_type": "boolean", "query_hint": "Cercare codice ICD-10 R07.9 o equivalente, oppure nota clinica che riporti dolore toracico.", "description": "Presenza documentata di dolore toracico o equivalente anginoso come sintomo di presentazione.", "coding_system": "ICD-10", "data_element_id": "DE-sintomo_dolore_toracico", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": false}, {"name": "Risultato ECG", "data_type": "coded concept", "query_hint": "Cercare referto ECG e classificazione (STEMI, NSTEMI, alterazioni aspecifiche, normale).", "description": "Esito dell''elettrocardiogramma eseguito all''arrivo, in particolare la presenza o assenza di sopraslivellamento del tratto ST.", "coding_system": null, "data_element_id": "DE-ECG_risultato", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "Diagnosi alternativa confermata", "data_type": "boolean", "query_hint": "Verificare nelle note cliniche o referti diagnostici la conferma di una diagnosi alternativa alla SCA.", "description": "Indicatore che la diagnosi alternativa Ã¨ stata confermata mediante esami o indagini complementari.", "coding_system": null, "data_element_id": "DE-diagnosi_alternativa_confermata", "source_location": "ehr_unstructured", "extraction_method": "inferential", "required_for_evaluation": false}], "recommendation_strength": "Classe I", "associated_weak_signal_ids": ["STEMI-WS-009-01", "STEMI-WS-009-02"], "documentation_requirements": {"mandatory_fields": ["Valore hs-cTn al tempo 0", "Valore hs-cTn a 1 ora", "Esito algoritmo 0 h/1 h (rule-in, rule-out, inconcludente)", "Valore hs-cTn a 3 ore (se applicabile)", "Timestamp di ciascun prelievo", "Valutazione clinica del risultato a 3 ore", "Eventuale diagnosi alternativa formulata"], "free_text_allowed": true, "justification_fields": ["Nota clinica motivante la deviazione", "Diagnosi alternativa documentata con relativa evidenza", "Motivo del mancato prelievo a 3 ore", "Modulo di dimissione volontaria (se applicabile)"], "acceptable_evidence_sources": ["Sistema informativo di laboratorio (LIS)", "Cartella clinica elettronica di pronto soccorso", "Note cliniche strutturate e narrative", "Ordini di laboratorio", "Scheda di osservazione breve"], "justification_required_when_deviating": true}, "evidence_of_non_compliance": [{"description": "Assenza di un terzo dosaggio di hs-cTn entro 4 ore dalla presentazione iniziale, in un paziente con esito inconcludente dell''algoritmo 0 h/1 h e senza diagnosi alternativa documentata.", "evidence_id": "STEMI-DO-009-EONC-01", "evidence_type": "absence_of_event", "time_reference": "Entro 4 ore dalla presentazione iniziale (tempo 0)", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-hs_cTn_3h_valore", "DE-timestamp_presentazione", "DE-algoritmo_0h1h_esito", "DE-diagnosi_alternativa"]}, {"description": "Il paziente viene dimesso o trasferito dal pronto soccorso senza che sia stato eseguito il dosaggio aggiuntivo a 3 ore e senza una diagnosi alternativa documentata nÃ© una giustificazione clinica per la deviazione.", "evidence_id": "STEMI-DO-009-EONC-02", "evidence_type": "sequence", "time_reference": "Prima delle 3 ore dalla presentazione o senza dosaggio hs-cTn a 3 ore", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-hs_cTn_3h_valore", "DE-diagnosi_alternativa", "DE-algoritmo_0h1h_esito"]}, {"description": "Dosaggio aggiuntivo eseguito ma con ritardo significativo (oltre 4.5 ore dalla presentazione) senza giustificazione documentata.", "evidence_id": "STEMI-DO-009-EONC-03", "evidence_type": "timestamp", "time_reference": "Oltre 4.5 ore dalla presentazione iniziale", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-timestamp_prelievo_3h", "DE-timestamp_presentazione"]}]}');
INSERT INTO riskm_manager_model_evaluation.rule_definition OVERRIDING SYSTEM VALUE VALUES (10, 1, 'STEMI-DO-010', '{"title": "Ecocardiografia transtoracica (TTE) d''emergenza raccomandata nei pazienti con sospetta SCA che presentano shock cardiogeno o sospette complicanze meccaniche", "intent": "Garantire una rapida valutazione ecocardiografica per identificare cause trattabili di instabilitÃ  emodinamica e complicanze meccaniche potenzialmente letali nei pazienti con sospetta SCA.", "rule_id": "STEMI-DO-010", "trigger": {"anchor_event": "riconoscimento_shock_cardiogeno_o_complicanza_meccanica", "trigger_type": "diagnostic_finding", "inference_allowed": true, "trigger_description": "Identificazione di un paziente con sospetta SCA che presenta segni clinici di shock cardiogeno (ipotensione, ipoperfusione, necessitÃ  di supporto emodinamico) oppure segni sospetti di complicanze meccaniche post-infarto (soffio di nuova insorgenza, deterioramento emodinamico improvviso, sospetto tamponamento).", "end_of_applicability": "Fino al completamento della TTE d''emergenza con referto conclusivo o fino alla risoluzione dello stato clinico che ha generato il trigger.", "trigger_data_elements": ["DE-STEMI-010-04", "DE-STEMI-010-05", "DE-STEMI-010-06", "DE-STEMI-010-07", "DE-STEMI-010-08", "DE-STEMI-010-09"], "start_of_applicability": "Dal momento in cui viene identificato lo shock cardiogeno o la sospetta complicanza meccanica nel paziente con sospetta SCA."}, "rationale": "Lo shock cardiogeno e le complicanze meccaniche (rottura del setto interventricolare, rottura della parete libera, insufficienza mitralica acuta) sono condizioni ad alto rischio di mortalitÃ  che richiedono una diagnosi immediata per guidare la strategia terapeutica, chirurgica o interventistica. La TTE d''emergenza consente una valutazione rapida e non invasiva della funzione ventricolare, dell''integritÃ  strutturale cardiaca e della presenza di versamento pericardico o tamponamento.", "rule_type": "do", "exceptions": [{"label": "IndisponibilitÃ  apparecchiatura ecocardiografica", "description": "L''apparecchiatura ecocardiografica non Ã¨ disponibile o non funzionante nella sede in cui si trova il paziente, e il trasferimento immediato verso una sede dotata di ecografo Ã¨ giÃ  in corso.", "exception_id": "STEMI-DO-010-EXP-01", "condition_logic": "tte_equipment.available == false AND patient_transfer.in_progress == true", "required_evidence": ["Documentazione dell''indisponibilitÃ  dell''apparecchiatura", "Documentazione dell''attivazione del trasferimento verso centro con disponibilitÃ  ecocardiografica"], "required_justification": true}, {"label": "Paziente in arresto cardiaco con RCP in corso", "description": "Il paziente Ã¨ in arresto cardiaco e le manovre di rianimazione cardiopolmonare (RCP) sono in corso; la TTE puÃ² essere posticipata o eseguita con modalitÃ  point-of-care focalizzata durante le pause della RCP.", "exception_id": "STEMI-DO-010-EXP-02", "condition_logic": "cardiac_arrest == true AND cpr_in_progress == true", "required_evidence": ["Documentazione dello stato di arresto cardiaco", "Registrazione temporale delle manovre di RCP"], "required_justification": true}, {"label": "Trasferimento immediato in sala di emodinamica", "description": "Il paziente viene trasferito immediatamente in sala di emodinamica per coronarografia/PCI primaria e la TTE verrÃ  eseguita contestualmente o immediatamente dopo la procedura.", "exception_id": "STEMI-DO-010-EXP-03", "condition_logic": "cath_lab_transfer.immediate == true AND tte_planned_periprocedural == true", "required_evidence": ["Documentazione dell''attivazione della sala di emodinamica", "Piano documentato per esecuzione TTE peri-procedurale"], "required_justification": true}], "short_label": "TTE emergenza in shock cardiogeno / complicanze meccaniche", "applicability": {"care_context": "Fase acuta dell''emergenza: pronto soccorso, UTIC o qualsiasi setting di prima valutazione del paziente critico con sospetta SCA.", "clinical_context": "Sindrome coronarica acuta (SCA / STEMI) complicata da instabilitÃ  emodinamica (shock cardiogeno) o sospette complicanze meccaniche post-infarto.", "exclusion_criteria": [{"label": "Paziente giÃ  sottoposto a TTE d''emergenza recente", "description": "Il paziente Ã¨ giÃ  stato sottoposto a TTE d''emergenza durante lo stesso episodio clinico con risultati completi e conclusivi che hanno giÃ  guidato la decisione terapeutica.", "criterion_id": "STEMI-DO-010-EXC-01", "data_elements": ["DE-STEMI-010-10"], "logic_expression": "tte_emergency.completed_in_current_episode == true AND tte_results.conclusive == true", "inference_allowed": false}], "inclusion_criteria": [{"label": "Sospetta sindrome coronarica acuta", "description": "Il paziente presenta segni e/o sintomi clinici compatibili con una sindrome coronarica acuta (dolore toracico, alterazioni ECG, elevazione dei marcatori di necrosi miocardica).", "criterion_id": "STEMI-DO-010-INC-01", "data_elements": ["DE-STEMI-010-01", "DE-STEMI-010-02", "DE-STEMI-010-03"], "logic_expression": "diagnosis.suspected == ''SCA'' OR ecg.ste_elevation == true OR troponin.elevated == true", "inference_allowed": true}, {"label": "Shock cardiogeno", "description": "Il paziente presenta segni clinici di shock cardiogeno: ipotensione persistente (PAS < 90 mmHg), segni di ipoperfusione periferica, necessitÃ  di supporto con vasopressori/inotropi, o evidenza di congestione polmonare.", "criterion_id": "STEMI-DO-010-INC-02", "data_elements": ["DE-STEMI-010-04", "DE-STEMI-010-05", "DE-STEMI-010-06"], "logic_expression": "systolic_bp < 90 OR vasopressor_use == true OR signs_of_hypoperfusion == true", "inference_allowed": true}, {"label": "Sospette complicanze meccaniche", "description": "Il paziente presenta segni clinici sospetti di complicanze meccaniche post-infarto: soffio cardiaco di nuova insorgenza, deterioramento emodinamico improvviso, sospetto tamponamento cardiaco, sospetta rottura del setto interventricolare o della parete libera.", "criterion_id": "STEMI-DO-010-INC-03", "data_elements": ["DE-STEMI-010-07", "DE-STEMI-010-08", "DE-STEMI-010-09"], "logic_expression": "new_murmur == true OR sudden_hemodynamic_deterioration == true OR suspected_tamponade == true OR suspected_vsd == true OR suspected_free_wall_rupture == true", "inference_allowed": true}], "population_description": "Pazienti adulti con sospetta sindrome coronarica acuta (SCA), incluso STEMI, che presentano segni di shock cardiogeno o sospette complicanze meccaniche."}, "care_settings": ["pronto soccorso", "unitÃ  di terapia intensiva cardiologica", "sala di emodinamica", "unitÃ  coronarica"], "clinical_phase": "diagnosi", "evidence_level": "Livello di evidenza C", "schema_version": "1.0.0", "expected_action": {"action_verb": "eseguire", "action_target": "ecocardiogramma transtoracico (TTE) d''emergenza", "action_parameters": [{"unit": null, "mandatory": true, "expected_value": "transtoracica (TTE)", "parameter_name": "modalitÃ ", "comparison_operator": "equals", "parameter_description": "Tipo di ecocardiografia da eseguire."}, {"unit": null, "mandatory": true, "expected_value": "emergenza", "parameter_name": "urgenza", "comparison_operator": "equals", "parameter_description": "Livello di urgenza dell''esecuzione dell''esame."}, {"unit": null, "mandatory": true, "expected_value": "sÃ¬", "parameter_name": "valutazione_funzione_ventricolare", "comparison_operator": "equals", "parameter_description": "L''esame deve includere la valutazione della funzione sistolica ventricolare sinistra e destra."}, {"unit": null, "mandatory": true, "expected_value": "sÃ¬", "parameter_name": "ricerca_complicanze_meccaniche", "comparison_operator": "equals", "parameter_description": "L''esame deve includere la ricerca attiva di complicanze meccaniche: rottura del setto interventricolare, rottura della parete libera, insufficienza mitralica acuta, versamento pericardico/tamponamento."}], "action_description": "Eseguire un ecocardiogramma transtoracico (TTE) d''emergenza per valutare la funzione ventricolare sinistra e destra, identificare eventuali complicanze meccaniche (difetto del setto interventricolare, rottura della parete libera, insufficienza mitralica acuta, tamponamento cardiaco) e guidare la gestione emodinamica del paziente.", "alternative_compliant_actions": ["Ecocardiografia point-of-care (POCUS) focalizzata se la TTE completa non Ã¨ immediatamente eseguibile, seguita da TTE completa appena possibile", "Ecocardiografia transesofagea (TEE) d''emergenza se la finestra acustica transtoracica Ã¨ inadeguata"]}, "deontic_strength": "recommended", "evaluation_logic": {"notes": "La valutazione dello shock cardiogeno e delle complicanze meccaniche sospette puÃ² richiedere inferenza da testo libero (note cliniche, esame obiettivo). In caso di dati mancanti o ambigui Ã¨ necessaria la revisione umana. La tempistica dell''esame Ã¨ un indicatore di qualitÃ  ma il vincolo temporale non Ã¨ hard deadline dato che la raccomandazione indica l''urgenza senza specificare un intervallo cronometrico preciso.", "ambiguity_policy": "review_required", "formal_expression": "IF (suspected_acs == TRUE) AND (cardiogenic_shock == TRUE OR suspected_mechanical_complication == TRUE) THEN IF (tte_emergency_order EXISTS AND tte_emergency_report EXISTS AND tte_report.includes_biventricular_function AND tte_report.includes_mechanical_complication_screening) THEN status = ''compliant'' ELSE IF (documented_exception EXISTS) THEN status = ''justified_deviation'' ELSE status = ''non_compliant''", "missing_data_policy": "review_required", "natural_language_test": "Per un paziente con sospetta SCA che presenta shock cardiogeno o sospette complicanze meccaniche: verificare che sia stato emesso un ordine di TTE d''emergenza e che il relativo referto, completo di valutazione della funzione biventricolare e delle complicanze meccaniche, sia stato prodotto durante l''episodio di cura. In caso di assenza dell''esame o del referto, e in assenza di eccezione documentata, la regola risulta non conforme.", "conflict_resolution_policy": "human_review", "formal_expression_language": "pseudocode"}, "time_constraints": [{"description": "La TTE d''emergenza deve essere eseguita il prima possibile e comunque entro un breve intervallo temporale dal riconoscimento dello shock cardiogeno o della sospetta complicanza meccanica.", "anchor_event": "riconoscimento_shock_cardiogeno_o_complicanza_meccanica", "constraint_id": "STEMI-DO-010-TC-01", "duration_unit": "minuti", "hard_deadline": false, "duration_value": 30, "relation_to_anchor": "immediate", "alert_threshold_unit": "minuti", "alert_threshold_value": 15}], "evaluation_method": {"notes": "L''identificazione dello shock cardiogeno Ã¨ spesso deterministica (parametri vitali, farmaci vasoattivi), ma le complicanze meccaniche sospette richiedono frequentemente inferenza da testo libero. Il referto TTE Ã¨ generalmente strutturato ma puÃ² necessitare di NLP per estrarre i campi specifici relativi alle complicanze meccaniche.", "primary_method": "hybrid", "minimum_confidence": 0.85, "human_review_required": true, "allowed_inference_sources": ["note cliniche di pronto soccorso", "note cliniche UTIC", "referti ecocardiografici", "esame obiettivo documentato", "parametri vitali", "fogli di terapia", "registro ordini clinici"]}, "possible_outcomes": ["compliant", "non_compliant", "justified_deviation", "not_applicable", "not_evaluable", "probable_non_compliance"], "source_references": [{"issuer": "European Society of Cardiology (ESC)", "source_id": "ESC-STEMI-2023", "citation_uri": "https://doi.org/10.1093/eurheartj/ehad191", "license_note": "Contenuto utilizzato a fini clinici e di implementazione PDTA. Riferimento alle linee guida ESC 2023 per SCA.", "source_level": "international", "document_title": "2023 ESC Guidelines for the management of acute coronary syndromes", "page_reference": null, "statement_quote": "Emergency TTE is recommended in patients with suspected ACS presenting with cardiogenic shock or suspected mechanical complications.", "document_version": "2023", "publication_date": "2023-08-25", "section_reference": "Sezione Imaging â€“ Raccomandazioni per ecocardiografia in SCA"}], "original_statement": "Emergency TTE is recommended in patients with suspected ACS presenting with cardiogenic shock or suspected mechanical complications.", "responsible_actors": [{"notes": "Responsabile dell''esecuzione e dell''interpretazione dell''ecocardiogramma transtoracico d''emergenza.", "role_name": "cardiologo ecocardiografista", "organization_unit": "servizio di cardiologia / laboratorio di ecocardiografia", "responsibility_type": "primary"}, {"notes": "Responsabile dell''identificazione iniziale dello shock cardiogeno o delle sospette complicanze meccaniche e dell''attivazione della richiesta di TTE d''emergenza.", "role_name": "medico d''emergenza", "organization_unit": "pronto soccorso", "responsibility_type": "supporting"}, {"notes": "Consulente per la valutazione clinica complessiva e l''interpretazione dei risultati ecocardiografici in contesto di emergenza.", "role_name": "cardiologo di guardia", "organization_unit": "unitÃ  di terapia intensiva cardiologica", "responsibility_type": "consulted"}, {"notes": "Supporto logistico e monitoraggio del paziente durante l''esecuzione dell''esame ecocardiografico.", "role_name": "infermiere di area critica", "organization_unit": "pronto soccorso / UTIC", "responsibility_type": "supporting"}], "clinical_pathway_id": "PDTA-STEMI-001", "completion_criteria": {"description": "La regola Ã¨ soddisfatta quando l''ecocardiogramma transtoracico d''emergenza Ã¨ stato eseguito, con referto che documenti la funzione ventricolare e l''eventuale presenza o assenza di complicanze meccaniche.", "success_condition": "TTE d''emergenza eseguita con referto completo che includa funzione biventricolare e screening delle complicanze meccaniche, documentato nel sistema informativo clinico.", "minimum_occurrences": 1, "required_event_types": ["ordine_tte_emergenza", "esecuzione_tte_emergenza", "referto_tte_emergenza"], "required_documentation_elements": ["Referto ecocardiografico con valutazione della funzione ventricolare sinistra (FEVS)", "Valutazione della funzione ventricolare destra", "Valutazione della presenza/assenza di complicanze meccaniche", "Valutazione del versamento pericardico", "Firma e timestamp del cardiologo ecocardiografista"]}, "extraction_metadata": {"validated_at": null, "validated_by": null, "ambiguity_flags": ["Il vincolo temporale di 30 minuti non Ã¨ esplicitamente indicato nella linea guida originale ed Ã¨ stato stimato come parametro operativo ragionevole.", "La definizione di ''suspected mechanical complications'' Ã¨ ampia e puÃ² richiedere interpretazione clinica contestuale.", "Il livello di evidenza C Ã¨ stato assegnato in modo plausibile ma potrebbe variare nella specifica raccomandazione della linea guida."], "generation_mode": "llm_inference", "extraction_confidence": 0.92, "human_validation_status": "not_reviewed", "source_interpretation_notes": "La raccomandazione originale utilizza il verbo ''is recommended'' che corrisponde a una classe di raccomandazione I (forte raccomandazione, da eseguire). Il termine ''emergency'' Ã¨ stato interpretato come necessitÃ  di esecuzione urgente e non differibile. Il termine ''suspected ACS'' include STEMI e NSTEMI, ma nel contesto del PDTA STEMI la regola Ã¨ applicata primariamente ai pazienti STEMI. Il vincolo temporale specifico (30 minuti) Ã¨ stato aggiunto come parametro operativo plausibile in quanto non esplicitamente indicato nella raccomandazione originale."}, "governance_metadata": {"version": "1.0.0", "rule_owner": "Responsabile clinico PDTA STEMI", "approved_by": null, "effective_to": null, "review_cycle": "12 mesi", "authoring_body": "Gruppo di Lavoro PDTA STEMI - Clinical Pathway Engineering", "effective_from": null, "last_reviewed_at": null, "lifecycle_status": "draft"}, "risk_classification": {"rationale": "La mancata esecuzione della TTE d''emergenza in un paziente con shock cardiogeno o complicanze meccaniche sospette puÃ² comportare un ritardo diagnostico fatale. Le complicanze meccaniche post-infarto (rottura del setto, rottura della parete libera, insufficienza mitralica acuta) richiedono un intervento chirurgico o interventistico urgente, e il loro mancato riconoscimento Ã¨ associato a mortalitÃ  estremamente elevata.", "detectability": "moderate", "priority_score": 9, "process_risk_severity": "high", "clinical_risk_severity": "critical", "likelihood_if_violated": "likely"}, "normalized_statement": "Ãˆ raccomandata l''esecuzione di un ecocardiogramma transtoracico (TTE) d''emergenza nei pazienti con sospetta sindrome coronarica acuta (SCA) che presentano shock cardiogeno o sospette complicanze meccaniche.", "sequence_constraints": [{"description": "L''identificazione dello shock cardiogeno o della sospetta complicanza meccanica deve precedere la richiesta e l''esecuzione della TTE d''emergenza.", "allowed_order": "predecessor_first", "constraint_id": "STEMI-DO-010-SC-01", "successor_event": "esecuzione_tte_emergenza", "predecessor_event": "riconoscimento_shock_cardiogeno_o_complicanza_meccanica", "violation_condition": "La TTE d''emergenza risulta eseguita senza una documentata valutazione clinica precedente che identifichi lo shock cardiogeno o la complicanza meccanica sospetta."}, {"description": "Il referto della TTE d''emergenza deve essere disponibile prima o contestualmente alla decisione terapeutica definitiva (chirurgia, PCI, supporto meccanico circolatorio).", "allowed_order": "predecessor_first", "constraint_id": "STEMI-DO-010-SC-02", "successor_event": "decisione_terapeutica_definitiva", "predecessor_event": "referto_tte_emergenza", "violation_condition": "La decisione terapeutica definitiva per la gestione della complicanza meccanica o dello shock viene presa senza che il referto TTE sia disponibile."}], "clinical_pathway_name": "Percorso Diagnostico-Terapeutico Assistenziale per STEMI", "evidence_of_compliance": [{"description": "Presenza di un ordine di TTE d''emergenza emesso dopo il riconoscimento dello shock cardiogeno o della complicanza meccanica sospetta.", "evidence_id": "STEMI-DO-010-EOC-01", "evidence_type": "order", "time_reference": "Entro breve tempo dal riconoscimento dello shock cardiogeno o della complicanza meccanica.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-STEMI-010-11", "DE-STEMI-010-13"]}, {"description": "Presenza di un referto di TTE d''emergenza completo con valutazione della funzione biventricolare e delle complicanze meccaniche.", "evidence_id": "STEMI-DO-010-EOC-02", "evidence_type": "result", "time_reference": "Durante l''episodio di cura, successivamente al trigger.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-STEMI-010-12", "DE-STEMI-010-13"]}, {"description": "Timestamp dell''esecuzione della TTE d''emergenza documentato nel sistema informativo clinico.", "evidence_id": "STEMI-DO-010-EOC-03", "evidence_type": "timestamp", "time_reference": "Dopo il riconoscimento dello shock/complicanza meccanica.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-STEMI-010-13"]}], "required_data_elements": [{"name": "Sospetto diagnostico di SCA", "data_type": "boolean", "query_hint": "Cercare diagnosi di ingresso o sospetto di SCA/STEMI/NSTEMI nel registro di accettazione PS.", "description": "Presenza di un sospetto clinico di sindrome coronarica acuta basato su anamnesi, sintomi, ECG e/o marcatori biochimici.", "coding_system": "ICD-10 (I21.x, I24.x)", "data_element_id": "DE-STEMI-010-01", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "Sopraslivellamento del tratto ST all''ECG", "data_type": "boolean", "query_hint": "Verificare referto ECG per presenza di sopraslivellamento ST.", "description": "Presenza di sopraslivellamento del tratto ST all''elettrocardiogramma compatibile con STEMI.", "coding_system": null, "data_element_id": "DE-STEMI-010-02", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": false}, {"name": "Troponina elevata", "data_type": "numeric", "query_hint": "Cercare risultato di laboratorio per troponina I hs o troponina T hs.", "description": "Valore di troponina cardiaca (I o T, ad alta sensibilitÃ ) superiore al 99Â° percentile del limite superiore di riferimento.", "coding_system": "LOINC", "data_element_id": "DE-STEMI-010-03", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": false}, {"name": "Pressione arteriosa sistolica", "data_type": "numeric", "query_hint": "Verificare parametri vitali per PAS < 90 mmHg.", "description": "Valore della pressione arteriosa sistolica del paziente al momento della valutazione.", "coding_system": "LOINC", "data_element_id": "DE-STEMI-010-04", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Utilizzo di vasopressori/inotropi", "data_type": "boolean", "query_hint": "Cercare prescrizioni/somministrazioni di noradrenalina, dopamina, dobutamina, adrenalina, levosimendan.", "description": "Indicazione se il paziente ha ricevuto o necessita di supporto farmacologico con vasopressori o inotropi.", "coding_system": "ATC", "data_element_id": "DE-STEMI-010-05", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Segni di ipoperfusione periferica", "data_type": "boolean", "query_hint": "Inferire da note cliniche, parametri vitali (diuresi, lattati, GCS) la presenza di segni di ipoperfusione.", "description": "Presenza di segni clinici di ipoperfusione: estremitÃ  fredde, oliguria, alterazione dello stato di coscienza, lattati elevati.", "coding_system": null, "data_element_id": "DE-STEMI-010-06", "source_location": "ehr_unstructured", "extraction_method": "inferential", "required_for_evaluation": true}, {"name": "Soffio cardiaco di nuova insorgenza", "data_type": "boolean", "query_hint": "Cercare nelle note cliniche e nell''esame obiettivo menzione di soffio cardiaco di nuova insorgenza.", "description": "Riscontro all''esame obiettivo di un soffio cardiaco non precedentemente documentato.", "coding_system": null, "data_element_id": "DE-STEMI-010-07", "source_location": "ehr_unstructured", "extraction_method": "inferential", "required_for_evaluation": true}, {"name": "Deterioramento emodinamico improvviso", "data_type": "boolean", "query_hint": "Cercare nelle note cliniche e nei parametri vitali un rapido peggioramento emodinamico.", "description": "Evento di deterioramento emodinamico acuto e improvviso durante l''episodio di cura.", "coding_system": null, "data_element_id": "DE-STEMI-010-08", "source_location": "ehr_unstructured", "extraction_method": "inferential", "required_for_evaluation": true}, {"name": "Sospetto di tamponamento cardiaco", "data_type": "boolean", "query_hint": "Cercare nelle note cliniche segni o sospetto di tamponamento cardiaco.", "description": "Sospetto clinico di tamponamento cardiaco basato su segni clinici (toni cardiaci ovattati, distensione giugulare, ipotensione).", "coding_system": "ICD-10 (I31.4)", "data_element_id": "DE-STEMI-010-09", "source_location": "ehr_unstructured", "extraction_method": "inferential", "required_for_evaluation": true}, {"name": "TTE d''emergenza giÃ  eseguita nell''episodio corrente", "data_type": "boolean", "query_hint": "Cercare ordine e referto di TTE d''emergenza con timestamp nell''episodio corrente.", "description": "Indicazione che una TTE d''emergenza completa e conclusiva Ã¨ giÃ  stata eseguita durante l''episodio clinico in corso.", "coding_system": null, "data_element_id": "DE-STEMI-010-10", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Ordine di TTE d''emergenza", "data_type": "coded concept", "query_hint": "Cercare ordine di ecocardiografia TT con prioritÃ  urgente/emergenza.", "description": "Ordine clinico per l''esecuzione di ecocardiogramma transtoracico in regime d''emergenza.", "coding_system": "codice prestazione locale / ICD-9-CM 88.72", "data_element_id": "DE-STEMI-010-11", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Referto TTE d''emergenza", "data_type": "text", "query_hint": "Cercare referto ecocardiografico con timestamp compatibile con l''episodio corrente.", "description": "Referto dell''ecocardiogramma transtoracico d''emergenza con valutazione della funzione ventricolare e delle complicanze meccaniche.", "coding_system": null, "data_element_id": "DE-STEMI-010-12", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "Timestamp esecuzione TTE d''emergenza", "data_type": "datetime", "query_hint": "Recuperare il timestamp dall''ordine eseguito o dal referto TTE.", "description": "Data e ora di esecuzione dell''ecocardiogramma transtoracico d''emergenza.", "coding_system": null, "data_element_id": "DE-STEMI-010-13", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}], "recommendation_strength": "Classe I (Raccomandato)", "associated_weak_signal_ids": ["STEMI-WS-010-01", "STEMI-WS-010-02", "STEMI-WS-010-03"], "documentation_requirements": {"mandatory_fields": ["Ordine di TTE d''emergenza con timestamp", "Referto ecocardiografico completo", "Valutazione della funzione ventricolare sinistra (FEVS)", "Valutazione della funzione ventricolare destra", "Screening delle complicanze meccaniche", "Valutazione del versamento pericardico", "Identificazione dell''operatore e firma digitale", "Timestamp di esecuzione dell''esame"], "free_text_allowed": true, "justification_fields": ["Nota clinica con motivazione della mancata esecuzione della TTE d''emergenza", "Documentazione dell''eccezione applicata (indisponibilitÃ  apparecchiatura, arresto cardiaco, trasferimento immediato in emodinamica)", "Piano alternativo documentato"], "acceptable_evidence_sources": ["Sistema informativo di cardiologia / ecocardiografia", "Cartella clinica elettronica (PS, UTIC)", "Registro ordini clinici", "Referto firmato digitalmente", "Immagini ecocardiografiche archiviate nel PACS"], "justification_required_when_deviating": true}, "evidence_of_non_compliance": [{"description": "Assenza di ordine di TTE d''emergenza nel paziente con shock cardiogeno o sospetta complicanza meccanica durante l''episodio.", "evidence_id": "STEMI-DO-010-EONC-01", "evidence_type": "absence_of_event", "time_reference": "Durante l''intero episodio di cura dal momento del trigger.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-STEMI-010-11"]}, {"description": "Assenza di referto di TTE d''emergenza nel paziente con shock cardiogeno o sospetta complicanza meccanica.", "evidence_id": "STEMI-DO-010-EONC-02", "evidence_type": "absence_of_event", "time_reference": "Durante l''intero episodio di cura dal momento del trigger.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-STEMI-010-12"]}, {"description": "TTE d''emergenza eseguita con significativo ritardo rispetto al riconoscimento dello shock cardiogeno o della complicanza meccanica, senza giustificazione documentata.", "evidence_id": "STEMI-DO-010-EONC-03", "evidence_type": "timestamp", "time_reference": "Timestamp TTE > 30 minuti dopo il riconoscimento del trigger, senza eccezione documentata.", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-STEMI-010-13"]}]}');
INSERT INTO riskm_manager_model_evaluation.rule_definition OVERRIDING SYSTEM VALUE VALUES (11, 1, 'STEMI-DONOT-001', '{"title": "Non eseguire di routine angio-TC coronarica precoce nei pazienti con sospetta sindrome coronarica acuta", "intent": "Evitare l''uso inappropriato e routinario della angio-TC coronarica nella fase acuta della gestione dei pazienti con sospetta SCA, al fine di non ritardare il trattamento riperfusivo e di non esporre il paziente a rischi inutili.", "rule_id": "STEMI-DONOT-001", "trigger": {"anchor_event": "Presentazione in Pronto Soccorso con sospetta SCA", "trigger_type": "order", "inference_allowed": true, "trigger_description": "Richiesta o prescrizione di angio-TC coronarica in un paziente con sospetta sindrome coronarica acuta in fase precoce.", "end_of_applicability": "Fino alla definizione diagnostica definitiva o all''esecuzione della coronarografia invasiva.", "trigger_data_elements": ["DE-006", "DE-001"], "start_of_applicability": "Dal momento della presentazione del paziente con sospetta SCA."}, "rationale": "Nei pazienti con sospetta sindrome coronarica acuta (SCA), l''angio-TC coronarica eseguita di routine in fase precoce non apporta benefici diagnostici incrementali significativi rispetto al percorso standard basato su ECG, biomarcatori cardiaci e coronarografia invasiva. Inoltre, puÃ² ritardare i tempi di riperfusione, esporre il paziente a mezzo di contrasto iodato e radiazioni ionizzanti non necessari e sottrarre risorse diagnostiche ad altri pazienti.", "rule_type": "do_not", "exceptions": [{"label": "Coronarografia invasiva controindicata", "description": "L''angio-TC coronarica puÃ² essere considerata quando la coronarografia invasiva Ã¨ controindicata o non disponibile e vi Ã¨ necessitÃ  clinica urgente di definizione anatomica coronarica.", "exception_id": "EXP-001", "condition_logic": "coronary_angiography.contraindicated = true OR cath_lab.available = false", "required_evidence": ["Documentazione della controindicazione alla coronarografia invasiva", "Valutazione collegiale cardiologo-radiologo", "Nota clinica motivata nel verbale di PS"], "required_justification": true}, {"label": "ProbabilitÃ  pre-test bassa/intermedia con diagnosi incerta", "description": "In casi selezionati con probabilitÃ  pre-test bassa o intermedia di SCA e diagnosi ancora incerta dopo ECG e biomarcatori iniziali, l''angio-TC coronarica puÃ² essere considerata come alternativa dopo consulenza cardiologica.", "exception_id": "EXP-002", "condition_logic": "pretest_probability IN (''low'', ''intermediate'') AND ecg.diagnostic = false AND troponin.serial_negative = true", "required_evidence": ["ECG seriali non diagnostici", "Troponina seriata negativa", "Consulenza cardiologica documentata", "Score di rischio calcolato (es. HEART score)"], "required_justification": true}], "short_label": "No angio-TC coronarica di routine in SCA sospetta", "applicability": {"care_context": "Pronto Soccorso, Dipartimento di Emergenza e Accettazione, fase diagnostica pre-coronarografia.", "clinical_context": "Sospetta sindrome coronarica acuta in fase acuta, incluso lo STEMI, dove la prioritÃ  Ã¨ la conferma diagnostica rapida e l''avvio tempestivo della strategia riperfusiva.", "exclusion_criteria": [{"label": "Diagnosi alternativa confermata", "description": "Il paziente ha ricevuto una diagnosi alternativa definitiva che esclude la SCA (es. embolia polmonare, dissecazione aortica confermata con altra metodica).", "criterion_id": "EXC-001", "data_elements": ["DE-001"], "logic_expression": "diagnosis.confirmed NOT IN (''STEMI'', ''NSTEMI'', ''UA'') AND diagnosis.alternative_confirmed = true", "inference_allowed": true}], "inclusion_criteria": [{"label": "Sospetta SCA", "description": "Il paziente presenta segni, sintomi o referti compatibili con una sindrome coronarica acuta (dolore toracico, alterazioni ECG, elevazione dei biomarcatori cardiaci).", "criterion_id": "INC-001", "data_elements": ["DE-001", "DE-002", "DE-003"], "logic_expression": "diagnosis.suspected IN (''STEMI'', ''NSTEMI'', ''UA'') OR ecg.ischemic_changes = true OR troponin.elevated = true", "inference_allowed": true}, {"label": "Fase precoce della presentazione", "description": "Il paziente si trova nella fase precoce dell''episodio acuto, prima dell''esecuzione della coronarografia invasiva o della definizione completa della strategia terapeutica.", "criterion_id": "INC-002", "data_elements": ["DE-004", "DE-005"], "logic_expression": "time_since_presentation <= 24h AND coronary_angiography.status != ''completed''", "inference_allowed": false}], "population_description": "Pazienti adulti che si presentano con sospetta sindrome coronarica acuta (SCA), inclusi STEMI, NSTEMI e angina instabile, nella fase diagnostica iniziale."}, "care_settings": ["Pronto Soccorso", "Dipartimento di Emergenza e Accettazione", "UnitÃ  di Terapia Intensiva Coronarica"], "clinical_phase": "diagnosi", "evidence_level": "C", "schema_version": "1.0.0", "deontic_strength": "recommended", "evaluation_logic": {"notes": "Prestare attenzione ai casi in cui la diagnosi sospetta viene modificata durante l''episodio; la regola si applica solo finchÃ© la sospetta SCA Ã¨ attiva. Le angio-TC eseguite per altre indicazioni (es. sospetta dissecazione aortica, embolia polmonare) non costituiscono violazione.", "ambiguity_policy": "review_required", "formal_expression": "IF (DE-001.value IN [''STEMI'',''NSTEMI'',''SCA'',''angina_instabile'']) AND (DE-006.value = true OR DE-007.value = true) AND (time(DE-006 OR DE-007) - time(DE-004) <= 24h) THEN IF (DE-008.override_justified = true) THEN outcome = ''justified_deviation'' ELSE outcome = ''non_compliant'' ELSE outcome = ''compliant''", "missing_data_policy": "review_required", "natural_language_test": "Verificare se Ã¨ stata richiesta o eseguita un''angio-TC coronarica in un paziente con sospetta SCA nella fase precoce (entro 24 ore dalla presentazione). Se l''esame Ã¨ stato richiesto o eseguito, verificare la presenza di documentazione di override giustificato (controindicazione alla coronarografia invasiva o decisione collegiale documentata). Se l''esame Ã¨ stato eseguito senza giustificazione, la regola Ã¨ violata.", "conflict_resolution_policy": "human_review", "formal_expression_language": "pseudocode"}, "time_constraints": [{"description": "La proibizione Ã¨ attiva dalla presentazione del paziente in PS fino alla definizione diagnostica o all''esecuzione della coronarografia invasiva, tipicamente entro le prime 24 ore.", "anchor_event": "Presentazione in Pronto Soccorso con sospetta SCA", "constraint_id": "TC-001", "duration_unit": "ore", "hard_deadline": false, "duration_value": 24, "relation_to_anchor": "within", "alert_threshold_unit": null, "alert_threshold_value": null}], "evaluation_method": {"notes": "L''identificazione dell''ordine e dell''esecuzione dell''angio-TC Ã¨ deterministica tramite dati strutturati. La verifica della giustificazione dell''override puÃ² richiedere estrazione inferenziale da testo libero e conferma umana.", "primary_method": "hybrid", "minimum_confidence": 0.85, "human_review_required": true, "allowed_inference_sources": ["Note cliniche di Pronto Soccorso", "Verbale di dimissione dal PS", "Consulenze cardiologiche", "Referti radiologici"]}, "possible_outcomes": ["compliant", "non_compliant", "justified_deviation", "not_applicable", "not_evaluable", "probable_non_compliance"], "prohibited_action": {"action_verb": "richiedere", "action_target": "Angio-TC coronarica (CCTA)", "action_description": "Richiedere o eseguire di routine e in fase precoce un''angio-TC coronarica (coronary computed tomography angiography, CCTA) nei pazienti con sospetta sindrome coronarica acuta.", "prohibition_parameters": [{"unit": null, "mandatory": true, "expected_value": "routine", "parameter_name": "modalitÃ  di utilizzo", "comparison_operator": "equals", "parameter_description": "L''esame Ã¨ proibito quando richiesto in modalitÃ  routinaria e non selettiva."}, {"unit": null, "mandatory": true, "expected_value": "precoce", "parameter_name": "tempistica", "comparison_operator": "equals", "parameter_description": "La proibizione riguarda specificamente la fase precoce dell''episodio acuto."}], "known_risk_if_performed": "Ritardo nella strategia riperfusiva (aumento del tempo door-to-balloon), esposizione non necessaria a mezzo di contrasto iodato e radiazioni ionizzanti, falsa rassicurazione o ritardo diagnostico, spreco di risorse diagnostiche."}, "source_references": [{"issuer": "European Society of Cardiology (ESC)", "source_id": "ESC-GUIDELINES-ACS-2023", "citation_uri": "https://doi.org/10.1093/eurheartj/ehad191", "license_note": "Contenuto soggetto a copyright ESC. Utilizzo a fini clinici e di implementazione locale del PDTA.", "source_level": "international", "document_title": "2023 ESC Guidelines for the management of acute coronary syndromes", "page_reference": null, "statement_quote": "Routine, early coronary computed tomography angiography in patients with suspected ACS is not recommended.", "document_version": "2023", "publication_date": "2023-08-25", "section_reference": "Sezione raccomandazioni diagnostiche - Imaging non invasivo"}], "original_statement": "Routine, early coronary computed tomography angiography in patients with suspected ACS is not recommended.", "responsible_actors": [{"notes": "Responsabile primario della fase diagnostica iniziale e della decisione di non richiedere angio-TC coronarica di routine.", "role_name": "Medico di Pronto Soccorso", "organization_unit": "Pronto Soccorso", "responsibility_type": "primary"}, {"notes": "Consultato per la stratificazione diagnostica e per eventuali eccezioni cliniche alla regola.", "role_name": "Cardiologo di guardia", "organization_unit": "Cardiologia / UTIC", "responsibility_type": "consulted"}, {"notes": "Informato della politica di non esecuzione routinaria per evitare richieste inappropriate.", "role_name": "Radiologo interventista", "organization_unit": "Radiologia", "responsibility_type": "informed"}], "clinical_pathway_id": "PDTA-STEMI-001", "extraction_metadata": {"validated_at": null, "validated_by": null, "ambiguity_flags": ["Il confine tra uso ''routinario'' e uso ''selettivo/mirato'' dell''angio-TC puÃ² variare tra centri e richiede definizione operativa locale.", "La definizione di ''fase precoce'' non Ã¨ quantificata nella fonte originale; Ã¨ stata interpretata come entro 24 ore dalla presentazione.", "La regola copre la SCA in generale (incluso STEMI); verificare se il contesto locale richiede distinzioni piÃ¹ granulari."], "generation_mode": "llm_inference", "extraction_confidence": 0.92, "human_validation_status": "not_reviewed", "source_interpretation_notes": "La raccomandazione originale in lingua inglese Ã¨ stata tradotta e contestualizzata per il PDTA STEMI italiano. Il termine ''routine, early'' Ã¨ stato interpretato come uso non selettivo in fase precoce (entro 24 ore). La raccomandazione Ã¨ classificata come Classe III (nessun beneficio) secondo la terminologia ESC."}, "governance_metadata": {"version": "1.0.0", "rule_owner": "Direttore UOC Cardiologia / Responsabile PDTA STEMI", "approved_by": null, "effective_to": null, "review_cycle": "12 mesi", "authoring_body": "Gruppo di lavoro PDTA STEMI", "effective_from": null, "last_reviewed_at": null, "lifecycle_status": "draft"}, "override_conditions": [{"label": "Override per controindicazione alla coronarografia invasiva", "description": "L''angio-TC coronarica puÃ² essere eseguita se la coronarografia invasiva Ã¨ controindicata o non disponibile e sussiste necessitÃ  clinica urgente.", "exception_id": "OVR-001", "condition_logic": "coronary_angiography.contraindicated = true OR cath_lab.available = false", "required_evidence": ["Documentazione della controindicazione alla coronarografia invasiva nel verbale clinico", "Consulenza cardiologica documentata"], "required_justification": true}, {"label": "Override per decisione collegiale in caso dubbio", "description": "Decisione motivata e collegiale tra cardiologo e medico d''urgenza in caso di diagnosi differenziale complessa dove l''angio-TC puÃ² fornire informazioni decisive.", "exception_id": "OVR-002", "condition_logic": "collegial_decision = true AND clinical_justification.documented = true", "required_evidence": ["Nota clinica collegiale firmata", "Motivazione esplicita della necessitÃ  dell''esame"], "required_justification": true}], "risk_classification": {"rationale": "L''esecuzione routinaria di angio-TC coronarica nella fase acuta puÃ² ritardare la riperfusione coronarica (aumentando il tempo door-to-balloon), esporre il paziente a mezzo di contrasto e radiazioni non necessari, e consumare risorse diagnostiche. La severitÃ  clinica Ã¨ moderata poichÃ© il danno dipende dall''entitÃ  del ritardo e dalle condizioni del paziente. La rilevabilitÃ  Ã¨ elevata perchÃ© l''ordine e il referto dell''esame sono facilmente tracciabili nei sistemi informativi.", "detectability": "easy", "priority_score": 6, "process_risk_severity": "moderate", "clinical_risk_severity": "moderate", "likelihood_if_violated": "possible"}, "normalized_statement": "Non Ã¨ raccomandata l''esecuzione routinaria e precoce di angio-TC coronarica nei pazienti con sospetta sindrome coronarica acuta.", "sequence_constraints": [{"description": "L''angio-TC coronarica non deve essere eseguita prima della valutazione clinica completa (ECG, biomarcatori) e della consulenza cardiologica nei pazienti con sospetta SCA.", "allowed_order": "predecessor_first", "constraint_id": "SC-001", "successor_event": "Eventuale angio-TC coronarica (solo se override giustificato)", "predecessor_event": "Valutazione clinica completa (ECG + biomarcatori + consulenza cardiologica)", "violation_condition": "Angio-TC coronarica richiesta o eseguita prima del completamento della valutazione clinica standard."}], "clinical_pathway_name": "Percorso Diagnostico Terapeutico Assistenziale per STEMI", "evidence_of_violation": [{"description": "Presenza di un ordine o di un referto di angio-TC coronarica in un paziente con sospetta SCA nella fase precoce, senza documentazione di override giustificato.", "evidence_id": "EV-VIOL-001", "evidence_type": "order", "time_reference": "Entro 24 ore dalla presentazione in PS con sospetta SCA", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-006", "DE-007", "DE-001", "DE-004"]}, {"description": "Referto di angio-TC coronarica completata nel PACS/RIS durante la fase acuta dell''episodio di sospetta SCA.", "evidence_id": "EV-VIOL-002", "evidence_type": "execution", "time_reference": "Entro 24 ore dalla presentazione in PS con sospetta SCA", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-007", "DE-001", "DE-004"]}], "required_data_elements": [{"name": "Diagnosi sospetta", "data_type": "coded concept", "query_hint": "Cercare codici ICD-10 I21.x, I20.0 o diagnosi di triage contenenti ''SCA'', ''STEMI'', ''infarto''.", "description": "Diagnosi clinica sospetta o confermata al momento della presentazione (es. STEMI, NSTEMI, angina instabile, SCA indifferenziata).", "coding_system": "ICD-10", "data_element_id": "DE-001", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Referto ECG", "data_type": "coded concept", "query_hint": "Cercare referto ECG con interpretazione automatica o manuale; parole chiave: sopraslivellamento ST, STEMI, ischemia.", "description": "Risultato dell''elettrocardiogramma a 12 derivazioni eseguito alla presentazione, con particolare attenzione a sopraslivellamento ST, sottoslivellamento ST, o altre alterazioni ischemiche.", "coding_system": null, "data_element_id": "DE-002", "source_location": "ehr_structured", "extraction_method": "hybrid", "required_for_evaluation": true}, {"name": "Troponina cardiaca", "data_type": "numeric", "query_hint": "LOINC 89579-7 (hs-cTnT) o 49563-0 (hs-cTnI). Verificare valore e cut-off del laboratorio locale.", "description": "Valore della troponina cardiaca ad alta sensibilitÃ  (hs-cTn) alla presentazione e nei controlli seriati.", "coding_system": "LOINC", "data_element_id": "DE-003", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Data e ora di presentazione in PS", "data_type": "datetime", "query_hint": "Campo ''data_ora_accettazione'' o ''triage_timestamp'' nel sistema di PS.", "description": "Timestamp di arrivo del paziente in Pronto Soccorso o primo contatto medico.", "coding_system": null, "data_element_id": "DE-004", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Stato coronarografia invasiva", "data_type": "coded concept", "query_hint": "Cercare ordini o referti di coronarografia nel sistema di emodinamica o nel RIS/PACS.", "description": "Stato della coronarografia invasiva (non eseguita, programmata, in corso, completata).", "coding_system": null, "data_element_id": "DE-005", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Richiesta angio-TC coronarica", "data_type": "boolean", "query_hint": "Cercare ordini radiologici con descrizione ''angio-TC coronarica'', ''CCTA'', ''TC coronarica'' nel RIS o nel sistema ordini.", "description": "Presenza di una richiesta o ordine per angio-TC coronarica (CCTA) nel sistema informativo.", "coding_system": null, "data_element_id": "DE-006", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Esecuzione angio-TC coronarica", "data_type": "boolean", "query_hint": "Cercare referti radiologici con modalitÃ  CT e descrizione ''coronarica'' o ''CCTA'' nel PACS.", "description": "Evidenza dell''effettiva esecuzione dell''angio-TC coronarica (referto presente nel PACS/RIS).", "coding_system": null, "data_element_id": "DE-007", "source_location": "ehr_structured", "extraction_method": "deterministic", "required_for_evaluation": true}, {"name": "Documentazione di giustificazione override", "data_type": "text", "query_hint": "Cercare nelle note cliniche del verbale di PS parole chiave: ''motivazione'', ''controindicazione coronarografia'', ''decisione collegiale'', ''angio-TC giustificata''.", "description": "Presenza di una nota clinica o documentazione strutturata che giustifica l''eventuale override della proibizione.", "coding_system": null, "data_element_id": "DE-008", "source_location": "ehr_unstructured", "extraction_method": "inferential", "required_for_evaluation": false}], "recommendation_strength": "Classe III (nessun beneficio)", "associated_weak_signal_ids": ["STEMI-WS-001"], "documentation_requirements": {"mandatory_fields": ["Diagnosi sospetta all''ingresso", "ECG a 12 derivazioni", "Troponina cardiaca", "Eventuali ordini di imaging cardiaco"], "free_text_allowed": true, "justification_fields": ["Nota clinica motivata nel verbale di PS", "Consulenza cardiologica con indicazione all''angio-TC", "Documentazione della controindicazione alla coronarografia invasiva"], "acceptable_evidence_sources": ["Cartella clinica elettronica di PS", "Sistema RIS/PACS", "Sistema ordini diagnostici", "Consulenze cardiologiche"], "justification_required_when_deviating": true}, "evidence_of_allowed_override": [{"description": "Documentazione clinica strutturata o narrativa che attesta la controindicazione alla coronarografia invasiva e la necessitÃ  dell''angio-TC coronarica, con firma del cardiologo.", "evidence_id": "EV-OVR-001", "evidence_type": "justification", "time_reference": "Prima dell''esecuzione dell''angio-TC coronarica", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-008"]}, {"description": "Nota di consulenza cardiologica che supporta la decisione di eseguire l''angio-TC coronarica come alternativa alla coronarografia invasiva.", "evidence_id": "EV-OVR-002", "evidence_type": "documentation", "time_reference": "Prima dell''esecuzione dell''angio-TC coronarica", "minimum_occurrences": 1, "derived_from_data_elements": ["DE-008"]}], "override_justification_requirements": {"notes": "L''override deve essere sempre documentato prima dell''esecuzione dell''esame. La motivazione deve essere clinicamente fondata e non basata su sola preferenza del clinico.", "mandatory": true, "required_fields": ["Motivazione clinica dell''override nel verbale di Pronto Soccorso", "Nome e qualifica del medico autorizzante", "Data e ora della decisione", "Esito della consulenza cardiologica"], "required_evidence_sources": ["Verbale di Pronto Soccorso", "Consulenza cardiologica", "Cartella clinica elettronica"]}}');
INSERT INTO riskm_manager_model_evaluation.rule_definition OVERRIDING SYSTEM VALUE VALUES (12, 1, 'STEMI-DO-011', '{"title": "Gestione pre-ospedaliera dello STEMI basata su reti regionali per la terapia di riperfusione con PCI primaria", "intent": "Garantire che ogni paziente con sospetto STEMI in fase pre-ospedaliera venga gestito all''interno di una rete regionale strutturata che consenta l''accesso rapido alla PCI primaria, riducendo i tempi di riperfusione e migliorando gli esiti clinici.", "rule_id": "STEMI-DO-011", "trigger": {"anchor_event": "primo_contatto_medico", "trigger_type": "diagnostic_finding", "inference_allowed": true, "trigger_description": "Riscontro di sopraslivellamento del tratto ST all''ECG a 12 derivazioni eseguito in fase pre-ospedaliera, in un paziente con sintomatologia compatibile con sindrome coronarica acuta.", "end_of_applicability": "Fino all''arrivo del paziente nel laboratorio di emodinamica del centro Hub o alla somministrazione della terapia fibrinolitica, se la PCI primaria non Ã¨ raggiungibile nei tempi previsti.", "trigger_data_elements": ["ecg_12_lead_result", "first_medical_contact_time", "symptom_onset_time", "chest_pain_present"], "start_of_applicability": "Dal momento del primo contatto medico (FMC) con riscontro ECG compatibile con STEMI."}, "rationale": "La riperfusione tempestiva mediante PCI primaria riduce la mortalitÃ  e la morbilitÃ  nei pazienti con STEMI. L''organizzazione in reti regionali, con protocolli condivisi e comunicazione in tempo reale, consente di bypassare strutture senza emodinamica e di ridurre significativamente i tempi totali di ischemia.", "rule_type": "do", "exceptions": [{"label": "PCI primaria non raggiungibile entro 120 minuti dal FMC", "description": "Se la PCI primaria non puÃ² essere eseguita entro 120 minuti dal primo contatto medico (es. per distanza geografica, condizioni meteo avverse, indisponibilitÃ  del laboratorio), Ã¨ giustificato il ricorso alla fibrinolisi come strategia di riperfusione alternativa, secondo un protocollo farmaco-invasivo.", "exception_id": "STEMI-DO-011-EXP-01", "condition_logic": "estimated_FMC_to_wire_time > 120 AND fibrinolysis_not_contraindicated == true", "required_evidence": ["documentazione_del_tempo_stimato_FMC_to_wire", "motivazione_della_non_raggiungibilitÃ _del_centro_PCI", "conferma_assenza_controindicazioni_fibrinolisi"], "required_justification": true}, {"label": "VolontÃ  del paziente o direttive anticipate", "description": "Il paziente esprime rifiuto informato alla procedura invasiva o esistono direttive anticipate di trattamento che limitano gli interventi.", "exception_id": "STEMI-DO-011-EXP-02", "condition_logic": "patient_refusal == true OR advance_directive_limits_intervention == true", "required_evidence": ["documentazione_del_rifiuto_informato", "copia_direttive_anticipate_di_trattamento"], "required_justification": true}], "short_label": "Rete regionale PPCI per STEMI", "applicability": {"care_context": "Fase pre-ospedaliera: primo contatto medico sul territorio, ambulanza, trasmissione telematica dell''ECG, decisione sulla destinazione e attivazione della rete.", "clinical_context": "Infarto miocardico con sopraslivellamento del tratto ST (STEMI) in fase acuta, entro 12 ore dall''esordio dei sintomi.", "exclusion_criteria": [{"label": "Arresto cardiaco refrattario non rianimabile", "description": "Paziente in arresto cardiaco refrattario senza indicazione a proseguire la rianimazione, per il quale non Ã¨ ipotizzabile alcun percorso di riperfusione.", "criterion_id": "STEMI-DO-011-EXC-01", "data_elements": ["cardiac_arrest_status", "resuscitation_decision"], "logic_expression": "cardiac_arrest_refractory == true AND resuscitation_futile == true", "inference_allowed": false}, {"label": "Diagnosi alternativa confermata", "description": "Il sopraslivellamento ST Ã¨ attribuibile a causa non ischemica confermata (es. pericardite, ripolarizzazione precoce) e la diagnosi di STEMI viene esclusa.", "criterion_id": "STEMI-DO-011-EXC-02", "data_elements": ["ecg_12_lead_result", "clinical_assessment_diagnosis"], "logic_expression": "STEMI_diagnosis_excluded == true", "inference_allowed": true}], "inclusion_criteria": [{"label": "Diagnosi operativa di STEMI", "description": "Il paziente presenta sopraslivellamento del tratto ST all''ECG a 12 derivazioni o blocco di branca sinistra di nuova insorgenza, compatibile con STEMI, in presenza di sintomatologia ischemica acuta.", "criterion_id": "STEMI-DO-011-INC-01", "data_elements": ["ecg_12_lead_result", "symptom_onset_time", "chest_pain_present"], "logic_expression": "ECG_STEMI_positive == true AND symptom_onset_hours <= 12", "inference_allowed": true}, {"label": "Primo contatto medico pre-ospedaliero", "description": "Il paziente Ã¨ stato valutato per la prima volta dal sistema di emergenza territoriale (118) o da un medico sul territorio, prima dell''arrivo in ospedale.", "criterion_id": "STEMI-DO-011-INC-02", "data_elements": ["first_medical_contact_location", "first_medical_contact_time"], "logic_expression": "first_medical_contact_location == ''pre-hospital''", "inference_allowed": false}], "population_description": "Pazienti adulti (â‰¥18 anni) con diagnosi operativa di STEMI formulata in fase pre-ospedaliera sulla base di segni, sintomi e tracciato ECG a 12 derivazioni."}, "care_settings": ["territorio", "ambulanza", "centrale operativa 118", "pronto soccorso spoke", "laboratorio di emodinamica hub"], "clinical_phase": "pre-ospedaliera", "evidence_level": "Livello di evidenza B", "schema_version": "1.0.0", "expected_action": {"action_verb": "attivare", "action_target": "Rete regionale STEMI e laboratorio di emodinamica per PCI primaria", "action_parameters": [{"unit": null, "mandatory": true, "expected_value": "PCI primaria", "parameter_name": "ModalitÃ  di riperfusione", "comparison_operator": "equals", "parameter_description": "Strategia di riperfusione preferita per il paziente con STEMI"}, {"unit": null, "mandatory": true, "expected_value": "eseguita", "parameter_name": "Trasmissione ECG telematica", "comparison_operator": "equals", "parameter_description": "L''ECG a 12 derivazioni deve essere trasmesso al centro Hub per la conferma diagnostica pre-arrivo"}, {"unit": null, "mandatory": true, "expected_value": "centro Hub con emodinamica", "parameter_name": "Destinazione del trasporto", "comparison_operator": "equals", "parameter_description": "Il paziente deve essere trasportato direttamente al centro Hub con laboratorio di emodinamica attivo H24/7"}], "action_description": "Attivare la rete regionale STEMI secondo i protocolli della rete cardiologica di riferimento: eseguire ECG a 12 derivazioni, trasmettere il tracciato al centro Hub, confermare la diagnosi con il cardiologo interventista, attivare il laboratorio di emodinamica e trasportare il paziente direttamente al centro Hub per PCI primaria.", "alternative_compliant_actions": ["Somministrazione di fibrinolisi pre-ospedaliera con successivo trasferimento per coronarografia (strategia farmaco-invasiva), se la PCI primaria non Ã¨ raggiungibile entro 120 minuti dal FMC"]}, "deontic_strength": "recommended", "evaluation_logic": {"notes": "In caso di assenza di timestamp strutturati, tentare l''estrazione dai testi liberi delle note 118 o della lettera di dimissione prima di dichiarare il caso non valutabile.", "ambiguity_policy": "review_required", "formal_expression": "IF STEMI_diagnosis_prehospital == true THEN CHECK ecg_performed_within_10min(FMC) AND ecg_transmitted_to_hub AND cath_lab_activated AND (patient_arrived_hub_within_120min OR fibrinolysis_administered_with_justification) THEN status = ''compliant'' ELSE IF justified_deviation_documented THEN status = ''justified_deviation'' ELSE status = ''non_compliant''", "missing_data_policy": "review_required", "natural_language_test": "Verificare che per ogni paziente con diagnosi operativa di STEMI in fase pre-ospedaliera siano documentati: (1) l''esecuzione dell''ECG a 12 derivazioni entro 10 minuti dal FMC, (2) la trasmissione telematica dell''ECG al centro Hub, (3) l''attivazione del laboratorio di emodinamica, (4) il trasporto diretto al centro Hub per PCI primaria oppure la somministrazione giustificata di fibrinolisi. Se tutti gli elementi sono presenti e i tempi rispettati, la regola Ã¨ conforme. Se mancano elementi chiave senza giustificazione, la regola Ã¨ non conforme.", "conflict_resolution_policy": "human_review", "formal_expression_language": "pseudocode"}, "time_constraints": [{"description": "L''ECG a 12 derivazioni deve essere eseguito entro 10 minuti dal primo contatto medico.", "anchor_event": "primo_contatto_medico", "constraint_id": "STEMI-DO-011-TC-01", "duration_unit": "minuti", "hard_deadline": true, "duration_value": 10, "relation_to_anchor": "within", "alert_threshold_unit": "minuti", "alert_threshold_value": 7}, {"description": "Il tempo dal primo contatto medico al passaggio del filo guida in coronaria (wire crossing) deve essere inferiore a 90 minuti (obiettivo ideale) e comunque non superiore a 120 minuti.", "anchor_event": "primo_contatto_medico", "constraint_id": "STEMI-DO-011-TC-02", "duration_unit": "minuti", "hard_deadline": true, "duration_value": 120, "relation_to_anchor": "no_later_than", "alert_threshold_unit": "minuti", "alert_threshold_value": 90}], "evaluation_method": {"notes": "Per i casi in cui i timestamp provengono esclusivamente da testo libero, Ã¨ richiesta validazione umana. In presenza di dati strutturati completi, la valutazione deterministica Ã¨ sufficiente.", "primary_method": "hybrid", "minimum_confidence": 0.85, "human_review_required": true, "allowed_inference_sources": ["note cliniche 118", "verbale di soccorso", "lettera di dimissione", "referto di emodinamica", "registro trasmissioni ECG"]}, "possible_outcomes": ["compliant", "non_compliant", "justified_deviation", "not_applicable", "not_evaluable", "probable_non_compliance"], "source_references": [{"issuer": "European Society of Cardiology (ESC)", "source_id": "ESC-STEMI-2023", "citation_uri": "https://doi.org/10.1093/eurheartj/ehad191", "license_note": "Contenuto citato a scopo di implementazione clinica non commerciale, in conformitÃ  con le condizioni d''uso ESC.", "source_level": "international", "document_title": "2023 ESC Guidelines for the management of acute coronary syndromes", "page_reference": "Raccomandazione classe I, livello B", "statement_quote": "It is recommended that the pre-hospital management of patients with a working diagnosis of STEMI is based on regional networks designed to deliver reperfusion therapy expeditiously and effectively, with efforts made to make PPCI available to as many patients as possible.", "document_version": "2023", "publication_date": "2023-08-25", "section_reference": "Sezione 5 â€“ Pre-hospital management and reperfusion strategy"}], "original_statement": "It is recommended that the pre-hospital management of patients with a working diagnosis of STEMI is based on regional networks designed to deliver reperfusion therapy expeditiously and effectively, with efforts made to make PPCI available to as many patients as possible.", "responsible_actors": [{"notes": "Responsabile della diagnosi operativa di STEMI in fase pre-ospedaliera e dell''attivazione della rete.", "role_name": "Medico del sistema di emergenza territoriale 118", "organization_unit": "Centrale Operativa 118 / Servizio di Emergenza Territoriale", "responsibility_type": "primary"}, {"notes": "Supporta l''acquisizione dell''ECG a 12 derivazioni e la trasmissione telematica al centro Hub.", "role_name": "Infermiere di ambulanza", "organization_unit": "Servizio di Emergenza Territoriale", "responsibility_type": "supporting"}, {"notes": "Riceve la trasmissione ECG, conferma la diagnosi e attiva il laboratorio di emodinamica.", "role_name": "Cardiologo interventista di guardia", "organization_unit": "Laboratorio di Emodinamica â€“ Centro Hub", "responsibility_type": "consulted"}, {"notes": "Supervisiona il funzionamento della rete, monitora i tempi e gli indicatori di performance.", "role_name": "Coordinatore della rete STEMI regionale", "organization_unit": "Rete cardiologica regionale", "responsibility_type": "monitoring"}], "clinical_pathway_id": "1", "completion_criteria": {"description": "La regola Ã¨ considerata soddisfatta quando il paziente con diagnosi operativa di STEMI Ã¨ stato gestito attraverso la rete regionale, con trasmissione ECG al centro Hub, attivazione del laboratorio di emodinamica e arrivo del paziente presso il centro Hub, oppure quando Ã¨ stata somministrata fibrinolisi in modo giustificato.", "success_condition": "ECG eseguito e trasmesso AND laboratorio emodinamica attivato AND paziente arrivato al centro Hub OR fibrinolisi somministrata con giustificazione documentata", "minimum_occurrences": 1, "required_event_types": ["esecuzione_ecg_12_derivazioni", "trasmissione_telematica_ecg", "attivazione_laboratorio_emodinamica", "arrivo_paziente_centro_hub"], "required_documentation_elements": ["orario_primo_contatto_medico", "orario_esecuzione_ecg", "orario_trasmissione_ecg", "orario_attivazione_emodinamica", "orario_arrivo_centro_hub", "referto_ecg"]}, "extraction_metadata": {"validated_at": null, "validated_by": null, "ambiguity_flags": ["La raccomandazione originale non specifica esplicitamente i tempi ma li rimanda ad altre sezioni delle linee guida; i vincoli temporali sono stati integrati per coerenza", "Il concetto di ''rendere la PPCI disponibile al maggior numero possibile di pazienti'' Ã¨ stato tradotto operativamente come obbligo di attivazione della rete con PCI primaria come default"], "generation_mode": "llm_inference", "extraction_confidence": 0.9, "human_validation_status": "not_reviewed", "source_interpretation_notes": "La raccomandazione originale ESC Ã¨ formulata in modo ampio, enfatizzando l''organizzazione in reti regionali e la massima accessibilitÃ  alla PCI primaria. La regola Ã¨ stata operazional